# Memoised backdrop-logo aspect fits, keyed on (profile_id, logo_id, mtime_ns).
# The backdrop pick opens every uploaded logo with PIL on each signed-in page
# render; this caches each logo's aspect so repeat renders do zero PIL opens.
# Keying on the file's mtime self-invalidates when a logo is replaced in place;
# the LRU bound stops replaced-file keys accumulating on long-lived workers.
_bg_fit_cache: BoundedCache = BoundedCache(max_size=512)


_approval_ledger = None  # 1.12 group-approver votes (lazy, like _wf_store)


def _get_approval_ledger():
    """The per-card approval-votes ledger (roadmap 1.12 group-approver rules)."""
    global _approval_ledger
    if _approval_ledger is None:
        try:
            from mediahub.workflow.approvals import ApprovalLedger

            _approval_ledger = ApprovalLedger(RUNS_DIR)
        except ImportError:
            pass
    return _approval_ledger


# Per-card inspector overrides (UI 1.18) ride the existing workflow
# ``edited_captions`` bag under dotted ``insp.*`` keys — no underscore, so the
# pack builder's ``tone_slot`` caption parser skips them cleanly. This is the
# whole persistence story: no new store, no schema change.
_INSPECTOR_EDIT_KEYS = {
    "insp.accent": "accent",
    "insp.focus": "photo_pos",
    "insp.hideSponsor": "hide_sponsor",
    "insp.noPhoto": "no_photo",
}


def _inspector_overrides_for_card(run_id: str, card_id: str) -> dict:
    """Read a card's persisted inspector overrides as a render-ready dict.

    Returns ``{accent?, photo_pos?, hide_sponsor?, no_photo?}`` — only the keys
    the user actually set. Booleans are coerced from their stored string form.
    Best-effort: any store/parse failure yields an empty dict so a render never
    breaks on a missing or malformed sidecar.
    """
    out: dict = {}
    try:
        ws = _get_wf_store()
        if ws is None:
            return out
        state = ws.load(run_id).get(card_id)
        edits = (getattr(state, "edited_captions", None) or {}) if state else {}
    except Exception:
        return out
    for store_key, render_key in _INSPECTOR_EDIT_KEYS.items():
        if store_key not in edits:
            continue
        val = edits.get(store_key)
        if render_key in ("hide_sponsor", "no_photo"):
            out[render_key] = str(val).lower() in ("1", "true", "yes", "on")
        elif val:
            out[render_key] = str(val)
    return out


_INSPECTOR_HEX_RE = re.compile(r"#(?:[0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})")


def _apply_inspector_overrides_to_motion(
    overrides: dict,
    card_payload: dict,
    brief_dict,
    brand_kit,
    *,
    brand_copy: bool = True,
):
    """Translate a card's persisted inspector overrides for the motion engine (M36).

    Mirrors the still create-graphic route's translation without touching
    ``visual/motion.py``:

    * ``accent`` — the same BrandKit-copy mechanism the still uses
      (``dataclasses.replace(..., accent_colour=...)`` plus the brief-palette
      accent), so ``_resolved_motion_roles`` resolves the SAME APCA-gated
      ``roleAccent`` the tweaked still painted. ``brand_copy=False`` (the reel,
      whose brand kit is shared across cards) applies the brief-palette half
      only — per-card, still APCA-gated.
    * ``no_photo`` — the brief copy gets ``photo_treatment="no-photo"``, the
      exact signal the motion photo resolver honours, so photoSrc / cutout /
      photoPos drop exactly as they do on the still.
    * The full override dict is attached onto the card payload
      (``inspector_overrides``) as the forward seam for the motion engine.
      Note honestly: a ``photo_pos`` (crop) override has no motion-prop hook
      in the current engine, so it does not alter the video — UI copy must
      not promise it. ``hide_sponsor`` needs no translation: single-card
      motion has no sponsor strip, and the reel outro sponsor is a club-level
      close, not the per-card strip.

    Because the accent/no-photo translations change the resolved props (and
    the brand dict), tweaked cards fold into NEW motion cache keys while an
    untouched card's inputs — and therefore its cache key — stay
    byte-identical (empty overrides return the inputs unchanged).
    """
    if not overrides:
        return card_payload, brief_dict, brand_kit
    card_payload = dict(card_payload or {})
    card_payload["inspector_overrides"] = dict(overrides)
    accent = str(overrides.get("accent") or "").strip()
    if accent and _INSPECTOR_HEX_RE.fullmatch(accent):
        if brand_copy and brand_kit is not None:
            try:
                import dataclasses as _dc

                brand_kit = _dc.replace(brand_kit, accent_colour=accent)
            except Exception:
                pass
        if isinstance(brief_dict, dict):
            brief_dict = {
                **brief_dict,
                "palette": {**(brief_dict.get("palette") or {}), "accent": accent},
            }
    if overrides.get("no_photo") and isinstance(brief_dict, dict):
        brief_dict = {**brief_dict, "photo_treatment": "no-photo"}
    return card_payload, brief_dict, brand_kit


# Preferred still format for thumbnails / previews, in order.
_THUMB_FORMAT_PREFERENCE = ("feed_portrait", "story", "feed_square")


def _rendered_visuals_for_run(run_id: str) -> dict[str, dict]:
    """Map each card id to its NEWEST persisted visual for a run (M29/M30).

    Scans ``RUNS_DIR/<run>/visuals/<brief_id>/visual.json`` sidecars (written
    by ``content_pack_visual.integration.persist_visual``) and keeps, per
    ``content_item_id``, the most recently written brief dir that still has
    PNGs on disk. Read-only — never renders. Returns::

        {card_id: {brief_id, visual_id, mtime, png_paths {fmt: path},
                   format_ids {fmt: per-format visual id}, layout_template,
                   why_this_design, sourced_asset_ids}}
    """
    out: dict[str, dict] = {}
    vdir = RUNS_DIR / run_id / "visuals"
    try:
        if not vdir.is_dir():
            return out
        subdirs = list(vdir.iterdir())
    except OSError:
        return out
    for sub in subdirs:
        if not sub.is_dir():
            continue
        sidecar = sub / "visual.json"
        try:
            payload = json.loads(sidecar.read_text(encoding="utf-8"))
            mtime = sidecar.stat().st_mtime
        except Exception:
            continue
        if not isinstance(payload, dict):
            continue
        cid = str(payload.get("content_item_id") or "")
        if not cid:
            continue
        try:
            pngs = {p.stem: str(p) for p in sub.glob("*.png")}
        except OSError:
            pngs = {}
        if not pngs:
            continue
        prev = out.get(cid)
        if prev is not None and prev["mtime"] >= mtime:
            continue
        fmt_ids: dict[str, str] = {}
        for vid_key, fmt in (payload.get("visual_ids") or {}).items():
            fmt_ids.setdefault(str(fmt), str(vid_key))
        out[cid] = {
            "brief_id": sub.name,
            "visual_id": str(payload.get("id") or ""),
            "mtime": mtime,
            "png_paths": pngs,
            "format_ids": fmt_ids,
            "layout_template": str(payload.get("layout_template") or ""),
            "why_this_design": str(payload.get("why_this_design") or ""),
            "sourced_asset_ids": [str(a) for a in (payload.get("sourced_asset_ids") or []) if a],
        }
    return out


def _visual_thumb_path(info: Optional[dict]) -> Optional[str]:
    """The best on-disk PNG for a rendered-visual entry, preferring the
    portrait cut the review thumbs and pack wall use. ``None`` when absent."""
    if not info:
        return None
    pngs = info.get("png_paths") or {}
    for fmt in _THUMB_FORMAT_PREFERENCE:
        p = pngs.get(fmt)
        if p and Path(p).exists():
            return p
    for p in pngs.values():
        if p and Path(p).exists():
            return p
    return None


def _recent_asset_families_for_run(
    run_id: str, exclude_card_id: str, media_assets: Optional[list]
) -> list[str]:
    """dHash burst families of photos already on OTHER cards' current renders.

    The pack path threads ``recent_asset_families`` between items so two
    cards never carry near-identical burst frames; this gives the PER-CARD
    render routes the same avoid-list, derived from what is actually rendered
    on the run right now (the card being re-rendered is excluded so its own
    photo stays eligible for itself). Deterministic and read-only — same
    library + same renders in, same families out. Empty on any miss.
    """
    fams: list[str] = []
    try:
        dhash_by_id: dict[str, str] = {}
        for ad in media_assets or []:
            d = ad if isinstance(ad, dict) else {}
            q = (d.get("media_meta") or {}).get("quality") or {}
            if d.get("id") and q.get("dhash"):
                dhash_by_id[str(d["id"])] = str(q["dhash"])
        if not dhash_by_id:
            return []
        for cid, info in _rendered_visuals_for_run(run_id).items():
            if str(cid) == str(exclude_card_id):
                continue
            for aid in info.get("sourced_asset_ids") or []:
                fam = dhash_by_id.get(str(aid))
                if fam and fam not in fams:
                    fams.append(fam)
    except Exception:
        return []
    return fams[-12:]


def _brand_swatches(brand_kit) -> list[dict]:
    """Brand-locked accent swatches for the UI 1.18 inspector palette.

    Only the club's OWN confirmed colours (primary / secondary / accent) are
    offered — never an arbitrary colour picker — so a per-card tweak can never
    paint a card off-brand. Returns ``[{role, hex}]`` de-duplicated, each a
    valid CSS hex; an empty list when the kit has none.
    """
    pairs = [
        ("primary", getattr(brand_kit, "primary_colour", None)),
        ("secondary", getattr(brand_kit, "secondary_colour", None)),
        ("accent", getattr(brand_kit, "accent_colour", None)),
    ]
    out: list[dict] = []
    seen: set[str] = set()
    for role, hexval in pairs:
        h = str(hexval or "").strip()
        if not re.fullmatch(r"#(?:[0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})", h):
            continue
        key = h.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append({"role": role, "hex": h})
    return out


def _inspector_state_attrs(wf_state) -> str:
    """``data-insp-*`` attributes carrying a card's persisted inspector state.

    Lets the drawer show the saved accent / crop / element toggles / caption the
    moment it opens — no render round-trip needed. Values are HTML-escaped; only
    set keys are emitted (an untouched card adds nothing).
    """
    edits = (getattr(wf_state, "edited_captions", None) or {}) if wf_state else {}
    parts: list[str] = []
    accent = str(edits.get("insp.accent") or "").strip()
    if re.fullmatch(r"#(?:[0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})", accent):
        parts.append(f'data-insp-accent="{_h(accent)}"')
    focus = str(edits.get("insp.focus") or "").strip()
    if focus:
        parts.append(f'data-insp-focus="{_h(focus)}"')
    if str(edits.get("insp.hideSponsor") or "").lower() in ("1", "true", "yes", "on"):
        parts.append('data-insp-hide-sponsor="1"')
    if str(edits.get("insp.noPhoto") or "").lower() in ("1", "true", "yes", "on"):
        parts.append('data-insp-no-photo="1"')
    caption = str(edits.get("warm-club_headline") or "").strip()
    if caption:
        parts.append(f'data-insp-caption="{_h(caption)}"')
    # H-10: the caption this one overwrote (stashed by WorkflowStore.set_edits)
    # feeds the drawer's one-step "Restore previous caption".
    prev_caption = str(edits.get("prev.warm-club_headline") or "").strip()
    if prev_caption and prev_caption != caption:
        parts.append(f'data-insp-caption-prev="{_h(prev_caption)}"')
    return (" " + " ".join(parts)) if parts else ""


# ---------------------------------------------------------------------
# In-process run registry (active progress) + persisted run metadata.
# ---------------------------------------------------------------------

# Both dicts are in-memory progress trackers — the source of truth for
# runs is the SQLite `runs` table + `runs_v4/<id>.json`; for Turn-Into
# jobs it's the pack file on disk. The in-process registries below keep
# transient state (live log lines, in-flight status) and must NOT grow
# unbounded — Render Standard is 2 GB across two workers, so an
# unchecked leak here is one of the things that causes the ~6-minute
# container restarts the user reported in the gunicorn logs (and was
# even worse on the 512 MB Starter the bounds were originally sized
# for). The /api/runs/<id>/status endpoint falls back to the SQLite
# row when an entry has been evicted, so the user only loses in-memory
# progress-log streaming, never run completion.
_active_runs: BoundedCache = BoundedCache(max_size=64)
# Turn-Into job tracker. The "pack" payload is stripped at completion
# time (the pack is already persisted to disk by save_pack), so each
# entry stays small.
_turn_into_jobs: BoundedCache = BoundedCache(max_size=32)
# Web-research console jobs (Capability 3c). Same small-record shape as
# Turn-Into — status + the cited answer + source URLs — held in memory for
# fast same-worker polls and mirrored to disk for the other worker.
_research_jobs: BoundedCache = BoundedCache(max_size=32)
# In-flight cap for deep-research jobs: each one holds a worker thread for a
# 30-90s LLM+network loop, so the bound is on WORK, not just records — the
# submit route 429s beyond this many status=running jobs.
_RESEARCH_MAX_INFLIGHT = 2
# Club-data Q&A jobs ("Ask the data"). Same lifecycle as the research
# console: background thread, memory + disk record, org-scoped polls.
_club_qa_jobs: BoundedCache = BoundedCache(max_size=32)
# G1.27 design-studio render cache: signature(brief levers) -> the JSON render
# payload (a base64 data-URI preview + its explainability sidecar). Lets the
# interactive editor re-show a previously-seen combination instantly and caps
# repeated Playwright renders. Entries are a few hundred KB each; 48 × keeps it
# well under the worker's memory ceiling.
_studio_render_cache: BoundedCache = BoundedCache(max_size=48)
# Short-lived tally of on-disk cache scale for the operator's cache-purge card.
# Walking every cache root (tens of thousands of files on a mature deployment)
# on every /settings/developer render costs seconds; a 60s snapshot is plenty
# fresh for an informational figure and is cleared on purge.
_cache_tally_cache: BoundedCache = BoundedCache(max_size=1)
_CACHE_TALLY_TTL = 60.0
# RLock so callers holding _active_lock can re-enter BoundedCache's
# own lock without deadlock.
_active_lock = threading.RLock()

# When either dict exceeds the threshold, the oldest finished entries
# are pruned to bring it back to the target. "Finished" = status in
# (done, error). Running rows are never evicted while in flight.
_ACTIVE_RUNS_LIMIT = 60
_ACTIVE_RUNS_TARGET = 40
_TURN_INTO_LIMIT = 30
_TURN_INTO_TARGET = 20
# Bound each run's log to the last N lines. A long pipeline emits ~20
# messages but a bug could spam thousands — cap defensively.
_RUN_LOG_LIMIT = 200
# A run whose heartbeat hasn't advanced in this many seconds is treated
# as dead: its gunicorn worker was recycled mid-pipeline (--max-requests)
# or restarted, taking the daemon worker thread with it, or a network
# call wedged past every per-call timeout. The status poller and the
# startup reconciler then surface a terminal error instead of letting
# the page spin forever. Generous on purpose — a single slow PB lookup
# can chain a 45s + 60s LLM failover, so this must clear that worst case.
_RUN_STALE_SECS = 180
# The heartbeat is advanced two ways: on every progress line (below) AND by a
# background ticker that runs for the lifetime of the worker thread (see
# _heartbeat_ticker in the run worker). The ticker is what makes the heartbeat a
# true *liveness* signal rather than a *progress-cadence* one: a single long,
# progress-silent step — notably the heavy LLM interpretation of a large fresh
# (uncached) PDF, which can run well past _RUN_STALE_SECS without emitting a line —
# no longer trips the staleness check and falsely kills a run that is still
# working. A genuinely dead run is still caught: if the worker is recycled or the
# process dies, the ticker thread dies with it and the heartbeat goes stale as
# before.
_RUN_HEARTBEAT_TICK_SECS = 30.0
# Safety cap on ticker-driven liveness: after this long the ticker stops
# advancing the heartbeat, so a truly wedged thread (an infinite hang with no
# per-call timeout) still goes stale ~_RUN_STALE_SECS later instead of spinning
# forever. Comfortably above any legitimate big-meet run.
_RUN_MAX_LIVENESS_SECS = 1800.0
# Throttle for streaming the progress log to the DB from the worker's
# progress callback. The in-memory entry updates on every line; the DB
# (read by polls that land on the *other* gunicorn worker) only needs to
# be fresh to the second.
_RUN_DB_HEARTBEAT_SECS = 2.0
# QA-015 — durable big-meet runs. The pipeline runs in a daemon thread inside a
# gunicorn worker; a `--max-requests` recycle, an overlapping deploy, or an OOM
# kills that thread mid-run. County/championship-sized meets (500+ swims) take
# long enough — dominated by per-swimmer PB lookups + meet-identity research, NOT
# the cheap detector loop (measured: ~0.4s for 1,000+ swims) — that a recycle is
# far likelier to land while they are in flight, which is why size correlates
# with the failure. Rather than lose the run, we RESUME it: re-run from the
# stored launch input (the pipeline is deterministic + cache-backed, so a resume
# on a fresh worker re-walks the same steps, warm where cached). Bounded so a
# genuinely-broken input cannot loop forever — after this many resumes a stale
# run is surfaced with the honest "please upload again" error instead.
_RUN_MAX_RESUMES = max(0, int(os.environ.get("MEDIAHUB_RUN_MAX_RESUMES", "2") or "2"))
# The honest dead-run message, shared by the status poller and the startup
# reconciler so the wording lives in one place.
_RUN_STALE_ERROR = (
    "Processing stopped responding — the server worker was recycled "
    "mid-run or a step timed out. Please upload the file again."
)


# ---------------------------------------------------------------------------
# Async health-check heartbeat writer.
#
# /healthz is Render's configured liveness probe and must answer fast no
# matter what else the box is doing. The heartbeat it records is a SQLite
# INSERT+commit on the *shared persistent disk*; under a concurrent render
# that disk is contended and the commit's fsync can stall for 10s+. A
# synchronous write therefore turned a slow render into a failed health
# probe -> Render restarted the whole container mid-render (the "image/
# video generation crashed and overloaded the site" incident).
#
# We hand the write to one daemon thread per worker process and return from
# the probe immediately. The write stays best-effort and lossy: a full queue
# drops the row rather than blocking the probe.
# ---------------------------------------------------------------------------
_HEARTBEAT_QUEUE = queue.Queue(maxsize=512)
_heartbeat_thread_started = False
_heartbeat_thread_lock = threading.Lock()
# A heartbeat write slower than this means the persistent disk is contended
# (almost always by a concurrent render). Surface it at WARNING so the
# slow-disk condition shows in the deployment logs without enabling INFO.
_HEARTBEAT_SLOW_WARN_MS = 1000.0


def _heartbeat_drain_loop() -> None:
    """Drain queued heartbeats to the uptime store, off the request path."""
    from mediahub.observability import uptime as _uptime

    while True:
        ok, source, response_ms, error = _HEARTBEAT_QUEUE.get()
        try:
            t0 = time.monotonic()
            _uptime.record_heartbeat(ok=ok, source=source, response_ms=response_ms, error=error)
            write_ms = (time.monotonic() - t0) * 1000.0
            if write_ms >= _HEARTBEAT_SLOW_WARN_MS:
                log.warning(
                    "healthz: heartbeat DB write slow (%.0fms, source=%s) — "
                    "persistent disk contended, likely a concurrent render",
                    write_ms,
                    source,
                )
        except Exception:
            pass
        finally:
            # task_done() must never escape this loop: a stray ValueError
            # ("called too many times" — possible when the queue is join()ed
            # or reset concurrently) would otherwise kill this daemon thread,
            # silently stopping all heartbeat writes for the worker's life.
            try:
                _HEARTBEAT_QUEUE.task_done()
            except ValueError:
                pass


def _ensure_heartbeat_thread() -> None:
    """Start the heartbeat drain thread once per process (idempotent)."""
    global _heartbeat_thread_started
    if _heartbeat_thread_started:
        return
    with _heartbeat_thread_lock:
        if _heartbeat_thread_started:
            return
        threading.Thread(target=_heartbeat_drain_loop, name="heartbeat-writer", daemon=True).start()
        _heartbeat_thread_started = True


# ---------------------------------------------------------------------------
# Heavy-render admission control.
#
# Image renders (Playwright/Chromium via graphic_renderer) and motion
# renders (Remotion/Node/Chromium) are CPU- and memory-heavy. On the
# single-CPU / 2 GB deployment, running several at once pegs the core and
# blows the memory ceiling -> OOM -> container restart. The regenerate-
# variants route alone fans out to three concurrent Chromium renders. Cap
# how many run at once: single-shot routes get a fast 429 ("busy, try
# again") instead of stacking more Chromium; internal batch members queue
# for a slot so they serialise instead of stampeding.
# ---------------------------------------------------------------------------
_RENDER_LIMIT = max(1, int(os.environ.get("MEDIAHUB_MAX_CONCURRENT_RENDERS", "1") or "1"))
_render_semaphore = threading.BoundedSemaphore(value=_RENDER_LIMIT)
# Single-shot routes wait this briefly for a slot before returning 429:
# long enough that back-to-back cache hits don't false-trip, short enough
# that the user gets snappy "busy" feedback while a cold render runs.
_RENDER_TRY_TIMEOUT = float(os.environ.get("MEDIAHUB_RENDER_TRY_TIMEOUT", "0.75") or "0.75")
# Internal batch members (the variant threads) queue up to this long for a
# slot so all of them complete, just serialised rather than concurrent.
_RENDER_QUEUE_TIMEOUT = float(os.environ.get("MEDIAHUB_RENDER_QUEUE_TIMEOUT", "180") or "180")
# A render holding a slot longer than this is logged at WARNING so slow
# renders are visible without enabling INFO.
_RENDER_SLOW_WARN_MS = 20_000.0


class _RenderBusy(Exception):
    """Raised when a render slot can't be acquired within the wait budget."""


@contextlib.contextmanager
def _render_slot(kind: str, label: str = "", *, timeout: float):
    """Hold a **per-worker** render slot for the duration of one heavy render.

    The semaphore is process-local: each Gunicorn worker has its own, so under
    ``--workers N`` the real cross-process ceiling is ``N × _RENDER_LIMIT``
    concurrent heavy renders, not ``_RENDER_LIMIT``. (Sizing/behaviour is
    unchanged — this only corrects the earlier "global slot" wording.)

    Raises ``_RenderBusy`` if no slot frees up within ``timeout`` seconds.
    Always releases the slot, even if the render raises.
    """
    if not _render_semaphore.acquire(timeout=timeout):
        log.warning(
            "render gate: %s rejected (no slot after %.2fs, limit=%d) label=%s",
            kind,
            timeout,
            _RENDER_LIMIT,
            label,
        )
        raise _RenderBusy(kind)
    t0 = time.monotonic()
    try:
        yield
    finally:
        dur_ms = (time.monotonic() - t0) * 1000.0
        _render_semaphore.release()
        if dur_ms >= _RENDER_SLOW_WARN_MS:
            log.warning("render gate: %s finished SLOW (%.0fms) label=%s", kind, dur_ms, label)
        else:
            log.info("render gate: %s finished (%.0fms) label=%s", kind, dur_ms, label)


class _PinnedStreamResponse:
    """requests.Response-shaped adapter over a pinned urllib3 response.

    Exposes exactly what the media-import callers use — ``raise_for_status``,
    ``headers``, ``raw.read(amt, decode_content=...)`` and ``close`` — while
    the underlying connection is pinned to the SSRF-validated IP. Holding the
    pool ties its lifetime to the response so the connection isn't reclaimed
    mid-stream.
    """

    __slots__ = ("raw", "headers", "status_code", "_pool")

    def __init__(self, r, pool) -> None:
        self.raw = r  # urllib3 response: .read(amt, decode_content=...)
        self.headers = r.headers
        self.status_code = int(r.status)
        self._pool = pool

    def raise_for_status(self) -> None:
        if self.status_code >= 400:
            # Deliberately NOT ValueError: callers map ValueError to a 400
            # "bad url" and everything else to a 502 "download_failed",
            # matching the previous requests.HTTPError behaviour.
            raise RuntimeError(f"HTTP {self.status_code}")

    def close(self) -> None:
        for closer in (self.raw.close, self._pool.close):
            try:
                closer()
            except Exception:
                pass


def _ssrf_safe_stream_get(url: str, *, timeout: int, max_hops: int = 5):
    """Streaming GET that refuses SSRF on a user-supplied URL.

    The initial URL and every redirect hop are resolved + validated and the
    connection is made to the validated IP itself
    (``web_research.safe_fetch.pinned_stream_get``), so an authenticated
    tenant can't aim a media import at an internal / cloud-metadata address —
    including via DNS rebinding between the check and the fetch. Returns a
    response with the body unread so callers can gate on status/content-type
    before a bounded read; raises ``ValueError`` when any hop is unsafe or the
    chain is too long.
    """
    from mediahub.web_research.safe_fetch import pinned_stream_get  # noqa: PLC0415

    r, pool = pinned_stream_get(url, timeout=float(timeout), max_hops=max_hops)
    return _PinnedStreamResponse(r, pool)


def _render_busy_response(kind: str):
    """Standard 429 payload returned when the render gate is saturated."""
    resp = jsonify(
        {
            "error": "renderer_busy",
            "kind": "busy",
            # Which render type saturated (graphic/motion/reel/variant/…) — for
            # 429 telemetry; JS still keys off error/renderer_busy + HTTP 429.
            "renderer": kind,
            "user_message": (
                "The renderer is busy finishing another graphic or video. "
                "Give it a few seconds and try again."
            ),
        }
    )
    resp.status_code = 429
    resp.headers["Retry-After"] = "5"
    return resp


def _friendly_failure_message(exc: Exception, *, kind: str = "ai", context: str = "") -> str:
    """Map a provider/render exception to plain-English customer copy, logging
    the raw exception server-side only (D-23).

    Customers on the chat, draft-graphic and public-demo surfaces must never
    read a raw Python exception or ``render_failed: <traceback>`` — it looks
    like the product broke and leaks internals. Operators still get the full
    detail in the server log via ``exc_info``.

    ``kind`` picks the copy register: ``"ai"`` for LLM / caption / chat turns,
    ``"render"`` for graphic / video renders. When the underlying cause is an
    unconfigured or unavailable AI provider we say so honestly — the fix is an
    operator action, not a customer retry — otherwise we describe a transient
    hiccup and invite a retry.
    """
    log.warning(
        "%s failure%s: %s",
        kind,
        f" [{context}]" if context else "",
        exc,
        exc_info=True,
    )
    name = type(exc).__name__
    text = str(exc).lower()
    provider_gap = name in {"ProviderNotConfigured", "ClaudeUnavailableError"} or any(
        hint in text for hint in ("not configured", "no provider", "unavailable", "no api key")
    )
    if provider_gap:
        return (
            "AI isn't switched on for this workspace yet, so this step can't run. "
            "Ask your administrator to connect an AI provider, then try again."
        )
    if kind == "render":
        return "We couldn't finish rendering this just now. Give it a moment and try again."
    return "Something went wrong on our side and this step didn't finish. Please try again in a moment."


# ---------------------------------------------------------------------------
# V10: background job store for the 3-variant regenerate fan-out.
#
# The synchronous route held one HTTP request open across three sequential
# Chromium renders (60-120s on the single-CPU box) — past proxy-timeout
# territory and a dishonest "10-30 seconds" UX. The route now returns a
# job id instantly; a daemon thread renders the variants one at a time
# (the render gate is 1-slot anyway, so parallel threads only added
# queue-timeout risk) and the UI polls /api/variant-jobs/<id>.
# ---------------------------------------------------------------------------
# DISK-BACKED, not in-memory: gunicorn runs ``--workers 2`` (docker-entrypoint.sh), so
# the POST that creates a job and the GETs that poll it routinely land on
# different processes — an in-memory dict 404s ("job_not_found") for half
# the polls. Jobs are tiny JSON files under RUNS_DIR/_variant_jobs/,
# written atomically (tmp + os.replace). ``--max-requests 200`` also
# recycles workers mid-job; a job whose file stops updating is reported
# as lost instead of spinning forever.
_VARIANT_JOB_TTL_S = 15 * 60.0
_VARIANT_JOB_STALL_S = 5 * 60.0  # running + no file update for this long = lost


def _variant_jobs_dir() -> Path:
    d = RUNS_DIR / "_variant_jobs"
    try:
        d.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass
    return d


def _variant_job_save(job: dict) -> None:
    """Atomically persist a job snapshot.

    Two threads save the same job (the worker and its ``_job_heartbeat``),
    so the tmp name is unique per write — a shared ``.tmp`` path let their
    writes interleave into a torn/absent job file for a poll cycle. The tmp
    stays in the same directory, so ``os.replace`` remains atomic."""
    job["updated_at"] = time.time()
    path = _variant_jobs_dir() / f"{job['id']}.json"
    tmp = path.with_suffix(f".{uuid.uuid4().hex[:8]}.tmp")
    try:
        tmp.write_text(json.dumps(job), encoding="utf-8")
        os.replace(tmp, path)
    except Exception:
        log.exception("variant job %s: persist failed", str(job.get("id", ""))[:8])
        with contextlib.suppress(OSError):
            tmp.unlink(missing_ok=True)


def _variant_job_load(job_id: str) -> Optional[dict]:
    if not re.fullmatch(r"[0-9a-f]{32}", job_id or ""):
        return None
    path = _variant_jobs_dir() / f"{job_id}.json"
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None


@contextlib.contextmanager
def _job_heartbeat(job: dict, interval_s: float = 60.0):
    """Keep a running job's file fresh while a slow render is in flight.

    The status routes flag a "running" job as lost once its file hasn't been
    touched for ``_VARIANT_JOB_STALL_S`` (5 min) — but a legitimately slow cold
    reel render is allowed up to the 600s subprocess timeout, so a healthy
    worker was reported "job_lost … the render worker restarted" while still
    rendering. This touch thread re-saves the job every ``interval_s`` seconds
    for the duration of the ``with`` block and stops (joined) before the worker
    writes its final state, preserving the single-writer rule. A genuinely
    dead worker stops heartbeating, so honest job-lost reports still happen.
    """
    stop = threading.Event()

    def _beat() -> None:
        while not stop.wait(interval_s):
            _variant_job_save(job)

    t = threading.Thread(target=_beat, name=f"jobbeat-{str(job.get('id', ''))[:8]}", daemon=True)
    t.start()
    try:
        yield
    finally:
        stop.set()
        t.join(timeout=5.0)


def _variant_jobs_gc() -> None:
    """Best-effort removal of expired job files (any worker may run this)."""
    now = time.time()
    try:
        for f in _variant_jobs_dir().glob("*.json"):
            try:
                if now - f.stat().st_mtime > _VARIANT_JOB_TTL_S:
                    f.unlink(missing_ok=True)
            except Exception:
                pass
    except Exception:
        pass


def _maybe_evict_active_runs() -> None:
    """Best-effort FIFO eviction of finished entries in _active_runs.

    Must be called with _active_lock held. Idempotent — no-op when
    the dict is under the threshold.
    """
    if len(_active_runs) <= _ACTIVE_RUNS_LIMIT:
        return
    # Oldest first. Use the started_at ISO string as the sort key.
    finished_ordered = sorted(
        (
            (rid, info)
            for rid, info in _active_runs.items()
            if info.get("status") in ("done", "error")
        ),
        key=lambda kv: kv[1].get("started_at", ""),
    )
    to_remove = max(0, len(_active_runs) - _ACTIVE_RUNS_TARGET)
    for rid, _ in finished_ordered[:to_remove]:
        _active_runs.pop(rid, None)


def _maybe_evict_turn_into_jobs() -> None:
    """Best-effort FIFO eviction of finished Turn-Into jobs. Must hold
    _active_lock."""
    if len(_turn_into_jobs) <= _TURN_INTO_LIMIT:
        return
    finished = [
        jid for jid, info in _turn_into_jobs.items() if info.get("status") in ("done", "error")
    ]
    to_remove = max(0, len(_turn_into_jobs) - _TURN_INTO_TARGET)
    for jid in finished[:to_remove]:
        _turn_into_jobs.pop(jid, None)


# ---- Cross-worker async-job state (shared disk store) ----------------
#
# gunicorn runs --workers 2, so the worker that creates an async job (and
# holds it in an in-memory BoundedCache) is usually NOT the worker a later
# status poll round-robins to. Without a shared store the poll on the other
# worker sees nothing and the UI shows "job not found". Runs dodge this via
# their SQLite row; the lighter async jobs (Turn-Into packs, web-research
# answers) get the same treatment via a tiny JSON file per job on the shared
# DATA_DIR disk. Records are small and short-lived, so a flat directory of
# <subdir>/<job_id>.json files is enough — no schema, no migration.


def _job_records_dir(subdir: str) -> Path:
    d = DATA_DIR / subdir
    d.mkdir(parents=True, exist_ok=True)
    return d


def _job_record_write(subdir: str, job_id: str, record: dict) -> None:
    """Persist a job record under DATA_DIR/<subdir> so any gunicorn worker
    can read it. Atomic (temp file + os.replace) so a concurrent poll never
    reads a half-written file. Best-effort — a disk hiccup must not break the
    job, since the in-memory cache still serves same-worker polls."""
    try:
        path = _job_records_dir(subdir) / f"{job_id}.json"
        tmp = path.with_name(f"{job_id}.json.{os.getpid()}.tmp")
        tmp.write_text(json.dumps(record, default=str))
        os.replace(tmp, path)
    except Exception:
        pass


def _job_record_read(subdir: str, job_id: str) -> Optional[dict]:
    """Read a persisted job record, or None if absent/unreadable."""
    try:
        path = _job_records_dir(subdir) / f"{job_id}.json"
        if not path.exists():
            return None
        return json.loads(path.read_text())
    except Exception:
        return None


def _prune_job_records(subdir: str, max_age_secs: int = 21_600) -> None:
    """Delete job-status files older than max_age_secs (default 6h). Jobs
    finish in well under two minutes, so anything older is long done and any
    durable artefact (a pack, say) is already persisted separately."""
    try:
        now = time.time()
        for f in _job_records_dir(subdir).glob("*.json"):
            try:
                if now - f.stat().st_mtime > max_age_secs:
                    f.unlink()
            except Exception:
                continue
    except Exception:
        pass


# Turn-Into jobs were the first user of the shared store; keep their original
# helper names as thin wrappers so existing call sites are unchanged.
def _ti_job_write(job_id: str, record: dict) -> None:
    _job_record_write("turn_into_jobs", job_id, record)


def _ti_job_read(job_id: str) -> Optional[dict]:
    return _job_record_read("turn_into_jobs", job_id)


def _prune_ti_job_files(max_age_secs: int = 21_600) -> None:
    _prune_job_records("turn_into_jobs", max_age_secs)


def _research_console_enabled() -> bool:
    """The web-research console (Capability 3c) is OFF by default. The operator
    opts in with MEDIAHUB_RESEARCH_UI=1 — it triggers LLM + network activity,
    so it must never be exposed by accident. Read at request time so the flag
    flips without a code change (matches how the search endpoint resolves)."""
    return os.environ.get("MEDIAHUB_RESEARCH_UI", "").strip().lower() in {
        "1",
        "true",
        "yes",
        "on",
    }


# UI 1.1 — Cycling example-prompt placeholders (inspired by Cosmos). Each
# describe-a-moment / search field carries a pipe-delimited list of real example
# prompts in a data-mh-cycle-placeholder attribute; bindCyclePlaceholders() in
# _layout types them through the field's own placeholder (a typewriter cycle:
# type → hold → erase → next), guiding first-time users with zero extra chrome.
# Pure vanilla JS, no deps, prefers-reduced-motion respected. The static
# placeholder="" each field already carries stays as the no-JS / reduced-motion
# fallback, so nothing is lost when the script or motion is unavailable.
_CYCLE_PH_MOMENT = (
    "Try: Tom Davies PB 100m free",
    "Try: top three at county finals",
    "Try: thank-you to our sponsor Riverside Physio",
    "Try: Maya's first sub-30 50m fly",
    "Try: relay squad breaks the club record",
    "Try: medal haul from the regional gala",
)
_CYCLE_PH_RESEARCH = (
    "Try: 2024 county championship headline results",
    "Try: who set the regional 100m free record this season",
    "Try: latest Swim England qualifying times",
)
_CYCLE_PH_ASKDATA = (
    "Try: when did Alice Lee last PB the 100m free",
    "Try: our medal count at the spring gala",
    "Try: which swimmers broke 30s in the 50m fly",
)


def _cycle_ph_attr(phrases) -> str:
    """Render the ``data-mh-cycle-placeholder`` attribute for one field.

    The phrases are joined with `` | `` (the JS splits on the pipe, trimming
    whitespace) and HTML-escaped so the value is safe inside a double-quoted
    attribute. Returns the whole ``data-mh-cycle-placeholder="…"`` token so call
    sites just drop it into the tag.
    """
    return f'data-mh-cycle-placeholder="{_h(" | ".join(phrases))}"'


# Precomputed once at import — the lists are static, so there's no reason to
# rebuild the escaped attribute on every request.
_CYCLE_PH_ATTR_MOMENT = _cycle_ph_attr(_CYCLE_PH_MOMENT)
_CYCLE_PH_ATTR_RESEARCH = _cycle_ph_attr(_CYCLE_PH_RESEARCH)
_CYCLE_PH_ATTR_ASKDATA = _cycle_ph_attr(_CYCLE_PH_ASKDATA)

# Upper bound on a single free-text prompt / chat reply before it reaches the
# LLM. A describe-your-post prompt is a sentence or two; this is a generous
# ceiling that still stops a several-hundred-KB paste from being forwarded to
# the provider verbatim and billed as input tokens (the only other limit is the
# 50 MB MAX_CONTENT_LENGTH, far too high to bound LLM cost).
_FREE_TEXT_MAX_PROMPT_CHARS = 8000


# UI2.6 — Vanish search. The /activity (global run) search uses the design-kit
# Vanish input (.mh-vanish): a rotating overlay-placeholder element
# (.mh-vanish__ph) that swap-fades through real example queries, instead of the
# UI 1.1 typewriter-through-the-native-placeholder cycle. The native placeholder
# is emptied (the overlay carries the hint), so the input keeps an explicit
# aria-label as its accessible name. bindVanish() in ui-kit.js reads this
# pipe-delimited list from data-mh-placeholders and rotates it (paused while the
# field holds text, no rotation under prefers-reduced-motion). The first phrase
# is also baked into the overlay element server-side so the hint reads with no
# JS, and a :placeholder-shown CSS rule hides the overlay the instant the box
# holds text even if .is-typing never gets toggled (no-JS / pre-init safety).
_VANISH_PH_SEARCH = (
    "Search meet name, file or run id…",
    "Search county championships…",
    "Search spring gala 2026…",
    "Find a file like regionals.hy3…",
    "Jump to a run id like 7f3c9a…",
)


def _vanish_ph_attr(phrases) -> str:
    """Render the ``data-mh-placeholders`` attribute for a Vanish input.

    Phrases are joined with `` | `` (``bindVanish()`` in ``ui-kit.js`` splits on
    the pipe and trims) and HTML-escaped so the value is safe inside a
    double-quoted attribute. Returns the whole ``data-mh-placeholders="…"`` token
    so call sites just drop it onto the ``.mh-vanish`` container.
    """
    return f'data-mh-placeholders="{_h(" | ".join(phrases))}"'


# Precomputed once at import — the list is static.
_VANISH_PH_ATTR_SEARCH = _vanish_ph_attr(_VANISH_PH_SEARCH)


# Console page body (Capability 3c). A plain string — NOT an f-string — so the
# JS braces stay literal; the route swaps __SUBMIT_URL__ for the real endpoint.
# Results are rendered with textContent / createElement only (never innerHTML),
# because answer text and source URLs come from the model + the open web and
# must not be trusted as markup.
_WEB_RESEARCH_CONSOLE_BODY = """
<section class="panel" style="max-width:840px;margin:28px auto">
  <h1 style="margin-top:0">Web research</h1>
  <p style="color:var(--muted);line-height:1.5">
    Ask a question and MediaHub runs a bounded, cited web search &mdash; a few
    targeted searches and page reads, then a source-grounded answer. Sources on
    authoritative domains are flagged. If the loop can't verify an answer within
    its bound it says so and asserts nothing &mdash; partial results are discarded.
  </p>
  <form id="rform" data-no-loader="1" style="margin-top:16px">
    <textarea id="rq" name="question" rows="3" maxlength="500" required __CYCLE_PH__
      placeholder="e.g. What were the headline results at the 2024 county championships for the City Aquatics club?"
      style="width:100%;padding:12px;border-radius:10px;border:1px solid var(--border);background:rgba(255,255,255,0.04);color:inherit;font-family:inherit;font-size:15px;box-sizing:border-box"></textarea>
    <div style="margin-top:12px;display:flex;gap:12px;align-items:center;flex-wrap:wrap">
      <button class="btn" type="submit" id="rbtn">Research</button>
      <span id="rhint" style="color:var(--muted);font-size:13px"></span>
    </div>
  </form>
  <div id="rresult" style="display:none;margin-top:24px">
    <div id="rstatus" style="font-size:13px;color:var(--muted);margin-bottom:12px"></div>
    <div id="ranswer" style="white-space:pre-wrap;line-height:1.55"></div>
    <div id="rsources" style="margin-top:20px"></div>
    <div id="rmeta" style="margin-top:14px;font-size:12px;color:var(--muted)"></div>
  </div>
</section>
<script>
(function(){
  var SUBMIT_URL = "__SUBMIT_URL__";
  var form = document.getElementById('rform');
  var btn = document.getElementById('rbtn');
  var hint = document.getElementById('rhint');
  var result = document.getElementById('rresult');
  var statusEl = document.getElementById('rstatus');
  var answerEl = document.getElementById('ranswer');
  var sourcesEl = document.getElementById('rsources');
  var metaEl = document.getElementById('rmeta');
  var timer = null;

  function clearOut(){ answerEl.textContent=''; sourcesEl.textContent=''; metaEl.textContent=''; }
  function done(){ if(timer){clearInterval(timer); timer=null;} btn.classList.remove('loading'); btn.disabled=false; hint.textContent=''; }

  function render(d){
    statusEl.textContent = d.complete
      ? 'Done.'
      : 'Inconclusive \\u2014 the research loop could not verify an answer within its bound, so nothing is asserted.';
    answerEl.textContent = d.answer || (d.complete ? '' : '(no verified answer)');
    var auth = {};
    (d.authority_sources || []).forEach(function(u){ auth[u] = 1; });
    var srcs = d.sources || [];
    if (srcs.length){
      var head = document.createElement('div');
      head.textContent = 'Sources'; head.style.fontWeight = '600'; head.style.marginBottom = '8px';
      sourcesEl.appendChild(head);
      var ul = document.createElement('ul');
      ul.style.margin = '0'; ul.style.paddingLeft = '18px';
      srcs.forEach(function(u){
        var li = document.createElement('li'); li.style.marginBottom = '6px';
        var a = document.createElement('a');
        a.textContent = u;
        var ok = (typeof u === 'string') && (u.indexOf('http://') === 0 || u.indexOf('https://') === 0);
        if (ok){ a.href = u; a.target = '_blank'; a.rel = 'noopener noreferrer'; }
        a.style.color = 'var(--lane,var(--accent,#8ab4ff))'; a.style.wordBreak = 'break-all';
        li.appendChild(a);
        if (auth[u]){
          var b = document.createElement('span');
          b.textContent = 'authority';
          b.style.cssText = 'margin-left:8px;font-size:11px;padding:1px 7px;border-radius:999px;background:rgba(94,227,154,0.15);color:#5EE39A;border:1px solid rgba(94,227,154,0.35)';
          li.appendChild(b);
        }
        ul.appendChild(li);
      });
      sourcesEl.appendChild(ul);
    }
    metaEl.textContent = 'rounds: ' + (d.rounds || 0) + ' \\u00b7 tool calls: ' + (d.tool_calls || 0);
  }

  function poll(url){
    fetch(url, {cache:'no-store'})
      .then(function(r){ return r.json().then(function(j){ return {s:r.status, j:j}; }); })
      .then(function(o){
        if (o.j && o.j.status === 'running') return;
        done();
        if (o.s >= 500 || (o.j && o.j.status === 'error')){
          statusEl.textContent = 'Research failed: ' + ((o.j && o.j.error) || 'unknown error');
          return;
        }
        render(o.j || {});
      })
      .catch(function(){ /* transient — keep polling */ });
  }

  form.addEventListener('submit', function(e){
    e.preventDefault();
    var q = document.getElementById('rq').value.trim();
    if (!q) return;
    if (timer){ clearInterval(timer); timer = null; }
    clearOut();
    result.style.display = 'block';
    statusEl.textContent = 'Researching\\u2026 this can take up to a minute.';
    btn.classList.add('loading'); btn.disabled = true; hint.textContent = 'Working\\u2026';
    fetch(SUBMIT_URL, {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({question:q})})
      .then(function(r){ return r.json().then(function(j){ return {s:r.status, j:j}; }); })
      .then(function(o){
        if (!o.j || !o.j.ok || !o.j.status_url){
          done();
          statusEl.textContent = 'Could not start research: ' + ((o.j && (o.j.message || o.j.error)) || ('HTTP ' + o.s));
          return;
        }
        var su = o.j.status_url;
        timer = setInterval(function(){ poll(su); }, 1800);
        poll(su);
      })
      .catch(function(){ done(); statusEl.textContent = 'Could not start research (network error).'; });
  });
})();
</script>
"""

