BASE_CSS = (
    _MH_TT_CSS
    + BASE_CSS
    + _MH_TC_CSS
    + _MH_AUDIENCE_ICON_CSS
    + _MH_MOTION_CSS
    + _MH_PL_CSS
    + _MH_CI_CSS
    + _MH_CAD_CSS
    + _MH_MISC_CHROME_CSS
    # RESPONSIVE_GUARDRAILS_CSS (_MH_RG_CSS) MUST stay the final chunk — it holds
    # the highest-priority responsive overrides and is test-guarded to be last.
    + _MH_RG_CSS
)


# Per-file content-hash fingerprint for a static asset. It rides the asset URL
# as `?v=…` so the long SEND_FILE_MAX_AGE_DEFAULT browser cache can hold the file
# across navigations, yet a deploy that changes the file ships a new URL and busts
# that cache immediately. A content hash (not file mtime) means every replica
# computes the same value, so a load-balanced fleet agrees on the URL. Every
# behaviour-bearing static JS must carry this buster or a returning browser can
# run week-stale JS against new server code on an auto-deploying trunk. Falls back
# to a constant only if the file is unreadable. Computed once per file and cached.
_STATIC_VER_CACHE: dict[str, str] = {}
_STATIC_DIR = Path(__file__).resolve().parent / "static"


def _static_ver(filename: str) -> str:
    """Short sha256 of a file under ``static/`` for cache-busting ``?v=``."""
    cached = _STATIC_VER_CACHE.get(filename)
    if cached is not None:
        return cached
    try:
        ver = hashlib.sha256((_STATIC_DIR / filename).read_bytes()).hexdigest()[:10]
    except OSError:
        ver = "static"
    _STATIC_VER_CACHE[filename] = ver
    return ver


# Back-compat alias — the UI kit's buster is now just one file's content hash.
_UI_KIT_VER = _static_ver("js/ui-kit.js")


# U.9 — cycling hero accent word. The content types MediaHub makes, in the
# order the signed-out landing hero crossfades through them. The first word is
# the one the server renders active (so it shows with no JavaScript and is the
# one a screen reader announces); the rest are aria-hidden decorative cycles.
_HERO_CONTENT_WORDS = ("stories", "reels", "graphics", "captions")

# The script that drives the crossfade. It only toggles `.is-active`; the
# crossfade itself is the CSS opacity transition on `.mh-word-cycle-item`. It
# is a no-op when the visitor asks for reduced motion (matchMedia guard) and
# when there is nothing to cycle, and it pauses while the tab is backgrounded
# so it isn't running a timer off-screen. Inline is fine: the CSP allows
# 'unsafe-inline' scripts and the rest of the app already uses inline scripts.
_HERO_WORD_CYCLE_JS = """<script>
(function(){
  var mq = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)');
  if (mq && mq.matches) return;
  var box = document.querySelector('[data-mh-word-cycle]');
  if (!box) return;
  var items = box.querySelectorAll('.mh-word-cycle-item');
  if (items.length < 2) return;
  var i = 0, timer = null;
  function step(){
    items[i].classList.remove('is-active');
    i = (i + 1) % items.length;
    items[i].classList.add('is-active');
  }
  function start(){ if (timer === null) { timer = window.setInterval(step, 2600); } }
  function stop(){ if (timer !== null) { window.clearInterval(timer); timer = null; } }
  document.addEventListener('visibilitychange', function(){
    if (document.hidden) { stop(); } else { start(); }
  });
  start();
})();
</script>"""


def _hero_word_cycle_html() -> str:
    """The signed-out hero's cycling content-type accent (U.9).

    Returns the ``<span class="mh-word-cycle">`` carrying one
    ``.editorial`` (gold serif-italic) word per content type. The first word
    is rendered ``is-active`` so it is the one shown with no JavaScript and the
    one a screen reader reads; the rest are ``aria-hidden`` decorative cycles.
    The words are fixed constants — no user input — so no escaping is needed.
    """
    spans = []
    for k, word in enumerate(_HERO_CONTENT_WORDS):
        cls = "editorial mh-word-cycle-item" + (" is-active" if k == 0 else "")
        hidden = "" if k == 0 else ' aria-hidden="true"'
        spans.append(f'<span class="{cls}"{hidden}>{word}</span>')
    return '<span class="mh-word-cycle" data-mh-word-cycle>' + "".join(spans) + "</span>"


def _logo_chip_html(
    src_url: str,
    alt: str = "",
    *,
    height: int = 96,
    dominant_hex: Optional[str] = None,
    surface_hex: Optional[str] = None,
    force_chip: bool = False,
    force_bare: bool = False,
    extra_attrs: str = "",
    size: str = "",
    tone: str = "",
    brand_hex: str = "",
    initials: str = "",
) -> str:
    """Render an uploaded logo with the chip-vs-bare decision.

    Phase 1.6 Stage F:
      F1 — default to a neutral chip behind every uploaded logo
      F2 — auto-detect "safe to drop chip" via ΔE2000 + APCA gates

    The chip's neutral-background styling lives in theme-base.css
    (.mh-logo-chip class); this helper picks the wrapping
    structure. Reads the active profile's derived palette for the
    surface colour (so a re-themed chrome uses the correct
    surface) and the logo's AI dominant colour for the gates.

    Parameters
    ----------
    src_url : str
        The logo URL (already HTML-escape-safe — callers pass
        the output of ``url_for`` or pre-escaped).
    alt : str
        Alt text for the ``<img>``. Will be HTML-escaped.
    height : int
        Max-height for the logo image in CSS px.
    dominant_hex : str | None
        The logo's dominant non-neutral colour, typically
        ``logo_meta['ai_dominant_colours'][0]``. If None, the
        helper falls back to safe-by-default chip mode.
    surface_hex : str | None
        Surface colour the logo will sit on. Defaults to the
        active profile's resolved surface, or ``#0A0B11`` (the
        Stage A default).
    force_chip / force_bare : bool
        Override the auto-detection. ``force_chip=True`` is used
        for grids / thumbnails where visual consistency matters
        more than per-logo lightness.
    extra_attrs : str
        Already-escaped attribute fragment appended to the
        ``<img>`` element (e.g. additional inline style).
    size : str
        ``"sm"`` / ``"md"`` / ``"lg"``. When set, render the ELEVATED chrome
        chip: a fixed-size, contrast-aware framed chip with a built-in initials
        fallback (overrides ``height`` and the bare/chip auto-detect). Empty →
        the legacy chip/bare behaviour above.
    tone : str
        ``"light"`` / ``"dark"`` — the backing the logo reads best on
        (``brand.logos.logo_chip_tone``). Only used in elevated mode.
    brand_hex : str
        Org primary hex — a subtle on-brand tint of the backing. Elevated mode.
    initials : str
        Fallback text shown when the logo can't load (``onerror``) or ``src_url``
        is empty. Elevated mode. Do NOT pass an ``onerror`` in ``extra_attrs``
        in elevated mode — the chip wires its own.
    """
    safe_src = _h(src_url)
    safe_alt = _h(alt or "")

    # Elevated chrome chip (opt-in via ``size``): a fixed-size, contrast-aware
    # framed chip with a built-in initials fallback — used by the nav avatar, the
    # sign-in picker tiles and the settings preview so EVERY club's mark reads at
    # the same size and weight whatever its colour / shape / format. ``src_url``
    # is the KEYED ``?bg=1&chip=1`` silhouette (opaque backgrounds removed, and an
    # unrenderable logo 404s so ``onerror`` swaps in the initials). ``tone`` is the
    # backing the logo reads best on (brand.logos.logo_chip_tone); ``brand_hex``
    # tints the backing subtly. Always framed (never bare) for a standardised look.
    if size:
        _sz = size if size in ("sm", "md", "lg") else "md"
        _tone = tone if tone in ("light", "dark") else "light"
        classes = f"mh-logo-chip mh-logo-chip--{_sz} mh-logo-chip--{_tone}"
        chip_style = ""
        if brand_hex and re.match(r"^#[0-9A-Fa-f]{3,8}$", brand_hex):
            chip_style = f' style="--chip-brand:{_h(brand_hex)}"'
        has_img = bool(src_url)
        if not has_img:
            classes += " is-empty"  # no logo → show the initials straight away
        out = [f'<span class="{classes}"{chip_style} aria-hidden="true">']
        if has_img:
            _lazy = "" if _sz == "sm" else ' loading="lazy" decoding="async"'
            out.append(
                f'<img class="mh-logo-chip__img" src="{safe_src}" alt="{safe_alt}"{_lazy}'
                " onerror=\"this.closest('.mh-logo-chip').classList.add('is-empty')\""
                f"{extra_attrs} />"
            )
        out.append(f'<span class="mh-logo-chip__initials">{_h(initials or "?")}</span>')
        out.append("</span>")
        return "".join(out)

    if force_chip and force_bare:
        force_chip = False  # bare wins on contradiction

    if force_bare:
        decision_mode = "bare"
    elif force_chip or dominant_hex is None:
        decision_mode = "chip"
    else:
        if surface_hex is None:
            surface_hex = _active_surface_hex()
        try:
            from mediahub.theming.logo_chip import decide_logo_chip

            decision = decide_logo_chip(dominant_hex, surface_hex)
            decision_mode = decision.mode
        except Exception:
            decision_mode = "chip"

    img_tag = (
        f'<img src="{safe_src}" alt="{safe_alt}" '
        f'style="max-height:{int(height)}px;max-width:100%;'
        f'object-fit:contain;display:block"{extra_attrs} />'
    )
    if decision_mode == "bare":
        return img_tag
    return f'<span class="mh-logo-chip">{img_tag}</span>'


def _active_surface_hex() -> str:
    """Resolved value of the active theme's --mh-surface, or
    ``#0A0B11`` (Stage A default) when no profile is active or the
    derived palette is missing.

    Stage F uses the dark-scheme surface because MediaHub's chrome
    is dark-only today; Stage J may revisit when light-mode visual
    design ships."""
    try:
        from flask import current_app

        get_active = getattr(current_app, "active_profile", None)
        if not get_active:
            return "#0A0B11"
        prof = get_active()
    except (RuntimeError, Exception):
        return "#0A0B11"
    if not prof:
        return "#0A0B11"
    try:
        kit = prof.get_brand_kit()
        palette = kit.ensure_derived_palette() or {}
    except Exception:
        return "#0A0B11"
    roles = palette.get("roles") or {}
    dark = roles.get("dark") or {}
    surface = dark.get("surface")
    return surface if isinstance(surface, str) and surface.startswith("#") else "#0A0B11"


def _repair_summary_text(theme_json: Optional[dict]) -> Optional[str]:
    """Phase 1.6 Stage H3 — plain-English summary of any repair-loop
    adjustments.

    Returns:
        None when ``was_repaired`` is False or the theme JSON is
        missing the data we need.
        A one-sentence string when the repair loop ran AND at least
        one status anchor moved from its canonical hue.
    """
    if not isinstance(theme_json, dict) or not theme_json.get("was_repaired"):
        return None
    palettes = theme_json.get("palettes") or {}
    try:
        from mediahub.theming.palette import STATUS_ANCHORS
    except Exception:
        return None
    deltas = []
    for name, (canonical_hue, _) in STATUS_ANCHORS.items():
        ramp = palettes.get(name) or {}
        actual_hue = ramp.get("hue")
        if isinstance(actual_hue, (int, float)):
            offset = ((float(actual_hue) - canonical_hue + 180.0) % 360.0) - 180.0
            if abs(offset) >= 1.0:
                deltas.append((name, canonical_hue, float(actual_hue), offset))
    if not deltas:
        return (
            "MediaHub ran additional accessibility checks during palette "
            "derivation; no status anchors needed to move. See decision "
            "trace below for full details."
        )
    parts = []
    for name, _canon, _actual, offset in deltas:
        sign = "+" if offset > 0 else ""
        parts.append(f"{name} (rotated {sign}{offset:.0f}°)")
    listing = ", ".join(parts)
    return (
        f"Your brand seed was close enough to our standard status anchors "
        f"that we adjusted {listing} to keep them distinguishable for "
        f"colour-blind viewers and to satisfy our contrast gates. "
        f"See the decision trace below for the precise gate that fired."
    )


def _theme_audit_panel_html(theme_json: Optional[dict]) -> str:
    """Phase 1.6 Stage H2 — render the "Why does my theme look like
    this?" expandable panel.

    Returns an empty string when ``theme_json`` is None or missing
    the keys required to render. The block is server-side HTML; no
    JS required — uses the native ``<details>`` element so the
    panel works in print, in keyboard-only navigation, and in
    every browser.
    """
    if not isinstance(theme_json, dict):
        return ""

    seed_hex = theme_json.get("seed_hex") or ""
    seed_source = theme_json.get("seed_source") or "unknown"
    seed_hct = theme_json.get("seed_hct") or []
    palettes = theme_json.get("palettes") or {}
    detail = theme_json.get("quality_detail") or {}
    harmonic = theme_json.get("harmonic_fit") or detail.get("harmonic_fit") or {}
    decision_trace = theme_json.get("decision_trace") or []
    was_repaired = bool(theme_json.get("was_repaired"))

    # markupsafe.escape returns Markup objects whose `+` operator
    # HTML-escapes adjacent str operands. Force plain str everywhere
    # so the structural HTML (the literal angle brackets) survives.
    def esc(s) -> str:
        return str(_h(s))

    # Swatch row
    def _swatch(name: str, hex_value: str) -> str:
        return (
            f'<span title="{esc(name)}: {esc(hex_value)}" '
            f'style="display:inline-flex;align-items:center;gap:6px;'
            f"margin-right:14px;margin-bottom:6px;font-size:11px;"
            f'color:var(--mh-on-surface-variant)">'
            f'<span style="display:inline-block;width:22px;height:22px;'
            f"border-radius:4px;background:{esc(hex_value)};"
            f'border:1px solid var(--mh-outline-variant)"></span>'
            f"{esc(name)}</span>"
        )

    swatches_html = ""
    swatch_order = (
        ("primary", "primary"),
        ("secondary", "secondary"),
        ("tertiary", "tertiary"),
        ("neutral", "neutral"),
        ("error", "error"),
        ("success", "success"),
        ("warning", "warning"),
        ("info", "info"),
    )
    for label, palette_name in swatch_order:
        ramp = palettes.get(palette_name) or {}
        tones = ramp.get("tones") or {}
        hex_value = tones.get("400") or tones.get("500") or tones.get("50") or ""
        if hex_value:
            swatches_html += _swatch(label, hex_value)

    # Contrast pairs (top 8 most-relevant text role pairs).
    contrast_rows: list[str] = []
    for c in (detail.get("contrast") or [])[:12]:
        passed = c.get("passes_apca", False)
        symbol = "✓" if passed else "✗"
        colour_var = "--mh-success" if passed else "--mh-error"
        contrast_rows.append(
            f'<tr><td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px">{esc(c.get("scheme", ""))}</td>'
            f'<td style="padding:4px 8px;font-size:12px">{esc(c.get("role_pair", ""))}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{c.get("apca_lc", 0):.1f}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{c.get("wcag2_ratio", 0):.2f}</td>'
            f'<td style="padding:4px 8px;text-align:center;'
            f'color:var({colour_var});font-weight:600">{symbol}</td></tr>'
        )

    # Brand vs status ΔE
    status_rows: list[str] = []
    for s in detail.get("status_distance") or []:
        passed = s.get("passes_hard", False)
        symbol = "✓" if passed else "✗"
        colour_var = "--mh-success" if passed else "--mh-error"
        status_rows.append(
            f'<tr><td style="padding:4px 8px;font-size:12px">'
            f"{esc(s.get('status_name', ''))}</td>"
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px">{esc(s.get("status_hex", ""))}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{s.get("delta_e_2000", 0):.1f}</td>'
            f'<td style="padding:4px 8px;text-align:center;'
            f'color:var({colour_var});font-weight:600">{symbol}</td></tr>'
        )

    # CVD checks
    cvd_rows: list[str] = []
    for c in detail.get("cvd") or []:
        passed = c.get("distinguishable", False)
        symbol = "✓" if passed else "✗"
        colour_var = "--mh-success" if passed else "--mh-warning"
        cvd_rows.append(
            f'<tr><td style="padding:4px 8px;font-size:12px">{esc(c.get("cvd", ""))}</td>'
            f'<td style="padding:4px 8px;font-size:12px">{esc(c.get("pair", ""))}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{c.get("delta_e_2000", 0):.1f}</td>'
            f'<td style="padding:4px 8px;text-align:center;'
            f'color:var({colour_var});font-weight:600">{symbol}</td></tr>'
        )

    # Harmonic fit
    if harmonic and harmonic.get("template"):
        harmonic_html = (
            f'<p style="margin:0;font-size:12px;color:var(--mh-on-surface)">'
            f"Best template: <b>{esc(harmonic['template'])}</b> @ "
            f"<code>{harmonic.get('rotation', 0):.1f}°</code>, "
            f"energy = <code>{harmonic.get('energy', 0):.1f}</code> "
            f"across <code>{harmonic.get('hue_count', 0)}</code> hues "
            f"(Cohen-Or 2006; lower energy = more harmonic)."
            f"</p>"
        )
    else:
        harmonic_html = (
            '<p class="dim" style="margin:0;font-size:12px">'
            "No harmonic fit recorded (older derivation).</p>"
        )

    # Decision trace as <pre>
    trace_text = "\n".join(decision_trace) if decision_trace else "(no trace recorded)"
    trace_html = (
        '<pre style="margin:0;padding:10px 12px;background:var(--mh-surface);'
        "border:1px solid var(--mh-outline-variant);border-radius:6px;"
        "font-family:var(--font-mono);font-size:11px;line-height:1.45;"
        "color:var(--mh-on-surface-variant);max-height:240px;overflow:auto;"
        'white-space:pre-wrap;word-break:break-word">' + esc(trace_text) + "</pre>"
    )

    seed_hct_str = ""
    if isinstance(seed_hct, (list, tuple)) and len(seed_hct) >= 3:
        seed_hct_str = f"HCT(H={seed_hct[0]:.1f}°, C={seed_hct[1]:.1f}, T={seed_hct[2]:.1f})"

    repaired_note = ""
    if was_repaired:
        repaired_note = (
            '<p class="dim" style="margin:6px 0 0;font-size:11px">'
            "⚙ This palette went through the repair loop — see the "
            "callout above for the plain-English summary, or the "
            "decision trace below for the full sequence.</p>"
        )

    return (
        '<details class="mh-theme-audit" style="margin:18px 0 0;'
        "border:1px solid var(--mh-outline-variant);border-radius:8px;"
        'background:var(--mh-surface-variant);overflow:hidden">'
        '<summary style="cursor:pointer;padding:12px 16px;font-size:13px;'
        'font-weight:600;color:var(--mh-on-surface);user-select:none">'
        "Why does my theme look like this?"
        '<span class="muted" style="font-weight:400;font-size:12px;'
        'margin-left:8px">Engine decisions, contrast checks, '
        "accessibility audit</span>"
        "</summary>"
        '<div style="padding:0 16px 16px 16px;'
        'border-top:1px solid var(--mh-outline-variant)">'
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">Captured seed</h4>'
        f'<p style="margin:0;font-size:13px;color:var(--mh-on-surface)">'
        f"Seed <code>{esc(seed_hex)}</code> from "
        f"<code>{esc(seed_source)}</code>; {seed_hct_str}.</p>"
        f"{repaired_note}"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">Derived palette</h4>'
        f'<div style="margin-top:4px">{swatches_html}</div>'
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Contrast checks (APCA Lc · WCAG 2.x)</h4>"
        '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;'
        'font-size:11.5px">'
        '<thead><tr style="border-bottom:1px solid var(--mh-outline-variant)">'
        '<th style="padding:4px 8px;text-align:left">scheme</th>'
        '<th style="padding:4px 8px;text-align:left">role pair</th>'
        '<th style="padding:4px 8px;text-align:right">Lc</th>'
        '<th style="padding:4px 8px;text-align:right">ratio</th>'
        '<th style="padding:4px 8px;text-align:center">ok</th>'
        "</tr></thead><tbody>" + "".join(contrast_rows) + "</tbody></table></div>"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Brand seed vs status anchors (CIEDE2000)</h4>"
        '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;'
        'font-size:11.5px">'
        '<thead><tr style="border-bottom:1px solid var(--mh-outline-variant)">'
        '<th style="padding:4px 8px;text-align:left">anchor</th>'
        '<th style="padding:4px 8px;text-align:left">hex</th>'
        '<th style="padding:4px 8px;text-align:right">ΔE2000</th>'
        '<th style="padding:4px 8px;text-align:center">ok</th>'
        "</tr></thead><tbody>" + "".join(status_rows) + "</tbody></table></div>"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Colour-vision-deficiency simulation (Machado 2009)</h4>"
        '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;'
        'font-size:11.5px">'
        '<thead><tr style="border-bottom:1px solid var(--mh-outline-variant)">'
        '<th style="padding:4px 8px;text-align:left">cvd</th>'
        '<th style="padding:4px 8px;text-align:left">pair</th>'
        '<th style="padding:4px 8px;text-align:right">sim ΔE2000</th>'
        '<th style="padding:4px 8px;text-align:center">ok</th>'
        "</tr></thead><tbody>" + "".join(cvd_rows) + "</tbody></table></div>"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Harmonic fit (Cohen-Or 2006)</h4>"
        + harmonic_html
        + '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">Decision trace</h4>'
        + trace_html
        + "</div></details>"
    )


def _colour_accessibility_panel_html(role_vars: Optional[dict]) -> str:
    """G1.18 — a collapsed "Colour accessibility" report beside the theme audit.

    Renders the deterministic ``quality.colour_audit`` verdict for the brand's
    resolved ``--mh-*`` role set: the APCA/WCAG summary from ``audit_roles`` plus
    the colourblind-preview swatch strip (``swatches_svg``). Read-only and
    engine-free — it explains, it never changes what renders. Returns "" when no
    usable role set is available.
    """
    if not isinstance(role_vars, dict) or not role_vars:
        return ""
    try:
        from mediahub.quality import colour_audit as _ca

        audit = _ca.audit_roles(role_vars)
        summary = audit.to_summary()
        explain = audit.explain()
        swatch_svg = _ca.swatches_svg(role_vars)
    except Exception:
        return ""

    verdict_ok = bool(summary.get("passes")) and bool(summary.get("cvd_safe"))
    verdict_label = "Passes" if verdict_ok else "Needs attention"
    verdict_var = "--mh-success" if verdict_ok else "--mh-error"
    warnings = summary.get("warnings") or []
    warn_html = ""
    if warnings:
        items = "".join(f"<li>{_h(w)}</li>" for w in warnings[:12])
        warn_html = (
            '<ul style="margin:8px 0 0;padding-left:18px;font-size:12px;'
            f'color:var(--mh-on-surface-variant)">{items}</ul>'
        )
    # swatches_svg is safe-by-construction (validated hex + fixed labels, every
    # text node XML-escaped) so it embeds inline without re-escaping.
    return (
        '<details style="margin-top:14px;border:1px solid var(--mh-outline-variant);'
        'border-radius:8px;padding:0 12px">'
        '<summary style="cursor:pointer;padding:10px 0;font-size:13px;font-weight:600;'
        'color:var(--mh-on-surface)">Colour accessibility '
        f'<span style="color:var({verdict_var});font-weight:600">&middot; {verdict_label}</span>'
        "</summary>"
        '<div style="padding:0 0 12px">'
        f'<p style="font-size:12px;color:var(--mh-on-surface-variant);'
        f'margin:0 0 10px;line-height:1.5">{_h(explain)}</p>'
        f"{warn_html}"
        f'<div style="overflow-x:auto;margin-top:12px">{swatch_svg}</div>'
        "</div></details>"
    )


def _theme_repair_callout_html(theme_json: Optional[dict]) -> str:
    """Phase 1.6 Stage H3 — render the non-blocking warning callout
    when the repair loop fired.

    Returns an empty string when no callout is warranted (palette
    didn't need repair, or theme JSON is missing).
    """
    text = _repair_summary_text(theme_json)
    if not text:
        return ""
    safe_text = str(_h(text))
    return (
        f'<div class="mh-theme-warning" role="status" '
        f'style="margin:14px 0 0;padding:12px 16px;'
        f"border-radius:6px;border:1px solid var(--mh-warning);"
        f"background:rgba(255,180,84,0.10);font-size:13px;"
        f'color:var(--mh-on-surface)">'
        f'<strong style="display:block;margin-bottom:4px;'
        f'color:var(--mh-warning)">'
        f"Theme adjusted for accessibility"
        f"</strong>"
        f"{safe_text}"
        f"</div>"
    )


def _adaptive_theme_enabled() -> bool:
    """Phase 1.6 Stage J1 — the cutover safety lever.

    Returns True (the default) when the adaptive theming
    pipeline should inject its inline <style id="mh-theme-seed">
    override into rendered pages. Returns False when the operator
    has set ``MEDIAHUB_ADAPTIVE_THEME=0`` (also accepts
    ``false``/``off``/``no``) — in which case every render falls
    through to the static Stage A cascade as if Stages D-J had
    never shipped.

    The flag is purely a *visible-cascade* control: the on-disk
    theme JSON (Stage G), the audit panel (Stage H2), and the
    repair callout (Stage H3) all keep working regardless,
    because they're independent of the CSS override.
    """
    import os as _os

    value = _os.environ.get("MEDIAHUB_ADAPTIVE_THEME", "")
    return value.strip().lower() not in ("0", "false", "off", "no")


def _default_theme_json() -> Optional[dict]:
    """Phase 1.6 Stage J2 — pre-derived default theme.

    Lazily derives a DerivedTheme from BrandKit.generic_default()'s
    seeds (#0E2A47 navy + #C9A227 gold) the first time it's called,
    then caches the result for the life of the process.

    Returns None on any derivation failure so callers can fall
    back to the static Stage A cascade cleanly. Side-effect:
    Stage G's hook in ensure_derived_palette() writes
    DATA_DIR/themes/default.json on first call, making the
    default theme available to motion / email / static
    renderers exactly like a real profile's theme.

    Cached at module level (not per-call) so the ~50ms first-
    call cost is amortised across the life of the worker.
    """
    return _default_theme_json_cached()


@functools.lru_cache(maxsize=1)
def _default_theme_json_cached() -> Optional[dict]:
    try:
        from mediahub.brand.kit import BrandKit

        kit = BrandKit.generic_default()
        return kit.ensure_derived_palette()
    except Exception:
        return None


def _theme_seed_style_block() -> str:
    """Return the inline <style id="mh-theme-seed"> block carrying
    the active organisation's brand-seed override.

    Phase 1.6 Stage E introduced the per-org override; Stage J
    extended it with a feature-flag rollback (J1) and a generic-
    default fallback for unconfigured deployments (J2).

    Three-tier resolution:
      1. ``MEDIAHUB_ADAPTIVE_THEME=0`` → return "" (Stage J1
         rollback to Stage A cascade)
      2. Active organisation pinned → use profile.brand_kit.
         derived_palette (Stages D-G)
      3. No active organisation → use _default_theme_json()
         (Stage J2 — unconfigured-first-run benefits from the
         pipeline)

    Returns an empty string in case 1 or when the chosen tier
    fails to resolve a valid seed (defence in depth).
    """
    import re as _re

    # Tier 1 — rollback flag
    if not _adaptive_theme_enabled():
        return ""

    # Tier 2 — active profile (the Stage E original behaviour)
    palette = None
    secondary_hex = ""
    accent_hex = ""
    try:
        from flask import current_app

        get_active = getattr(current_app, "active_profile", None)
        if get_active:
            prof = get_active()
            if prof:
                try:
                    from mediahub.brand.palette import effective_palette

                    eff = effective_palette(
                        manual=getattr(prof, "brand_palette_manual", {}) or {},
                        extracted=getattr(prof, "brand_palette_extracted", {}) or {},
                    )
                except Exception:
                    eff = {}
                # Only override the chrome when the org has SOME
                # explicit brand signal. Without this guard, brand-new
                # profiles whose AI capture failed (no LLM key, DNS
                # error, blocked socials) would still drive the seed
                # off ``ClubProfile.brand_primary`` — and that field
                # defaults to ``#A30D2D`` (legacy red), so the user
                # saw a red theme they never picked. We treat any
                # of these as "the user has a brand pinned":
                #   - manual override set (any slot)
                #   - AI-extracted slot set (any slot)
                #   - brand_kit dict has a primary_colour explicitly
                #   - legacy ``brand_primary`` differs from the class
                #     default (someone actively set it)
                bk_dict = dict(getattr(prof, "brand_kit", {}) or {})
                _CLUB_PROFILE_DEFAULT_PRIMARY = "#A30D2D"
                explicit_legacy_primary = (
                    getattr(prof, "brand_primary", "") or ""
                ).strip() not in ("", _CLUB_PROFILE_DEFAULT_PRIMARY)
                has_confirmed_primary = bool(
                    eff.get("primary")
                    or eff.get("secondary")
                    or eff.get("accent")
                    or bk_dict.get("primary_colour")
                    or explicit_legacy_primary
                )
                if has_confirmed_primary:
                    try:
                        kit = prof.get_brand_kit()
                        palette = kit.ensure_derived_palette()
                    except Exception:
                        palette = None
                    secondary_hex = (eff.get("secondary") or "").strip()
                    accent_hex = (eff.get("accent") or "").strip()
    except (RuntimeError, Exception):
        palette = None

    # Tier 3 — generic-default fallback (Stage J2)
    if not isinstance(palette, dict):
        palette = _default_theme_json()

    if not isinstance(palette, dict):
        return ""

    seed_hex = palette.get("seed_hex")
    if not isinstance(seed_hex, str):
        return ""
    if not _re.fullmatch(r"#[0-9A-Fa-f]{6,8}", seed_hex):
        return ""

    overrides = [f"--mh-brand-seed: {seed_hex};"]
    # Re-derive the on-colour (button/label ink) from the LIVE seed so the
    # recoloured chrome stays legible whatever the club's brand lightness.
    # --lane-ink aliases --mh-on-primary, and --mh-primary resolves to the
    # raw seed (brand tone 400) — so without this, a dark brand seed (the
    # signed-out navy default, a maroon/navy club) keeps the static near-
    # black ink and the primary CTA renders dark-on-dark (~1.3:1, a WCAG
    # fail). brand_on_color reuses the deterministic contrast science to
    # pick paper-cream vs paper-black; for the lane-yellow default it
    # returns the existing near-black, so nothing changes there.
    try:
        from mediahub.theming.contrast import brand_on_color as _brand_on_color
    except Exception:
        _brand_on_color = None
    if _brand_on_color is not None:
        overrides.append(f"--mh-on-primary: {_brand_on_color(seed_hex[:7])};")
    # Secondary → tertiary ramp (the "medal gold" slot). Honouring the
    # user's secondary here means a navy+gold org sees navy chrome AND
    # gold medal/accent ribbons instead of the MediaHub default cream.
    if secondary_hex and _re.fullmatch(r"#[0-9A-Fa-f]{6,8}", secondary_hex):
        overrides.append(f"--mh-tertiary-seed: {secondary_hex};")
        # On-tertiary (--medal-ink) must track a custom secondary too, so a
        # dark secondary doesn't break medal/achievement text. The default
        # medal-gold keeps its themed ink (this branch is simply skipped).
        if _brand_on_color is not None:
            overrides.append(f"--mh-on-tertiary: {_brand_on_color(secondary_hex[:7])};")
    # Accent is a third brand colour with no dedicated seed in
    # theme-base.css yet; expose it as a custom property so component
    # code that wants it can opt in via var(--mh-brand-accent).
    if accent_hex and _re.fullmatch(r"#[0-9A-Fa-f]{6,8}", accent_hex):
        overrides.append(f"--mh-brand-accent: {accent_hex};")

    return f'<style id="mh-theme-seed">:root {{ {" ".join(overrides)} }}</style>'


# Self-contained "Create graphic" panel script for pages OTHER than the meet
# review page (which has its own richer createGraphic with motion + add-to-pack).
# U.6 — the branded render/generation loading state (inspired by Lusion). One
# reusable controller, `MH.renderProgress(container, opts)`, shared by every long
# render/generation wait (motion, reels, graphics). It paints a large editorial
# %-numeral (reusing the .display-num motif) over a minimal progress bar.
#
# Honesty: the renders are opaque (a blocking request, or a running/done poll),
# so the percentage is an eased *time estimate* that asymptotes BELOW 100 and
# only snaps to 100 when the real result lands (`complete()`). Where the backend
# does report real progress (variant batches: done/total), the caller feeds it
# via `setProgress` and the bar tracks the actual work. The number is monotonic
# and never claims "done" before the artefact exists.
#
# UI1.26 — every renderProgress wait also spawns a cursor-anchored mirror via
# MH.cursorReadout (ui-kit.js): a small "NN% · phase" chip that follows the
# pointer during the wait and disappears on complete()/stop(). It is opt-out
# (opts.cursor === false) and degrades safely if ui-kit.js hasn't loaded yet.
#
# Defined in <head> (before any body consumer, incl. on-load mhAutoGraphic) and
# kept as a module constant so tests can exercise the controller directly.
