# Inline line-art for empty states (24×24 stroked SVGs, currentColor).
_EMPTY_ART = {
    "inbox": '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"><path d="M22 12h-6l-2 3h-4l-2-3H2"/><path d="M5.45 5.11L2 12v6a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2v-6l-3.45-6.89A2 2 0 0 0 16.76 4H7.24a2 2 0 0 0-1.79 1.11z"/></svg>',
    "search": '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="7"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>',
    "trophy": '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"/><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"/><path d="M4 22h16"/><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"/><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"/><path d="M18 2H6v7a6 6 0 0 0 12 0V2z"/></svg>',
    "alert": '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>',
}


def _empty_state(
    art: str = "inbox",
    headline: str = "Nothing here yet",
    sub: str = "",
    *,
    actions: str = "",
    kind: str = "",
) -> str:
    """Render a polished empty / zero-data state with line-art, a display
    headline, a sentence of guidance, and optional CTA buttons HTML.

    ``art`` is a key into _EMPTY_ART; ``kind="error"`` tints the art red.
    ``headline`` may contain an <em> for an editorial-italic accent.
    """
    art_svg = _EMPTY_ART.get(art, _EMPTY_ART["inbox"])
    kind_cls = " error" if kind == "error" else ""
    sub_html = f'<p class="mh-emptystate-sub">{sub}</p>' if sub else ""
    actions_html = f'<div class="mh-emptystate-actions">{actions}</div>' if actions else ""
    return (
        f'<div class="mh-emptystate{kind_cls}">'
        f'<div class="mh-emptystate-art" aria-hidden="true">{art_svg}</div>'
        f'<h3 class="mh-emptystate-title">{headline}</h3>'
        f"{sub_html}{actions_html}"
        "</div>"
    )


def _recovery_page(
    headline: str = "Not found",
    detail: str = "The thing you were looking for isn't here. It may have been deleted, or the URL might be out of date.",
    primary_cta: tuple[str, str] | None = None,
    secondary_cta: tuple[str, str] | None = None,
    code: int = 404,
    eyebrow: str | None = None,
    lane: str | None = None,
) -> tuple[str, int]:
    """Render a friendly recovery page with an H1 and at least one CTA.

    The interaction audit found that every 404 / dead-end in MediaHub was
    a blank-feeling text line with no escape hatch. This helper builds the
    standard recovery page so users can always see what happened and where
    to go next without using the browser back button.

    ``eyebrow`` lets each call site supply context-appropriate copy
    ("Card", "Chat", "Service status") instead of every recovery page
    wearing the same "Not found" eyebrow regardless of context.
    """
    pcta = primary_cta or ("Back to home", url_for("home"))
    if eyebrow is None:
        # Default eyebrow follows the HTTP code class — error pages
        # used to leak "404 / page not found" into the masthead chrome,
        # which is the only place in the UI that surfaces raw status
        # codes. Now eyebrows read as editorial labels.
        eyebrow = "Not found" if 400 <= code < 500 else "Something went wrong"
    if lane is None:
        lane = str(code)
    sects: list[str] = []
    sects.append(
        f'<section class="mh-hero" data-lane="{_h(lane)}" style="padding-top:var(--sp-9);padding-bottom:var(--sp-8)">'
    )
    sects.append(f'<span class="mh-hero-eyebrow">{_h(eyebrow)}</span>')
    sects.append(f"<h1>{_h(headline)}</h1>")
    sects.append(f'<p class="lede">{_h(detail)}</p>')
    sects.append('<div class="mh-hero-actions">')
    sects.append(f'<a class="mh-cta-primary" href="{pcta[1]}">{_h(pcta[0])} &rarr;</a>')
    if secondary_cta:
        sects.append(
            f'<a class="mh-cta-secondary" href="{secondary_cta[1]}">{_h(secondary_cta[0])}</a>'
        )
    sects.append("</div>")
    sects.append("</section>")
    return _layout(headline, "".join(sects)), code


# --- Honest "AI provider not configured" banner (U.2) -------------------------
#
# MediaHub never substitutes a heuristic when the cloud LLM is absent — it
# surfaces an honest error instead (CLAUDE.md: "Gemini-first, AI required, never
# heuristic-substituted"). This is the *designed* shape of that error, defined
# once so the wording and styling stay identical on every primary-flow surface
# that promises AI output (the review page and both content builders). It used to
# be hand-inlined three times with copy that had already drifted apart.
_AI_UNAVAILABLE_DETAIL_FULL = (
    "Cards show ranker reasoning and grounded source lines only. Captions, "
    "&ldquo;why this card&rdquo; explanations and performance context need a "
    "Gemini or Anthropic key set by the deployment operator."
)
_AI_UNAVAILABLE_DETAIL_PACK = (
    "Captions and &ldquo;why this card&rdquo; explanations need a Gemini or "
    "Anthropic key set by the deployment operator."
)
# Warning glyph from the same line-art set as the toast icons, so the banner
# reads as a designed state rather than a bare strap of text.
_AI_UNAVAILABLE_ICON = (
    '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" '
    'stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" '
    'style="flex-shrink:0;color:var(--warn)">'
    '<path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/>'
    '<line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>'
)


def _ai_unavailable_banner(detail: str = "") -> str:
    """Return the honest "AI provider not configured" banner, or "" when a
    provider IS available — so a call site can drop the result straight into a
    template with no branching of its own.

    ``detail`` overrides the body copy for surfaces that promise a narrower
    slice of AI output (the content builders don't show ranker reasoning).
    """
    try:
        from mediahub.media_ai.llm import is_available as _llm_available  # noqa: PLC0415

        if _llm_available():
            return ""
    except Exception:  # noqa: BLE001 — a provider probe must never block a page
        return ""
    body = detail or _AI_UNAVAILABLE_DETAIL_FULL
    return (
        '<div role="status" class="mh-ai-unavailable" '
        'style="margin-bottom:var(--sp-5);padding:14px 18px;'
        "background:var(--warn-bg);border:1px solid rgba(255,180,84,0.30);"
        "border-left:3px solid var(--warn);border-radius:var(--radius-sm);"
        "font-family:var(--font-body);font-size:13px;color:var(--ink);"
        'display:flex;align-items:center;gap:var(--sp-3);flex-wrap:wrap">'
        f"{_AI_UNAVAILABLE_ICON}"
        '<span class="strap" style="color:var(--warn)">AI provider not configured</span>'
        f'<span style="color:var(--ink-dim)">{body}</span>'
        "</div>"
    )


# --- Parse-uncertainty / flag-for-review surface (U.2) ------------------------
#
# The pipeline never silently guesses: anything it inferred or could not fully
# resolve is recorded as a ParseWarning and shown to the reviewer. The raw codes
# are engine vocabulary ("course_inferred", "pb_enrichment_failed") and mean
# nothing to a committee volunteer, so we map the known ones to plain English and
# split the serious (error-severity) flags out from the routine "we filled this
# in" inferences. Unknown codes fall back to a humanised form of the code so a
# newly-added warning is never shown as raw snake_case.
_PARSE_NOTE_LABELS: dict[str, str] = {
    # Inference — a gap filled from the data we had
    "course_inferred": "Course length inferred",
    "course_mixed": "Mixed course lengths in file",
    "start_date_inferred": "Start date inferred",
    "end_date_inferred": "End date inferred",
    "host_inferred": "Host club inferred",
    "gb_inferred": "Governing body assumed",
    # Ambiguity / partial reads
    "orphan_swim": "Swim with no swimmer record",
    "needs_verification": "Swimmer needs verification",
    "low-confidence-column": "Low-confidence column read",
    "low-overall-confidence": "Low overall read confidence",
    "ocr-used": "Read via OCR",
    "ocr-low-confidence-row": "Low-confidence OCR row",
    "image-needs-ocr": "Image needs OCR to read",
    "no-events-detected": "No event headers detected",
    # Lookups that didn't fully complete (non-fatal)
    "pb_enrichment_failed": "PB history lookup incomplete",
    "pb_audit_failed": "PB audit incomplete",
    # Hard problems (error severity)
    "decode_failed": "File couldn't be decoded",
    "parse_failed": "File couldn't be parsed",
    "no_swims": "No swims found in file",
    "no_results": "No results found",
    "no_club_filter": "No club selected",
}

# F-7 — one source of truth for the PB identity-match status shown on the audit
# table AND the per-swimmer Verify screen, so the two never disagree (the Verify
# screen used to render the raw `needs_verification` / `asa_id_verified` enum
# while the table one screen earlier showed a friendly label). Maps the internal
# `identity.method` enum to (human label, semantic tag class).
_PB_MATCH_STATUS_META: dict[str, tuple[str, str]] = {
    "asa_id_verified": ("Verified", "good"),
    "needs_verification": ("Needs check", "warn"),
    "asa_id_unverified": ("Unverified", ""),
    "no_id": ("Not linked", ""),
    "manual_override": ("Override", "info"),
}


def _pb_match_status_meta(method: str) -> tuple[str, str]:
    """(human label, tag class) for a PB identity-match ``method``.

    Unknown codes humanise the raw code rather than leak snake_case, so a newly
    added status is never shown as ``needs_verification`` to a volunteer.
    """
    m = (method or "").strip()
    if m in _PB_MATCH_STATUS_META:
        return _PB_MATCH_STATUS_META[m]
    return (m.replace("_", " ").capitalize() or "—", "")


# Plain-language trust key for the PB-audit surfaces (F-7): what "confirmed"
# means and what each match status is telling the volunteer. Rendered as a
# collapsible so it explains without crowding the numbers.
_PB_TRUST_KEY_HTML = (
    '<details class="mh-trust-key" style="margin-top:var(--sp-3)">'
    '<summary style="cursor:pointer;font-size:12.5px;color:var(--ink-dim)">'
    "What do these mean?</summary>"
    '<ul style="margin:8px 0 0 18px;font-size:12.5px;color:var(--ink-dim);line-height:1.6">'
    "<li><strong>Confirmed PB</strong> &mdash; the time matched an official record "
    "for that swimmer, so we're confident it's a genuine personal best.</li>"
    "<li><strong>Verified</strong> &mdash; we matched the swimmer to their official "
    "member ID.</li>"
    "<li><strong>Needs check</strong> &mdash; we couldn't confirm the swimmer's ID, "
    "so their PBs aren't confirmed yet. Use the Verify action to set the right ID.</li>"
    "<li><strong>Not linked / Unverified</strong> &mdash; no official member ID on "
    "file to check against; the swim still appears, just not as a confirmed PB.</li>"
    "</ul></details>"
)

# F-10 — plain-language labels for the brand-kit editor, so the form stops
# reading like an internal config file. Lock tokens, the font-pairing catalogue
# (ids mirror graphic_renderer's self-hosted @font-face stacks) and the tone
# options all get human names; a typo can no longer be silently dropped because
# the palette uses colour pickers and font/tone use dropdowns.
_BRAND_LOCK_LABELS: dict[str, str] = {
    "palette": "Lock colours",
    "fonts": "Lock fonts",
    "logo": "Lock logo",
}
_BRAND_FONT_PAIRINGS: tuple[tuple[str, str], ...] = (
    ("", "Club default (inherit)"),
    ("anton-inter", "Anton + Inter — bold, modern"),
    ("bebas-grotesk", "Bebas Neue + Space Grotesk — tall, sporty"),
    ("druk-inter", "Druk + Inter — heavy, editorial"),
    ("bowlby-inter", "Bowlby One + Inter — rounded, playful"),
    ("archivo-inter", "Archivo + Inter — clean, technical"),
    ("oswald-inter", "Oswald + Inter — condensed, classic"),
)


def _humanise_parse_code(code: str) -> str:
    """Plain-English label for a parse-warning code, falling back to a
    title-cased form of the raw code for ones we have not named yet."""
    code = (code or "").strip()
    if not code:
        return "Parse note"
    if code in _PARSE_NOTE_LABELS:
        return _PARSE_NOTE_LABELS[code]
    return code.replace("_", " ").replace("-", " ").strip().capitalize() or "Parse note"


def _parse_notes_card(warnings: list) -> str:
    """Render the "Parse notes" card from a run's parse_warnings, or "" when
    there are none. Error-severity flags lead in a "Needs your attention" block;
    inferences and ambiguities follow. The point of the surface is that we never
    silently guess, so it always names both the human label and the raw code."""
    if not warnings:
        return ""
    errs = [w for w in warnings if isinstance(w, dict) and w.get("severity") == "error"]
    notes = [w for w in warnings if isinstance(w, dict) and w.get("severity") != "error"]
    if not errs and not notes:
        return ""
    _CAP = 12
    err_shown = errs[:_CAP]
    note_shown = notes[: max(0, _CAP - len(err_shown))]
    extra = (len(errs) - len(err_shown)) + (len(notes) - len(note_shown))

    def _row(w: dict) -> str:
        sev = w.get("severity", "")
        cls = {"info": "info", "warn": "warn", "error": "bad"}.get(sev, "")
        label = _humanise_parse_code(w.get("code", ""))
        msg = (w.get("message") or "").strip()
        msg_html = f" &mdash; {_h(msg)}" if msg else ""
        raw = (w.get("code") or "").strip()
        code_html = (
            f'<code style="font-size:10.5px;color:var(--ink-faint);margin-left:6px">{_h(raw)}</code>'
            if raw
            else ""
        )
        return (
            '<li style="margin-bottom:6px">'
            f'<span class="tag {cls}">{_h(sev) or "note"}</span> '
            f"<strong>{_h(label)}</strong>{msg_html}{code_html}</li>"
        )

    sections = ""
    if err_shown:
        sections += (
            '<div style="margin-top:10px"><div class="strap" '
            'style="color:var(--bad);margin-bottom:6px">Needs your attention</div>'
            f'<ul style="margin:0;padding-left:18px">{"".join(_row(w) for w in err_shown)}</ul></div>'
        )
    if note_shown:
        head = (
            '<div class="strap" style="color:var(--ink-muted);margin:10px 0 6px">'
            "Inferred &amp; ambiguous</div>"
            if err_shown
            else ""
        )
        sections += (
            f"{head}"
            f'<ul style="margin:0;padding-left:18px">{"".join(_row(w) for w in note_shown)}</ul>'
        )
    more_html = (
        f'<p class="muted" style="font-size:12px;margin-top:8px">+{extra} more '
        f"note{'s' if extra != 1 else ''} not shown.</p>"
        if extra > 0
        else ""
    )
    return (
        '<div class="card"><h2>Parse notes</h2>'
        '<p class="dim">We never silently guess. Anything we inferred from the source '
        "file, or couldn&rsquo;t fully resolve, is listed here so you can check it "
        "before approving.</p>"
        f"{sections}{more_html}</div>"
    )


def _import_skipped_html(rows) -> str:
    """D-19: render the rows an import couldn't read — line number, name (if any)
    and reason — so the user can fix and re-import, instead of only being told a
    count. Empty string when there's nothing to show."""
    if not isinstance(rows, list) or not rows:
        return ""
    items = []
    for r in rows[:50]:
        if not isinstance(r, dict):
            continue
        rownum = r.get("row")
        name = str(r.get("name") or "").strip()
        reason = str(r.get("reason") or "couldn’t be read").strip()
        loc = f"Row {rownum}" if rownum is not None else "Row"
        who = f" · {_h(name)}" if name else ""
        items.append(f"<li><strong>{_h(loc)}</strong>{who} — {_h(reason)}</li>")
    more = ""
    if len(rows) > 50:
        more = (
            f'<div class="muted" style="font-size:11px;margin-top:4px">'
            f"…and {len(rows) - 50} more.</div>"
        )
    return (
        '<div class="card" style="border-left:2px solid var(--warn);margin-bottom:14px">'
        f'<strong style="color:var(--warn)">{len(rows)} row{"s" if len(rows) != 1 else ""} '
        "couldn&rsquo;t be imported</strong>"
        '<ul style="margin:6px 0 0;padding-left:18px;font-size:13px;color:var(--ink-dim)">'
        + "".join(items)
        + "</ul>"
        + more
        + '<div class="muted" style="font-size:11px;margin-top:6px">'
        "Fix these rows in your sheet and import again.</div>"
        "</div>"
    )


def _erasure_removed_html(report: dict, cascade: Optional[dict] = None) -> str:
    """F-9: the shared "What was removed" summary for a DSR erasure. Both the
    formal Article-12A workflow and the /privacy quick-erase render this, so the
    compliant path no longer gives the worse (raw-JSON) experience."""
    c = cascade or {}
    r = report or {}
    runs_n = len(set(list(c.get("runs_touched", [])) + list(r.get("runs_touched", []))))
    return (
        "<ul>"
        f"<li>{c.get('cards_removed', 0) + r.get('cards_removed', 0)} card(s) and "
        f"{c.get('swims_removed', 0)} result row(s) across {runs_n} run(s)</li>"
        f"<li>{c.get('assets_removed', 0) + len(r.get('visual_files_deleted', []))} rendered file(s)</li>"
        f"<li>{c.get('pb_cache_files', 0) + len(r.get('pb_cache_files_deleted', []))} PB-cache and "
        f"{c.get('research_cache_files', 0)} research-cache file(s)</li>"
        f"<li>{c.get('memory_rows', 0) + r.get('memory_rows_deleted', 0)} caption-memory row(s)</li>"
        f"<li>{c.get('posting_excerpts', 0)} posting-log excerpt(s) blanked</li>"
        f"<li>{len(r.get('media_assets_deleted', []))} media-library photo(s) deleted, "
        f"{len(r.get('media_assets_unlinked', []))} unlinked</li>"
        "<li>Suppression recorded in both consent registries &mdash; the athlete "
        "cannot reappear in new content</li>"
        "</ul>"
    )


def _flash_toast(message: str, kind: str = "success") -> None:
    """Queue a one-shot toast to show on the next rendered page.

    Mirrors the operator-notice pattern (session-stored, popped on render in
    ``_layout``). It feeds the existing ``MH.toast`` framework, so a POST that
    redirects (a run deleted, settings saved) finally gives the user an honest
    success/error confirmation instead of a silent reload. Best-effort: it
    never raises into a request handler, and a missing request context is a
    no-op (so direct ``_layout`` calls in tests stay unaffected)."""
    try:
        from flask import has_request_context  # noqa: PLC0415

        if not has_request_context():
            return
        session["mh_toast"] = {"msg": str(message), "kind": (kind or "success")}
    except Exception:  # noqa: BLE001
        pass


# D-15 — the /organisation analyse actions persist their results immediately;
# the values they overwrite ride the session as a one-shot "Discard this
# analysis" undo (per-session best-effort, consumed by the discard route).
_ORG_ANALYSIS_STASH_KEY = "org_analysis_stash"
# The default Flask session is a ~4 KB cookie: refuse an oversized stash
# rather than risk the browser dropping the whole session cookie.
_ORG_ANALYSIS_STASH_MAX_BYTES = 3000


def _org_analysis_stash_previous(profile_id: str, kind: str, fields: dict) -> None:
    """Stash the pre-analysis values in *fields* as a one-shot undo.

    ``kind`` is ``"brand"`` or ``"voice"`` and decides which preview the
    Discard button renders beside. Best-effort by design: an unserialisable
    or oversized payload drops the stash (so a stale undo can never restore
    the wrong thing) and never raises into the request handler."""
    try:
        payload = {"profile_id": str(profile_id), "kind": kind, "fields": fields}
        if len(json.dumps(payload)) > _ORG_ANALYSIS_STASH_MAX_BYTES:
            session.pop(_ORG_ANALYSIS_STASH_KEY, None)
            return
        session[_ORG_ANALYSIS_STASH_KEY] = payload
    except Exception:  # noqa: BLE001
        session.pop(_ORG_ANALYSIS_STASH_KEY, None)


def _org_analysis_stash_for(profile_id: str) -> dict:
    """The pending analysis-undo stash for *profile_id* ({} when none)."""
    stash = session.get(_ORG_ANALYSIS_STASH_KEY)
    if isinstance(stash, dict) and stash.get("profile_id") == profile_id:
        return stash
    return {}


# --------------------------------------------------------------------------- #
# UI 1.9 — Multi-select + bulk actions (Media library + review queue).
#
# "Pure HTML form multi-select with progressive JS enhancement": the bulk
# endpoints are content-negotiated so the SAME route serves a no-JS HTML form
# POST (redirect + flash) and a fetch() AJAX call (per-item JSON results). The
# two helpers below are the shared request-shape glue; the CSS/JS constants are
# the shared front-end. Each surface keeps its own action semantics (the review
# queue updates workflow state in place; the library removes deleted rows).
# --------------------------------------------------------------------------- #


def _req_wants_json(req) -> bool:
    """True when a request should get a JSON response, not an HTML redirect.

    A fetch() bulk call sends a JSON body (or an explicit Accept/X-Requested-With
    header); a classic ``<form method=post>`` submission sends url-encoded form
    data with the browser's default ``Accept: text/html`` and gets redirected.
    """
    ctype = (req.headers.get("Content-Type", "") or "").split(";")[0].strip()
    if ctype == "application/json":
        return True
    if "application/json" in (req.headers.get("Accept", "") or ""):
        return True
    return req.headers.get("X-Requested-With") == "XMLHttpRequest"


def _bulk_ids_from_request(req, *keys: str) -> list[str]:
    """Collect a de-duplicated, order-preserving id list from a bulk request.

    Accepts either a JSON body (``{"ids": [...]}`` under any of ``keys``) or a
    classic multi-select form (repeated ``<input name=ids>`` fields), so the
    progressive-enhancement fetch() and the no-JS form POST share one route.
    """
    out: list[str] = []
    seen: set[str] = set()

    def _add(value) -> None:
        if value is None:
            return
        s = str(value).strip()
        if s and s not in seen:
            seen.add(s)
            out.append(s)

    body = req.get_json(silent=True) if getattr(req, "is_json", False) else None
    if isinstance(body, dict):
        for k in keys:
            v = body.get(k)
            if isinstance(v, (list, tuple)):
                for item in v:
                    _add(item)
            elif v is not None:
                _add(v)
    # Form fields (no-JS path). getlist() returns [] when the field is absent.
    try:
        for k in keys:
            for item in req.form.getlist(k):
                _add(item)
    except Exception:  # noqa: BLE001 — a malformed body must never 500 the route
        pass
    return out


# Shared styling for the UI 1.9 bulk-action bar + selection checkboxes. Injected
# inline per surface (CSP allows `style-src 'unsafe-inline'`); kept self-contained
# so neither surface has to touch the shared BASE_CSS cascade. The bar is hidden
# only when JS is present AND nothing is selected (`html.mh-js .is-empty`), so a
# no-JS visitor always sees the controls.
