def _record_heartbeat_safe(
    source: str, ok: bool, started_at: float, error: Optional[str] = None
) -> None:
    """Queue a heartbeat write OFF the request path.

    The liveness probe must never block on disk I/O: a synchronous
    SQLite commit here used to stall 10s+ when a concurrent render
    saturated the shared persistent disk, tripping Render's
    health-check timeout and restarting the container mid-render. We
    hand the write to a background thread and return immediately; it
    stays best-effort and lossy (a full queue drops the row).
    """
    try:
        response_ms = (time.monotonic() - started_at) * 1000.0
        _ensure_heartbeat_thread()
        try:
            _HEARTBEAT_QUEUE.put_nowait((bool(ok), str(source), response_ms, error))
        except queue.Full:
            pass
    except Exception:
        pass


def _uptime_tracking_note(*stats: dict) -> str:
    """Explain a clamped uptime window.

    The heartbeat store starts fresh on a new disk / after a deploy that
    didn't carry the DB forward, so a 7d/30d window can be older than the
    data. ``uptime_stats`` then measures uptime over the tracked period
    only (first heartbeat → now) and flags ``window_clamped``. Surface
    that here so an operator understands why the longer windows read
    "tracking since …" rather than mistaking a young store for an outage.
    """
    since = ""
    for s in stats:
        if s.get("has_data") and s.get("window_clamped"):
            ts = s.get("tracking_since")
            if ts:
                since = ts
                break
    if not since:
        return ""
    return (
        '<p class="dim" style="margin-top:10px;font-size:12px">'
        "Uptime is measured from the first recorded heartbeat &mdash; "
        f"tracking since <b>{_h(since[:19])} UTC</b> ({_h(_humanize_when(since))}). "
        "Windows longer than that cover the tracked period only, so a recent "
        "deploy or restart isn&rsquo;t counted as downtime.</p>"
    )


def _notification_link(item: dict) -> str:
    explicit = (item.get("click_url") or "").strip()
    if explicit:
        return explicit
    rid = (item.get("run_id") or "").strip()
    if not rid:
        return ""
    # A finished render lives on the content-pack page; everything else
    # (pack-ready / error) points at the review page for that run.
    endpoint = "content_pack" if item.get("kind") == "render_complete" else "review"
    try:
        return url_for(endpoint, run_id=rid)
    except Exception:
        return ""


