def _render_settings_account_section() -> str:
    """Account — leaving the current org, security, data export, deletion."""
    try:
        email = _auth.current_user_email() or ""
    except Exception:
        email = ""
    who = (
        f'<p class="dim" style="margin-bottom:14px">Signed in as <b>{_h(email)}</b>.</p>'
        if email
        else '<p class="dim" style="margin-bottom:14px">These actions apply to your '
        "MediaHub account.</p>"
    )
    # Leave the currently-active organisation. Relocated here from the nav
    # org-menu so the exit sits beside the other session/account actions.
    # Same gate as the old nav control — offered only to sessions that can
    # actually leave without it being a dead/looping button: the dev
    # operator and anonymous pilot sessions (org pinned in the session, not
    # bound to an account). A single-org member's access is bound to their
    # account, so their exit is Log out, not "leave org". Hidden entirely
    # when no org is pinned, since there is then nothing to leave.
    try:
        _leave_ok = _auth.is_dev_operator() or not email
        _has_active_org = bool((session.get("active_profile_id") or "").strip())
    except Exception:
        _leave_ok, _has_active_org = False, False
    leave_org_card = ""
    if _has_active_org and _leave_ok:
        leave_org_card = (
            '<div class="card" style="padding:16px 18px;margin-bottom:14px">'
            '<h3 style="margin-top:0;font-size:16px">Organisation</h3>'
            '<p class="dim" style="font-size:13px;margin-bottom:10px">Leave the '
            "organisation you&rsquo;re currently in. Your work is kept &mdash; you can "
            "re-enter it from the picker at any time.</p>"
            f'<form method="post" action="{url_for("sign_out")}">'
            '<button class="btn secondary" type="submit">Leave organisation</button>'
            "</form></div>"
        )
    return (
        who + leave_org_card + '<div class="card" style="padding:16px 18px;margin-bottom:14px">'
        '<h3 style="margin-top:0;font-size:16px">Security</h3>'
        '<p class="dim" style="font-size:13px;margin-bottom:10px">Protect your account with '
        "a second factor.</p>"
        f'<a class="btn secondary" href="{url_for("account_2fa")}">Two-factor authentication</a>'
        "</div>"
        '<div class="card" style="padding:16px 18px;margin-bottom:14px">'
        '<h3 style="margin-top:0;font-size:16px">Your data</h3>'
        '<p class="dim" style="font-size:13px;margin-bottom:10px">Download everything this '
        "account holds.</p>"
        f'<a class="btn secondary" href="{url_for("account_export_route")}">Export my data</a>'
        "</div>"
        '<div class="card" style="padding:16px 18px;border-left:2px solid var(--mh-prim-error-500)">'
        '<h3 style="margin-top:0;font-size:16px">Delete account</h3>'
        '<p class="dim" style="font-size:13px;margin-bottom:10px">Permanently delete your '
        "account. This cannot be undone.</p>"
        '<form method="post" action="'
        + url_for("account_delete")
        + '" onsubmit="return confirm(\'Permanently delete your account? This cannot be undone.\')">'
        # E-9: `required` stops an empty submit that used to sail past the
        # confirm and dead-end on a full-page "Password check failed"; the
        # return_to lands a failed check back on THIS page, not /privacy.
        f'<input type="hidden" name="return_to" value="{_h(url_for("settings_section", section="account"))}"/>'
        '<input type="password" name="password" required placeholder="Confirm password" '
        'style="font-size:13px;padding:8px 10px;border:1px solid var(--panel);border-radius:6px;'
        'background:var(--bg);color:var(--ink);margin-right:8px"/>'
        '<button class="btn danger" type="submit" style="font-size:13px">Delete my account</button>'
        "</form></div>"
    )


def _render_settings_status_public_section() -> str:
    """Public status — just "operational" or "down", nothing more.

    The detailed uptime/incident/version view moved to Developer settings.
    """
    # D-28: three honest states, not a green default. If there is no
    # heartbeat, or reading the uptime store throws, we genuinely CANNOT
    # confirm the system is healthy — say so rather than flashing green
    # (which would tell a volunteer "all is well" during an outage the
    # observability layer can't see).
    state = "unknown"
    try:
        from mediahub.observability import uptime as _uptime

        latest = _uptime.latest_heartbeat()
        if latest is not None:
            ts_raw = latest["ts"]
            if ts_raw.endswith("Z"):
                ts_raw = ts_raw[:-1] + "+00:00"
            from datetime import datetime as _dt

            age_s = (datetime.now(timezone.utc) - _dt.fromisoformat(ts_raw)).total_seconds()
            state = "up" if (bool(latest.get("ok")) and age_s <= 1800) else "down"
    except Exception:
        state = "unknown"
    if state == "up":
        return (
            '<div class="card" style="padding:22px 24px">'
            '<div style="display:flex;align-items:center;gap:12px">'
            '<span style="display:inline-block;width:12px;height:12px;border-radius:50%;'
            'background:#2cc97f;box-shadow:0 0 0 4px rgba(44,201,127,0.18)"></span>'
            '<span style="font-size:18px;font-weight:600">Website operational</span></div>'
            '<p class="dim" style="margin:10px 0 0 0;font-size:13px">Everything is running '
            "normally.</p></div>"
        )
    if state == "down":
        return (
            '<div class="card" style="padding:22px 24px;border-left:2px solid var(--mh-prim-error-500)">'
            '<div style="display:flex;align-items:center;gap:12px">'
            '<span style="display:inline-block;width:12px;height:12px;border-radius:50%;'
            'background:#ff5d6c;box-shadow:0 0 0 4px rgba(255,93,108,0.18)"></span>'
            '<span style="font-size:18px;font-weight:600">Website down</span></div>'
            '<p class="dim" style="margin:10px 0 0 0;font-size:13px">The site isn&rsquo;t '
            "responding right now. Your runs, profiles and data are safe. Try again in a "
            "few minutes.</p></div>"
        )
    # unknown — we can't confirm either way.
    return (
        '<div class="card" style="padding:22px 24px;border-left:2px solid var(--warn)">'
        '<div style="display:flex;align-items:center;gap:12px">'
        '<span style="display:inline-block;width:12px;height:12px;border-radius:50%;'
        'background:var(--warn);box-shadow:0 0 0 4px rgba(255,180,84,0.18)"></span>'
        '<span style="font-size:18px;font-weight:600">Status unavailable</span></div>'
        '<p class="dim" style="margin:10px 0 0 0;font-size:13px">We can&rsquo;t confirm the '
        "system&rsquo;s health right now. This usually means the monitoring signal is missing, "
        "not that anything is broken. If a page fails to load, reload it in a minute.</p></div>"
    )


