def _llm_unavailable_banner() -> str:
    """Render a warning banner when no LLM provider is configured.

    Pre-fix, the user could submit a stub form (Sponsor Post, Event
    Preview, Session Update) or start a chat with no LLM key and
    only learn it had failed when the request bounced to an error
    page after a 10-second loader. Surfacing it on the form itself
    sets expectations: the action will fail until the operator
    configures a key. Returns an empty string when AI IS available
    so working deployments aren't nagged.
    """
    try:
        from mediahub.media_ai.llm import is_available as _llm_avail

        if _llm_avail():
            return ""
    except Exception:
        pass
    return (
        '<div role="status" style="margin-bottom:14px;padding:12px 14px;'
        "border:1px solid rgba(255,180,84,0.45);border-radius:8px;"
        "background:rgba(255,180,84,0.08);font-size:13px;"
        'color:var(--ink);line-height:1.5">'
        '<strong style="color:var(--warn)">AI features unavailable.</strong> '
        "No cloud LLM provider is configured on this deployment. "
        "Submitting this form will surface an AI-unavailable error. "
        "Ask your administrator to set "
        '<code style="font-family:var(--font-mono,monospace);font-size:12px">'
        "GEMINI_API_KEY</code> or "
        '<code style="font-family:var(--font-mono,monospace);font-size:12px">'
        "ANTHROPIC_API_KEY</code>."
        "</div>"
    )


def _latest_brief_in_run(run_id: str):
    """Most-recent CreativeBrief JSON in a run's briefs dir, ignoring
    ``content_item_id``. A synthetic ``_stub_<pack_id>`` run holds exactly
    one card's briefs (the composite), so this resolves the composite
    design without coupling to the stub item id."""
    try:
        bdir = RUNS_DIR / run_id / "briefs"
        if not bdir.exists():
            return None
        cands: list[tuple[float, Path]] = []
        for p in bdir.glob("cb_*.json"):
            try:
                mtime = p.stat().st_mtime
            except OSError:
                mtime = 0.0
            cands.append((mtime, p))
        if not cands:
            return None
        cands.sort(key=lambda kv: kv[0], reverse=True)
        return json.loads(cands[0][1].read_text(encoding="utf-8"))
    except Exception:
        return None


def _user_store() -> "_auth.UserStore":
    return _auth.UserStore()


def _runs_this_month() -> int:
    """Count runs created in the current UTC month (free-tier soft limit).

    Scoped to the active organisation when one is pinned so the banner
    reflects the club the user is working in; falls back to a global
    count otherwise. Best-effort — never raises into a page render.
    """
    since = time.strftime("%Y-%m-01T00:00:00", time.gmtime())
    try:
        conn = _db()
        try:
            pid = session.get("active_profile_id")
            if pid:
                row = conn.execute(
                    "SELECT COUNT(*) FROM runs WHERE profile_id = ? AND created_at >= ?",
                    (pid, since),
                ).fetchone()
            else:
                row = conn.execute(
                    "SELECT COUNT(*) FROM runs WHERE created_at >= ?",
                    (since,),
                ).fetchone()
            return int(row[0]) if row else 0
        finally:
            conn.close()
    except Exception:
        return 0


