def _video_safe_look(raw) -> str:
    """Coerce a requested colour look to a known name ('none' otherwise)."""
    from mediahub.video.edl import LOOKS

    name = str(raw or "none").strip().lower()
    return name if name in LOOKS else "none"


def _video_norm_source(src) -> str:
    """Normalise a clip source path for identity comparison (resolve ./..)."""
    try:
        return str(Path(str(src or "")).resolve())
    except Exception:
        return str(src or "")


def _footage_permission_error(asset) -> Optional[dict]:
    """Plain-language block reason when a clip may not be used (M26), or None.

    The MediaAsset.is_usable_for_post() consent gate, surfaced with an
    actionable message per status — footage of minors under a consent hold
    must be blocked everywhere content is made, not just in the photo
    selector.
    """
    name = str(getattr(asset, "filename", "") or "this clip")
    status = str(getattr(asset, "permission_status", "") or "")
    if status == "do_not_use":
        return {
            "error": "footage_blocked",
            "permission_status": status,
            "message": (
                f"“{name}” is marked “do not use”, so it can't "
                "appear in content. Pick another clip — or, if that marking is "
                "wrong, change its permission on the footage tile first."
            ),
        }
    if status == "needs_parental_consent":
        return {
            "error": "footage_blocked",
            "permission_status": status,
            "message": (
                f"“{name}” needs parental consent before it can appear "
                "in content. Record the consent and set its permission to "
                "“approved by club” on the footage tile, or pick "
                "another clip."
            ),
        }
    if str(getattr(asset, "approval_status", "") or "") == "rejected":
        return {
            "error": "footage_blocked",
            "permission_status": status,
            "message": (
                f"“{name}” was rejected in review, so it can't appear "
                "in content. Re-approve it in the media library, or pick "
                "another clip."
            ),
        }
    if not asset.is_usable_for_post():
        return {
            "error": "footage_blocked",
            "permission_status": status,
            "message": (
                f"“{name}” isn't cleared for public use yet — check its "
                "permission on the footage tile."
            ),
        }
    return None


def _project_source_states(proj) -> list[dict]:
    """Each EDL clip source's library permission state, for the approve
    dialog and the export gate (M26). Re-resolved from the store at call
    time, so a permission regression AFTER project creation still shows/
    blocks. Sources that aren't library assets (e.g. stabilised copies
    under the project's render dir) can't be resolved and are skipped."""
    try:
        store = _v8_get_media_store()
        assets = store.list(
            profile_id=getattr(proj, "profile_id", None), asset_type="footage", limit=500
        )
    except Exception:
        return []
    by_path = {str(Path(a.path)): a for a in assets if a.path}
    out: list[dict] = []
    seen: set[str] = set()
    for clip in getattr(proj.edl, "clips", None) or []:
        src = str(Path(clip.source)) if clip.source else ""
        if not src or src in seen:
            continue
        seen.add(src)
        asset = by_path.get(src)
        if asset is None:
            continue
        out.append(
            {
                "asset_id": asset.id,
                "filename": asset.filename,
                "permission_status": asset.permission_status,
                "approval_status": asset.approval_status,
                "usable": asset.is_usable_for_post(),
            }
        )
    return out


def _video_footage_summary(asset) -> dict:
    ad = asset.to_dict() if hasattr(asset, "to_dict") else dict(asset)
    meta = ad.get("media_meta") or {}
    usable = (
        asset.is_usable_for_post()
        if hasattr(asset, "is_usable_for_post")
        else ad.get("permission_status") not in ("do_not_use", "needs_parental_consent")
    )
    return {
        "id": ad.get("id", ""),
        "filename": ad.get("filename", ""),
        "file_url": url_for("api_media_library_file", asset_id=ad.get("id", "")),
        # M27 — poster thumbnail recorded at ingest; "" when extraction
        # wasn't possible (the tile then keeps its <video> behaviour).
        "poster_url": (
            url_for("api_media_library_file", asset_id=ad.get("id", ""), poster=1)
            if meta.get("poster")
            else ""
        ),
        "duration_ms": meta.get("duration_ms", 0),
        "has_audio": meta.get("has_audio", False),
        "orientation": ad.get("orientation", "unknown"),
        "permission_status": ad.get("permission_status", ""),
        # M26 — badge + gate signal for the tiles.
        "usable": bool(usable),
        "uploaded_at": ad.get("uploaded_at", ""),
    }


def _build_run_pack_zip(run_id: str, run_data: dict, profile_id: str):
    """Build the all-formats content-pack ZIP for a run, or None if no
    graphics have been rendered yet. Shared by the ``/pack/<id>/export.zip``
    download route and the public API's ``/api/v1/runs/<id>/export`` so both
    produce byte-identical bundles. Packaging only — never re-renders."""
    from mediahub.graphic_renderer import pack_export as _pack_export

    visuals_dir = RUNS_DIR / run_id / "visuals"
    if not visuals_dir.is_dir() or not any(visuals_dir.iterdir()):
        return None

    run_data = run_data or {}
    meet = run_data.get("meet") or {}
    run_meta = {
        "name": meet.get("name") or run_data.get("profile_display") or "",
        "venue": meet.get("venue") or run_data.get("venue") or "",
        "date": meet.get("date") or meet.get("start_date") or "",
    }

    club: dict = {}
    try:
        from mediahub.brand.store import load_brand

        kit, _tone, _tpl = load_brand(profile_id)
        if kit is not None:
            club = {
                "name": getattr(kit, "display_name", "") or "",
                "primary_colour": getattr(kit, "primary_colour", "") or "",
                "secondary_colour": getattr(kit, "secondary_colour", "") or "",
            }
    except Exception:
        club = {}

    # Real approved captions + ranking from the content pack (the manifest's
    # caption source — the visual sidecar carries none). Keyed by card id,
    # which matches the visual's content_item_id in the normal flow.
    captions: dict[str, str] = {}
    order: list[str] = []
    try:
        from mediahub.workflow.pack import build_content_pack as _bcp

        for _card in _bcp(run_id, profile_id, RUNS_DIR):
            _cid = str(_card.get("_card_id") or "")
            if not _cid:
                continue
            order.append(_cid)
            _active = _card.get("active_caption") or {}
            if isinstance(_active, dict):
                captions[_cid] = " ".join(
                    str(v).strip() for v in _active.values() if isinstance(v, str) and v.strip()
                )
    except Exception:
        captions, order = {}, []

    # Approver-edited alt text + approval status from the workflow sidecar.
    alt_texts: dict[str, str] = {}
    statuses: dict[str, str] = {}
    try:
        _ws = _get_wf_store()
        if _ws is not None:
            for _cid, _st in (_ws.load(run_id) or {}).items():
                if not _st:
                    continue
                _alt = (_st.edited_captions or {}).get("alt_text", "")
                if _alt:
                    alt_texts[_cid] = _alt
                try:
                    statuses[_cid] = _st.status.value
                except Exception:
                    statuses[_cid] = str(getattr(_st, "status", ""))
    except Exception:
        alt_texts, statuses = {}, {}

    result = _pack_export.build_pack_export(
        run_id,
        visuals_dir=visuals_dir,
        run_meta=run_meta,
        club=club,
        captions=captions,
        alt_texts=alt_texts,
        statuses=statuses,
        order=order,
    )
    # Outbound webhook (1.21): a pack was exported. Single chokepoint shared
    # by the download route and the public API. Best-effort.
    try:
        from mediahub import webhooks as _webhooks
        from mediahub.webhooks import events as _wh_events

        _webhooks.emit(
            _wh_events.EVENT_PACK_EXPORTED,
            profile_id,
            _wh_events.pack_exported(profile_id, run_id),
        )
    except Exception:
        pass
    return result.zip_bytes


