def _live_watch_runner(watch, data: bytes, new_swim_keys: list[str]) -> None:
    """Re-run the full pipeline into the watch's fixed run id.

    Idempotent per swim key: card ids derive from swim identity, so a
    re-run upserts the same cards; the workflow sidecar (approvals so
    far) is a separate file and survives. Cards land in QUEUE — the
    autonomy posture is structural, nothing here can publish.
    """
    run = run_pipeline_v4(
        file_bytes=data,
        filename=f"live-{watch.id}.html",
        profile_id=watch.profile_id,
        run_id=watch.run_id or watch.id,
    )
    _persist_run(run, f"Live watch: {watch.label or watch.url}")


def _ensure_live_watch_schedule() -> bool:
    """One global poll task drives every org's due watches (idempotent).

    Returns True when the poll task is present (already existed or was just
    created), False if it could not be ensured — so the caller reports the
    outcome honestly instead of claiming success on a watch that will never
    be polled.
    """
    try:
        from mediahub.workflow.schedule import create_task as _ct
        from mediahub.workflow.schedule import list_tasks as _lt

        if not any(t.task_type == "live_meet_poll" for t in _lt()):
            _ct(
                name="Live meet watch poll (W.7)",
                task_type="live_meet_poll",
                schedule_kind="cron",
                schedule_expr="*/2 * * * *",
            )
        return True
    except Exception:
        log.warning("could not ensure live watch schedule", exc_info=True)
        return False


def _phase_w_after_status_change(
    pid: str, run_id: str, card_id: str, action: str, *, via: str = "web", actor: str = ""
) -> None:
    """Telemetry + records-on-approval, fed by every approval surface.

    Best-effort by design: a telemetry or records failure must never
    block the approval itself. ``actor`` (finding #116) is the machine-
    distinguishable audit label (member email, or ``api-token:<id>`` for a
    public-API/MCP action) recorded alongside ``via`` in the approval
    telemetry so agent and human approvals are separable after the fact.
    """
    # Outbound webhook (1.21): a single chokepoint for BOTH the web route and
    # the public API, so every approval fans out identically. Best-effort.
    if action == "approved":
        try:
            from mediahub import webhooks as _webhooks
            from mediahub.webhooks import events as _wh_events

            _webhooks.emit(
                _wh_events.EVENT_CARD_APPROVED,
                pid,
                _wh_events.card_approved(pid, run_id, card_id, via=via),
            )
        except Exception:
            pass
    card = None
    try:
        data = _load_run(run_id) or {}
        for ra in (data.get("recognition_report") or {}).get("ranked_achievements") or []:
            a = ra.get("achievement") or {}
            if a.get("swim_id") == card_id:
                card = ra
                break
    except Exception:
        card = None
    try:
        from mediahub.observability.approval_telemetry import record_event

        a = (card or {}).get("achievement") or {}
        prof = load_profile(pid) if pid else None
        record_event(
            pid or "",
            run_id,
            card_id,
            action,
            achievement_type=a.get("type", ""),
            post_angle=(card or {}).get("post_angle") or a.get("post_angle", ""),
            tone=(getattr(prof, "tone", "") or "") if prof else "",
            quality_band=str((card or {}).get("quality_band") or ""),
            via=via,
            actor=actor,
        )
    except Exception:
        log.warning("approval telemetry failed", exc_info=True)
    if action == "approved" and card is not None:
        try:
            from mediahub.club_records import apply_approved_card

            a = card.get("achievement") or {}
            if a.get("type") == "club_record" and pid:
                updated = apply_approved_card(pid, dict(card, run_id=run_id))
                if updated:
                    log.info("club record table updated from approved card %s", card_id)
        except Exception:
            log.warning("club record approval hook failed", exc_info=True)


def _certificates_approved_for(run_id: str):
    """(run_data, pid, prof, approved_items) for the certificates export.

    Shared by the synchronous ZIP route and the D-12 background job so
    both build from exactly the same approved, consent-cleared set."""
    from mediahub.content_pack.builder import build_grouped_pack

    data = _load_run(run_id)
    if not data:
        return None, "", None, []
    pid = _run_owner_profile_id(run_id) or ""
    prof = load_profile(pid) if pid else None
    pack = build_grouped_pack(data, pid, RUNS_DIR)
    approved = [
        item
        for group in ("main_feed", "stories", "needs_review")
        for item in (pack.get(group) or [])
        if item.get("wf_status") in ("approved", "posted") and not item.get("consent_blocked")
    ]
    return data, pid, prof, approved


def _write_certificates_zip(
    stream,
    run_id: str,
    data: dict,
    pid: str,
    prof,
    approved: list,
    *,
    print_mode: bool,
    bleed_mm: float,
    crop_marks: bool,
    colour_bar: bool,
    want_cmyk: bool,
    progress=None,
    use_render_slot: bool = False,
) -> None:
    """Render one A4 certificate PDF per approved card into ``stream``
    as a ZIP. ``progress(i, total, swimmer_name)`` (optional) is called
    before each render so the D-12 background job can report
    "Rendering certificate N of M" honestly.

    ``use_render_slot=True`` (the D-12 background job) takes the shared
    render slot per certificate with the queue timeout — like the
    render-all batch worker — so a big meet's build queues politely and
    other renders (thumbnails, motion) interleave between PDFs instead
    of starving for minutes. The synchronous route keeps its historical
    no-slot behaviour."""
    import shutil as _shutil
    import zipfile as _zip

    from mediahub.graphic_renderer.print_export import (
        CmykUnavailable,
        build_certificate_html,
        export_certificate_print_pdf,
        ghostscript_available,
        render_html_to_pdf,
    )

    brand = {
        "primary": getattr(prof, "brand_primary", "#0A2540") if prof else "#0A2540",
        "secondary": getattr(prof, "brand_secondary", "#000000") if prof else "#000000",
    }
    meet = data.get("meet") or {}
    meet_name = meet.get("name") or data.get("file_name") or run_id
    meet_date = str(meet.get("start_date") or "")
    do_cmyk = print_mode and want_cmyk and ghostscript_available()
    cmyk_note = None
    if print_mode and want_cmyk and not do_cmyk:
        cmyk_note = (
            "CMYK conversion was requested but Ghostscript is not installed on "
            "the server, so these PDFs are RGB (the 3mm bleed and crop marks are "
            "intact). Most digital print shops convert RGB to CMYK with their own "
            "press/paper ICC profile, which is more accurate than a generic "
            "conversion would be.\n"
        )
    out_dir = DATA_DIR / "print_exports" / run_id
    out_dir.mkdir(parents=True, exist_ok=True)
    # Concurrent builds (background job + synchronous route) must never
    # zip each other's half-written PDFs — intermediates render into a
    # unique per-build subdirectory, removed when the build finishes.
    # The final ZIP artifact path stays stable.
    build_dir = out_dir / f"build-{uuid.uuid4().hex[:8]}"
    build_dir.mkdir(parents=True, exist_ok=True)
    rgb_fallbacks: list = []  # certs where gs failed mid-run and RGB shipped
    try:
        with _zip.ZipFile(stream, "w", _zip.ZIP_DEFLATED) as zf:
            for i, item in enumerate(approved):
                a = item.get("achievement") or {}
                name = a.get("swimmer_name") or "Swimmer"
                if progress is not None:
                    progress(i, len(approved), name)
                facts = a.get("raw_facts") or {}
                time_str = facts.get("new_time") or facts.get("time") or facts.get("time_str") or ""
                cert_kwargs = dict(
                    swimmer_name=name,
                    event_label=a.get("event", ""),
                    time_str=str(time_str),
                    achievement_headline=a.get("headline", "Achievement"),
                    meet_name=meet_name,
                    meet_date=meet_date,
                    club_name=(prof.display_name if prof else pid or "Our club"),
                    brand=brand,
                    detail_line=a.get("angle_hint", ""),
                )
                safe_name = re.sub(r"[^A-Za-z0-9._-]+", "-", f"{name}-{a.get('event', '')}")
                pdf_path = build_dir / f"cert-{i:02d}.pdf"
                slot = (
                    _render_slot("certificates", run_id, timeout=_RENDER_QUEUE_TIMEOUT)
                    if use_render_slot
                    else contextlib.nullcontext()
                )
                with slot:
                    if print_mode:
                        try:
                            export_certificate_print_pdf(
                                pdf_path,
                                bleed_mm=bleed_mm,
                                crop_marks=crop_marks,
                                colour_bar=colour_bar,
                                cmyk=do_cmyk,
                                **cert_kwargs,
                            )
                        except CmykUnavailable as e:
                            # Ghostscript failed mid-run: the RGB print PDF
                            # (bleed + crop marks intact) is already rendered
                            # and print-ready — ship it and say so, mirroring
                            # print_ready/engine.py.
                            rgb_fallbacks.append(f"{i + 1:02d}-{safe_name}.pdf: {e}")
                    else:
                        render_html_to_pdf(build_certificate_html(**cert_kwargs), pdf_path)
                zf.writestr(f"certificates/{i + 1:02d}-{safe_name}.pdf", pdf_path.read_bytes())
            if rgb_fallbacks:
                cmyk_note = (cmyk_note or "") + (
                    "CMYK conversion failed at run time for these certificates, so "
                    "they are RGB (the bleed and crop marks are intact):\n"
                    + "\n".join(rgb_fallbacks)
                    + "\n"
                )
            if cmyk_note:
                zf.writestr("certificates/CMYK-NOTE.txt", cmyk_note)
    finally:
        _shutil.rmtree(build_dir, ignore_errors=True)


def _doc_clean_detail(exc) -> str:
    """A user-safe one-line failure reason for a document/PDF-tool error.

    The document endpoints operate on server-side temp files, and library
    errors (Pillow/pypdf/Playwright) embed the absolute path — leaking the
    server's filesystem layout and the temp-naming scheme (CLAUDE.md: never
    expose internal paths). Scrub any absolute path to a neutral token while
    keeping the helpful validation text (e.g. page/size limits)."""
    return re.sub(r"(?:/[^\s'\"]+)+", "a file", str(exc))[:200]


def _doc_recent_runs(pid, limit=60):
    out = []
    try:
        conn = _db()
        rows = conn.execute(
            "SELECT id, meet_name, n_achievements FROM runs "
            "WHERE profile_id = ? AND status = 'done' "
            "ORDER BY created_at DESC LIMIT ?",
            (pid, int(limit)),
        ).fetchall()
        for r in rows:
            # Clean a stale HY-TEK banner title (pre-QA-002 runs) at render
            # time so the Sites/Documents source pickers show the real name.
            meet = _clean_stored_meet_title(r["meet_name"]) or "Meet"
            out.append((r["id"], meet, r["n_achievements"] or 0))
    except Exception:
        pass
    return out


def _nl_resolve_images(spec, resolver):
    """Return a copy of ``spec`` with each card's image ``src`` filled from
    its ``card_ref`` via ``resolver(run_id, card_id) -> url`` — so a card
    image is only ever served behind the right access check, never baked in."""
    from mediahub.email_design.models import NewsletterSpec

    data = spec.to_dict()
    for sec in data.get("sections", []):
        for b in sec.get("blocks", []):
            p = b.get("props", {})
            if b.get("kind") == "card" and not p.get("src") and p.get("card_ref"):
                run_id, _, card_id = str(p["card_ref"]).partition("/")
                if run_id and card_id:
                    url = resolver(run_id, card_id) or ""
                    if url:
                        p["src"] = url
    return NewsletterSpec.from_dict(data)


def _nl_card_refs(spec) -> set:
    """The (run_id, card_id) pairs a newsletter spec's card blocks reference —
    the only card images its token/preview may unlock (snapshot scoping)."""
    refs: set = set()
    for sec in spec.to_dict().get("sections", []):
        for b in sec.get("blocks", []):
            p = b.get("props", {})
            if b.get("kind") == "card" and p.get("card_ref"):
                run_id, _, card_id = str(p["card_ref"]).partition("/")
                if run_id and card_id:
                    refs.add((run_id, card_id))
    return refs


def _nl_card_image_path(pid: str, run_id: str, card_id: str):
    """Newsletter-scoped card image: approved + tenant + consent gated, but
    WITHOUT the public wall's own exclusion/recency gates — a newsletter is
    its own surface, so a wall-excluded or older-run card still renders."""
    from mediahub.web import public_wall as _pw

    if str(card_id) not in _pw._approved_card_ids(run_id):
        return None
    return _pw.rendered_card_png(pid, run_id, card_id)


def _nl_unavailable_src(reason: str) -> str:
    """An inline SVG placeholder for the editor preview so an unavailable
    card image is explained, never a silent blank."""
    import base64 as _b64

    svg = (
        '<svg xmlns="http://www.w3.org/2000/svg" width="600" height="120">'
        '<rect width="100%" height="100%" fill="#1a1d21"/>'
        '<text x="50%" y="45%" fill="#9aa3ab" font-family="sans-serif" font-size="16" '
        'text-anchor="middle">Image unavailable</text>'
        f'<text x="50%" y="72%" fill="#6d757d" font-family="sans-serif" font-size="13" '
        f'text-anchor="middle">{reason}</text></svg>'
    )
    return "data:image/svg+xml;base64," + _b64.b64encode(svg.encode("utf-8")).decode("ascii")


def _editorial_ai_record(pid: str, detail: str) -> None:
    """Count one successful AI editorial draft toward the org's quota.
    Best-effort; never affects the response."""
    from mediahub.governance import features as _gov_features, quota as _gov_quota

    org = "" if _auth.is_dev_operator() else (pid or "")
    if not org:
        return
    try:
        _gov_quota.record(org, _gov_features.FEATURE_CAPTION, ok=True, detail=detail)
    except Exception:
        pass


