def _record_operator_notice(subject: str, result: dict) -> None:
    try:
        path = _operator_notices_path()
        path.parent.mkdir(parents=True, exist_ok=True)
        with path.open("a", encoding="utf-8") as fh:
            fh.write(
                json.dumps(
                    {
                        "sent_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
                        "subject": subject,
                        "recipients_sent": result.get("sent", 0),
                        "recipients_failed": result.get("failed", []),
                    },
                    ensure_ascii=False,
                )
                + "\n"
            )
        os.chmod(path, 0o600)
    except OSError:
        log.warning("operator notice ledger write failed", exc_info=True)


def _billing_unconfigured_response():
    """The honest 503 for billing actions when Stripe is unset.

    D-14: a browser navigation (Accept: text/html) gets the styled billing
    error card the graceful pages use — not a bare ``{"error":...}`` JSON
    body dumped into a full-page load. JSON/AJAX callers still get the 503
    machine body.
    """
    if not _req_wants_json(request):
        return (
            _layout("Billing", _billing_error_body(_billing.NOT_CONFIGURED_MESSAGE), active=""),
            503,
        )
    return (
        jsonify(
            {
                "ok": False,
                "error": "billing_not_configured",
                "message": _billing.NOT_CONFIGURED_MESSAGE,
            }
        ),
        503,
    )


def _brand_kit_card_html(prof, kit, default_id: str, can_admin: bool = True) -> str:
    from mediahub.brand.kits import LOCKABLE_TOKENS

    is_default = kit.kit_id == default_id
    role_label = kit.role.replace("_", " ").title()
    default_badge = (
        '<span class="pill" style="background:rgba(34,197,94,0.10);'
        'border-color:rgba(34,197,94,0.30);color:var(--good)">Default</span>'
        if is_default
        else ""
    )
    locks_txt = ", ".join(kit.locks) if kit.locks else "none"
    # Set-default + delete actions (delete hidden for the primary kit).
    actions = ""
    if not is_default:
        actions += (
            f'<form method="post" action="{url_for("api_brand_kit_set_default", kit_id=kit.kit_id)}" '
            'style="display:inline">'
            '<button class="btn secondary" type="submit">Make default</button></form> '
        )
    if kit.role != "primary":
        actions += (
            f'<form method="post" action="{url_for("api_brand_kit_delete", kit_id=kit.kit_id)}" '
            'style="display:inline" onsubmit="return confirm(\'Delete this kit?\')">'
            '<button class="btn secondary" type="submit">Delete</button></form>'
        )
    # Edit form: name, role, palette slots, font pairing, tone, locks.
    lock_checks = ""
    for tok in LOCKABLE_TOKENS:
        checked = "checked" if tok in (kit.locks or []) else ""
        tok_label = _BRAND_LOCK_LABELS.get(tok, tok.replace("_", " ").capitalize())
        lock_checks += (
            f'<label style="margin-right:14px;font-size:12px;color:var(--ink-muted)">'
            f'<input type="checkbox" name="lock" value="{tok}" {checked}/> {_h(tok_label)}</label>'
        )
    # 1.18 per-content-type approver overrides: a stricter rule for the
    # sensitive types the roadmap names. Empty inputs → no override (the
    # type inherits the base rule above).
    _by_type = (kit.approver_rule or {}).get("by_type", {}) or {}

    def _per_type_row(type_key: str, label: str) -> str:
        sub = _by_type.get(type_key, {}) or {}
        n = int(sub.get("min_approvers", 0) or 0)
        owner_checked = "checked" if sub.get("require_owner") else ""
        return (
            '<div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap">'
            f'<span style="font-size:12px;color:var(--ink-muted);min-width:130px">{label}</span>'
            f'<label style="font-size:12px;color:var(--ink-muted)">Min approvers '
            f'<input class="mh-input" type="number" min="0" max="10" '
            f'name="min_approvers__{type_key}" value="{n}" style="max-width:72px" '
            'placeholder="—" /></label>'
            f'<label style="font-size:12px;color:var(--ink-muted)">'
            f'<input type="checkbox" name="require_owner__{type_key}" value="1" '
            f"{owner_checked}/> require an owner</label>"
            "</div>"
        )

    per_type_html = (
        '<div style="font-size:12px;color:var(--ink-muted);margin-top:6px">'
        "Stricter approval for sensitive cards "
        "(leave min approvers at 0 to inherit the rule above):</div>"
        + _per_type_row("safeguarding", "Young / consent-flagged")
        + _per_type_row("sponsor_activation", "Sponsor activation")
    )
    pal = kit.palette or {}
    # F-10 — colour pickers (validated by construction, so "red" or a typo
    # can't be silently dropped) instead of bare "#hex" text inputs. Empty
    # slots fall back to the kit's primary, then a neutral, so the picker
    # always shows something on-brand.
    _pal_default = pal.get("primary") if str(pal.get("primary", "")).startswith("#") else "#5b6b7a"

    def _kit_colour_slot(slot: str, label: str) -> str:
        # A slot the kit never set must NOT be silently persisted from the
        # picker's on-brand fallback: <input type=color> always submits a
        # value, so an unset slot rendered at _pal_default would be read back
        # by _form_palette() as a real user choice and fabricate a colour the
        # club never picked (CLAUDE.md: palettes are evidence-grounded, never
        # invented). Gate each picker behind a "set" checkbox: an unset slot
        # renders its picker DISABLED (disabled inputs are not submitted), so
        # a no-op save round-trips the palette unchanged. Ticking the box
        # enables the picker so the slot can be set; unticking a set slot
        # clears it.
        cur = pal.get(slot, "")
        is_set = str(cur).startswith("#")
        val = cur if is_set else _pal_default
        checked = " checked" if is_set else ""
        disabled = "" if is_set else " disabled"
        return (
            '<div style="display:flex;flex-direction:column;gap:3px;'
            'font-size:11px;color:var(--ink-muted)">'
            f"<span>{label}</span>"
            '<span style="display:flex;align-items:center;gap:6px">'
            f'<input type="checkbox"{checked} aria-label="Set {_h(label.lower())} colour" '
            'onchange="this.nextElementSibling.disabled=!this.checked" '
            'style="cursor:pointer"/>'
            f'<input type="color" name="{slot}" value="{_h(val)}"{disabled} '
            f'aria-label="{_h(label)} colour" '
            'style="width:64px;height:40px;padding:0;border:1px solid var(--border);'
            'border-radius:4px;background:var(--panel);cursor:pointer"/>'
            "</span></div>"
        )

    palette_pickers = "".join(
        _kit_colour_slot(slot, label)
        for slot, label in (
            ("primary", "Primary"),
            ("secondary", "Secondary"),
            ("accent", "Accent"),
            ("fourth", "Fourth"),
        )
    )
    font_options = "".join(
        f'<option value="{_h(fid)}"'
        f"{' selected' if kit.font_pairing == fid else ''}>{_h(flabel)}</option>"
        for fid, flabel in _BRAND_FONT_PAIRINGS
    )
    from mediahub.brand.tone import TONE_META as _TONE_META  # noqa: PLC0415

    tone_options = '<option value="">Club default (inherit)</option>' + "".join(
        f'<option value="{_h(t.value)}"'
        f"{' selected' if kit.tone == t.value else ''}>{_h(meta.get('label', t.value))}</option>"
        for t, meta in _TONE_META.items()
    )
    edit_form = (
        f'<details style="margin-top:10px"><summary style="cursor:pointer;'
        'color:var(--accent);font-size:13px">Edit kit</summary>'
        f'<form method="post" action="{url_for("api_brand_kit_update", kit_id=kit.kit_id)}" '
        'style="display:flex;flex-direction:column;gap:8px;margin-top:10px">'
        f'<input class="mh-input" name="name" value="{_h(kit.name)}" placeholder="Kit name" required />'
        # Sentinel: disabled pickers are not submitted, so an all-slots-unticked
        # save posts ZERO colour fields — indistinguishable from a POST that
        # never carried the palette at all. This marker tells the update route
        # the palette section WAS on the form, so an empty submission honestly
        # clears every slot instead of silently keeping the old palette.
        '<input type="hidden" name="palette_submitted" value="1"/>'
        '<div style="display:flex;gap:12px;flex-wrap:wrap;align-items:flex-end">'
        + palette_pickers
        + "</div>"
        '<label style="font-size:12px;color:var(--ink-muted)">Fonts'
        f'<select class="mh-input" name="font_pairing" style="max-width:320px;display:block">{font_options}</select>'
        "</label>"
        '<label style="font-size:12px;color:var(--ink-muted)">Caption tone'
        f'<select class="mh-input" name="tone" style="max-width:320px;display:block">{tone_options}</select>'
        "</label>"
        '<div style="font-size:12px;color:var(--ink-muted)">Block approval when content strays from these (off-brand guard):</div>'
        f"<div>{lock_checks}</div>"
        '<div style="font-size:12px;color:var(--ink-muted)">Group approval (members-only workspaces):</div>'
        '<div style="display:flex;gap:14px;align-items:center;flex-wrap:wrap">'
        f'<label style="font-size:12px;color:var(--ink-muted)">Min approvers '
        f'<input class="mh-input" type="number" min="1" max="10" name="min_approvers" '
        f'value="{int((kit.approver_rule or {}).get("min_approvers", 1))}" style="max-width:80px" /></label>'
        f'<label style="font-size:12px;color:var(--ink-muted)">'
        f'<input type="checkbox" name="require_owner" value="1" '
        f"{'checked' if (kit.approver_rule or {}).get('require_owner') else ''}/> require an owner</label>"
        "</div>" + per_type_html + '<div><button class="btn" type="submit">Save kit</button></div>'
        "</form>"
        # Palette-file import (Adobe .ase / Color JSON).
        f'<form method="post" action="{url_for("api_brand_kit_palette_import", kit_id=kit.kit_id)}" '
        'enctype="multipart/form-data" style="margin-top:12px;display:flex;gap:8px;'
        'align-items:center;flex-wrap:wrap">'
        '<input type="file" name="palette_file" accept=".ase,.json,application/json" '
        'aria-label="Palette file to import (Adobe .ase or Color JSON)" required />'
        '<button class="btn secondary" type="submit">Import palette file</button>'
        '<span style="font-size:12px;color:var(--ink-muted)">Adobe .ase or Color JSON</span>'
        "</form>"
        # Kit-edit -> re-render sweep (diff preview + approval-gated apply).
        f'<div class="mh-resweep" data-kit="{_h(kit.kit_id)}" '
        f'data-preview="{url_for("api_brand_kit_resweep_preview", kit_id=kit.kit_id)}" '
        f'data-apply="{url_for("api_brand_kit_resweep_apply", kit_id=kit.kit_id)}" '
        'style="margin-top:12px;display:flex;gap:8px;align-items:center;flex-wrap:wrap">'
        '<button type="button" class="btn secondary mh-resweep-preview">Preview re-render impact</button>'
        '<button type="button" class="btn mh-resweep-apply" style="display:none">Apply &amp; re-queue</button>'
        '<span class="mh-resweep-out" style="font-size:12px;color:var(--ink-muted)"></span>'
        "</div></details>"
    )
    return (
        '<div class="mh-panel" style="padding:18px;margin-bottom:14px">'
        '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:6px">'
        f'<h3 style="margin:0">{_h(kit.name)}</h3>'
        f'<span class="pill">{_h(role_label)}</span>{default_badge}</div>'
        f'<div style="margin:10px 0">{_brand_swatch_row(kit.palette)}</div>'
        f'<p style="font-size:12px;color:var(--ink-muted);margin:4px 0">'
        f"Locked: {_h(locks_txt)}"
        + (f" · Font: {_h(kit.font_pairing)}" if kit.font_pairing else "")
        + (f" · Tone: {_h(kit.tone)}" if kit.tone else "")
        + "</p>"
        # Mutating controls (make-default / delete / edit / import / resweep)
        # only for an admin: a bound non-owner gets a read-only card instead
        # of controls that would dead-end in a 404 (the POST routes gate on
        # _brand_can_admin). See brand_home_page.
        + (f'<div style="margin-top:10px">{actions}</div>{edit_form}' if can_admin else "")
        + "</div>"
    )


