def _resolve_run_brand_kit(profile_id: str, run_id: str, run_data=None):
    """Brand kit for run-scoped graphics, in priority order:

    1. The per-run kit (data/brand_kits/<run_id>.json) — written when
       the user confirms a palette in the two-step upload flow, so it
       must keep winning.
    2. The owning organisation's saved brand kit — without this,
       graphics for runs whose profile_id fell back to club_filter
       rendered with a synthetic identity: default navy/gold palette
       and the swimmer's club code title-cased into the footer
       ("Aberdeen Asc") instead of the signed-in club's brand.
    3. The synthetic kit derived from profile_id (legacy fallback —
       keeps pre-multi-tenant runs rendering).
    """
    try:
        kit_path = DATA_DIR / "data" / "brand_kits" / f"{run_id}.json"
        if kit_path.exists() and (json.loads(kit_path.read_text()) or {}):
            return _v8_brand_kit_for(profile_id, run_id=run_id)
    except Exception:
        pass
    owner = ""
    try:
        owner = _run_owner_id(run_id, run_data)
    except Exception:
        owner = ""
    if owner:
        try:
            prof = load_profile(owner)
            if prof is not None:
                bk = prof.get_brand_kit()
                if bk is not None:
                    return bk
        except Exception:
            log.warning("run brand kit: owner profile %s unreadable, using fallback", owner)
    return _v8_brand_kit_for(profile_id, run_id=run_id)


def _autotag_asset_async(asset_id: str, profile_id: str, run_id: Optional[str] = None) -> bool:
    """Vision-tag one freshly-uploaded photo in a background thread.

    Returns True when a tagging thread was started; False when no
    vision provider is configured (the photo stays fully usable —
    "untagged" badge, manual description flow — never a fabricated tag).
    The roster is resolved on the request thread; the provider call runs
    in a daemon thread so the upload response never waits on the model.
    """
    if not asset_id or not _vision_tagging_available():
        return False
    roster = _vision_roster_for(profile_id, run_id)

    def _work() -> None:
        try:
            from mediahub.media_library.describe import describe_photo_vision

            store = _v8_get_media_store()
            asset = store.get(asset_id)
            if asset is None or not asset.path or not os.path.exists(asset.path):
                return
            vision = describe_photo_vision(asset.path, roster=roster)
            _apply_vision_result(store, asset_id, vision)
        except Exception as e:
            from mediahub.media_ai.llm import ClaudeUnavailableError as _CUE

            if isinstance(e, _CUE):
                # Honest: the provider was attempted and failed — the photo
                # simply stays untagged (badge + manual flow), never fabricated.
                log.info("autotag %s: provider unavailable: %s", asset_id[:8], e)
            else:
                log.exception("autotag %s: vision pass failed", asset_id[:8])

    threading.Thread(target=_work, name=f"autotag-{asset_id[:8]}", daemon=True).start()
    return True


def _imagine_persist(result, *, profile_id, prompt="", source_asset=None):
    """Save an ImagineResult as a provenance-stamped MediaAsset, return it."""
    store = _v8_get_media_store()
    op = result.operation
    # Write under DATA_DIR's persistent uploads tree, exactly like the
    # upload route (UPLOADS_DIR), so generated assets land on the same disk.
    import uuid as _uuid

    upload_dir = UPLOADS_DIR / "media_library" / profile_id
    upload_dir.mkdir(parents=True, exist_ok=True)
    path = upload_dir / f"imagine_{op}_{_uuid.uuid4().hex[:12]}.{result.ext}"
    path.write_bytes(result.data)
    # Provenance: embed IPTC DigitalSourceType + write the sidecar manifest.
    try:
        _imagine.stamp_file(path, result, source_asset=source_asset)
    except Exception:  # pragma: no cover - stamping is best-effort
        pass
    w, h, orient = _imagine_dims(result.data)
    from mediahub.media_library.models import MediaAsset

    model = result.model or ""
    asset = MediaAsset(
        id="",
        filename=path.name,
        path=str(path),
        type="ai_generated",
        description_raw=(prompt or result.manifest.get("prompt", "")),
        description_parsed={"imagine": result.manifest},
        profile_id=profile_id,
        width=w,
        height=h,
        orientation=orient,
        permission_status="internal_only",
        approval_status="draft",
        source_attribution=f"Generated with MediaHub ({model})"
        if model
        else "Generated with MediaHub",
        tags=["ai-generated", op],
        safe_for_minors=True,
    )
    return store.save(asset)


