def _v9_load_variation_history(run_id: str, card_id: str) -> dict:
    p = _v9_variation_history_path(run_id, card_id)
    if not p.exists():
        return {"signatures": [], "hooks": []}
    try:
        data = json.loads(p.read_text("utf-8"))
        if not isinstance(data, dict):
            return {"signatures": [], "hooks": []}
        sigs = list(data.get("signatures") or [])
        hooks = list(data.get("hooks") or [])
        return {"signatures": sigs, "hooks": hooks}
    except Exception:
        return {"signatures": [], "hooks": []}


def _v9_load_caption_history(run_id: str, swim_id: str) -> list[str]:
    p = _v9_caption_history_path(run_id, swim_id)
    if not p.exists():
        return []
    try:
        data = json.loads(p.read_text("utf-8"))
        if isinstance(data, dict):
            items = data.get("captions") or []
            return [c for c in items if isinstance(c, str) and c.strip()]
        if isinstance(data, list):
            return [c for c in data if isinstance(c, str) and c.strip()]
    except Exception:
        pass
    return []


def _sponsor_variant_cached(run_id: str, card_id: str, sponsor_name: str) -> Optional[dict]:
    """The last successfully rendered sponsor variant for this card, or
    None when there is nothing usable (never rendered, PNG purged, or the
    rotation now assigns a different sponsor). Only a render that
    produced a visual counts — failures are never cached, so the page
    retries them automatically."""
    path = _sponsor_variant_sidecar(run_id, card_id)
    if path is None or not path.exists():
        return None
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None
    if not isinstance(data, dict):
        return None
    if (data.get("sponsor_name") or "") != sponsor_name:
        return None
    vid = data.get("visual_id") or ""
    png = str(data.get("png_path") or "")
    if not vid or not png or not Path(png).exists():
        return None
    return data


def _demo_run_or_404(run_id: str) -> dict:
    """Demo-run access: the run must be in THIS browser session's demo
    list and stamped to the demo org. Real-org routes can't see demo
    runs; demo routes can't see real runs."""
    from mediahub.web import demo_try as _demo

    if not _demo.demo_enabled():
        abort(404)
    if run_id not in _demo_session_runs():
        abort(404)
    row = None
    try:
        conn = _db()
        try:
            row = conn.execute(
                "SELECT id, status, profile_id, error FROM runs WHERE id = ?", (run_id,)
            ).fetchone()
        finally:
            conn.close()
    except Exception:
        row = None
    if row is None or (row["profile_id"] or "") != _demo.DEMO_PROFILE_ID:
        abort(404)
    return {"status": row["status"], "error": row["error"] or ""}


def _print_card_png(run_id, run_data, card_id, spec, profile_id, brand_kit, *, cached_only=False):
    """Re-lay card_id's approved design at ``spec`` and render a print PNG.

    Returns the PNG ``Path``, or ``None`` when the card has no design yet.
    Mirrors the reformat render path (deterministic transform + the existing
    graphic_renderer), cached under ``runs/<id>/print_art/<key>/``.
    ``cached_only=True`` never renders: it returns the cached PNG if one
    exists for the current design, else ``None`` (the preflight route's
    no-render fast path).
    """
    import hashlib as _hl

    from mediahub.creative_brief.generator import CreativeBrief
    from mediahub.graphic_renderer.render import render_brief
    from mediahub.turn_into import transform_design

    bdict = _latest_brief_for_card(run_id, card_id)
    if not bdict:
        return None
    src = CreativeBrief.from_dict(bdict)
    if src is None:
        return None
    tr = transform_design(source_brief=src, target_format=spec, brand_kit=brand_kit)
    new_brief = tr.brief
    # The source-brief digest keeps the print art honest: a design edit
    # that keeps the layout template still re-renders (never prints the
    # pre-edit artwork from cache).
    key = _hl.sha256(
        f"print|{card_id}|{spec.slug}|{spec.width}x{spec.height}|"
        f"{new_brief.layout_template}|{_brief_cache_sig(bdict)}".encode("utf-8")
    ).hexdigest()[:20]
    out_dir = RUNS_DIR / run_id / "print_art" / key
    cache_png = out_dir / f"{spec.render_name}.png"
    if cache_png.exists():
        return cache_png
    if cached_only:
        return None
    media_assets: list = []
    try:
        if _v8_get_media_store is not None:
            from mediahub.media_library.photo_edit import asset_dicts_for_render

            _ml_store = _v8_get_media_store()
            media_assets = asset_dicts_for_render(_ml_store.list(profile_id=profile_id), _ml_store)
    except Exception:
        media_assets = []
    athlete_path = None
    hero_id = (new_brief.sourced_asset_ids or [None])[0]
    if hero_id:
        for a in media_assets:
            ad = a if isinstance(a, dict) else {}
            if str(ad.get("id")) == str(hero_id):
                athlete_path = ad.get("path") or ad.get("file_path")
                break
    logo_path = None
    bk_logo = getattr(brand_kit, "logo_path", None)
    if bk_logo:
        try:
            if Path(bk_logo).exists():
                logo_path = str(bk_logo)
        except Exception:
            logo_path = None
    out_dir.mkdir(parents=True, exist_ok=True)
    skip_cutout = getattr(new_brief, "photo_treatment", "") == "no-photo" or not athlete_path
    with _render_slot("graphic", card_id, timeout=_RENDER_TRY_TIMEOUT):
        res = render_brief(
            new_brief,
            output_dir=out_dir,
            size=spec.size,
            format_name=spec.render_name,
            athlete_path=(None if skip_cutout else athlete_path),
            logo_path=logo_path,
            brand_kit=brand_kit,
            image_format="png",
        )
    return Path(res.visual.file_path)


def _bulk_items_for_run(run_id: str):
    """One BulkItem per rendered card in a run (a representative still).

    Rejected cards are excluded (E-2)."""
    from mediahub.export_engine.bulk import BulkItem

    visuals = RUNS_DIR / run_id / "visuals"
    items: list = []
    if not visuals.is_dir():
        return items
    rejected = _rejected_card_ids(run_id)
    for sub in sorted(p for p in visuals.iterdir() if p.is_dir()):
        if _visual_dir_card_id(sub, sub.name) in rejected:
            continue
        pick = None
        for cand in ("feed_portrait.png", "story.png", "feed_square.png"):
            if (sub / cand).is_file():
                pick = sub / cand
                break
        if pick is None:
            pngs = sorted(sub.glob("*.png"))
            pick = pngs[0] if pngs else None
        if pick is not None:
            items.append(BulkItem(name=sub.name, source=pick))
    return items


def _assistant_thread_answer(run_id: str, card_id: str, message: str, run_data) -> str:
    """The assistant's plain-text reply to an @assistant comment (1.18).

    Explains or suggests in words, grounded only in the card's verified facts
    (never invents times/names). Honest-errors when no provider is configured
    — the MediaHub AI rule: a clear "not configured" beats a fabricated reply.
    """
    from mediahub.ai_core import ProviderError, ProviderNotConfigured, ask

    facts: dict = {}
    try:
        if card_id:
            facts = _assistant_card_facts(run_data or _load_run(run_id) or {}, card_id)
    except Exception:
        facts = {}
    system = (
        "You are MediaHub's review assistant. A club reviewer has tagged you in a "
        "comment about a piece of content. Reply briefly and concretely (2-4 "
        "sentences): explain a design choice or suggest an improvement in words. "
        "Never invent facts (times, names, places) — use only what you are given."
    )
    user = f"Card facts: {facts}\n\nReviewer's comment: {message}\n\nYour reply:"
    try:
        out = (ask(system, user, max_tokens=300) or "").strip()
        return out or "I don't have anything to add."
    except ProviderNotConfigured:
        return (
            "The AI assistant isn't configured on this deployment, so I can't reply "
            "automatically — a teammate can still help here."
        )
    except ProviderError as e:
        return f"I couldn't reply just now (provider error: {str(e)[:120]})."
    except Exception:
        return "I couldn't reply just now."


def _project_blocked_source(proj) -> Optional[dict]:
    """The first EDL source whose library asset fails the consent gate."""
    try:
        store = _v8_get_media_store()
        assets = store.list(
            profile_id=getattr(proj, "profile_id", None), asset_type="footage", limit=500
        )
    except Exception:
        return None
    by_path = {str(Path(a.path)): a for a in assets if a.path}
    for clip in getattr(proj.edl, "clips", None) or []:
        asset = by_path.get(str(Path(clip.source)) if clip.source else "")
        if asset is None:
            continue
        blocked = _footage_permission_error(asset)
        if blocked:
            return blocked
    return None


def _video_stabilize_edl(edl, project_id: str) -> None:
    """Stabilise each distinct source and repoint the EDL clips at the result.

    Two-pass vidstab per source (cached under the project's render dir, keyed
    by source path), then the clip's ``source`` is repointed at the steadied
    file. Honest-errors when FFmpeg lacks vidstab.
    """
    import hashlib as _hashlib

    from mediahub.video.enhance import is_stabilize_available, stabilize_source

    if not is_stabilize_available():
        from mediahub.video.enhance import VideoEnhanceUnavailable

        raise VideoEnhanceUnavailable(
            "Stabilisation needs an FFmpeg build with vidstab, which isn't "
            "available on this deployment."
        )
    stab_dir = _video_render_dir(project_id) / "stabilized"
    stab_dir.mkdir(parents=True, exist_ok=True)
    mapping: dict[str, str] = {}
    for c in edl.clips:
        if str(stab_dir) in c.source:
            continue  # already stabilised
        if c.source in mapping:
            c.source = mapping[c.source]
            continue
        out = stab_dir / (_hashlib.sha256(c.source.encode("utf-8")).hexdigest()[:16] + ".mp4")
        if not out.exists():
            stabilize_source(c.source, out)
        mapping[c.source] = str(out)
        c.source = str(out)


def _doc_brand_kit(pid):
    if not pid:
        return None
    try:
        return _v8_brand_kit_for(pid)
    except Exception:
        return None


def _nl_embed_card_src(pid: str, run_id: str, card_id: str) -> str:
    """D-18 — a self-contained ``data:`` URI for a card image so a downloaded
    (unpublished) email actually carries its images instead of silently
    dropping them. Falls back to the honest "unavailable" placeholder when
    the card isn't approved/rendered, never a blank."""
    path = _nl_card_image_path(pid, run_id, card_id)
    if not path:
        return _nl_unavailable_src("publish the hosted version to include this image")
    try:
        import base64 as _b64  # noqa: PLC0415
        import mimetypes  # noqa: PLC0415

        raw = Path(path).read_bytes()
        mime = mimetypes.guess_type(path)[0] or "image/png"
        return f"data:{mime};base64," + _b64.b64encode(raw).decode("ascii")
    except Exception:
        return _nl_unavailable_src("image could not be read")


def _api_pack_exporter(profile_id, run_id):
    run_data = _load_run(run_id) or {}
    zb = _build_run_pack_zip(run_id, run_data, profile_id)
    return (zb or b""), f"content-pack-{run_id}-all-formats.zip"


def _intro_mark_seen(pid: Optional[str], slug: str) -> None:
    if not pid or not slug:
        return
    try:
        seen = _intro_seen_slugs(pid)
        if slug in seen:
            return
        seen.add(slug)
        p = _intro_seen_path(pid)
        p.parent.mkdir(parents=True, exist_ok=True)
        # CON2-1 — unique-tmp + os.replace (the _variant_job_save idiom):
        # two concurrent marks must never interleave into a torn sidecar.
        # The reader already fails soft on a corrupt file, but a torn
        # write would silently drop every previously-seen slug.
        tmp = p.with_suffix(f".{uuid.uuid4().hex[:8]}.tmp")
        try:
            tmp.write_text(json.dumps(sorted(seen)), encoding="utf-8")
            os.replace(tmp, p)
        except OSError:
            with contextlib.suppress(OSError):
                tmp.unlink(missing_ok=True)
            raise
    except OSError:
        # A failed sidecar write must never break the intro page.
        log.debug("intro_seen: could not persist %r for %r", slug, pid)


def _v9_save_variation_history(run_id: str, card_id: str, signature: str, hook: str) -> None:
    if not signature:
        return
    p = _v9_variation_history_path(run_id, card_id)
    try:
        p.parent.mkdir(parents=True, exist_ok=True)
        data = _v9_load_variation_history(run_id, card_id)
        sigs = data.get("signatures") or []
        hooks = data.get("hooks") or []
        sigs.append(signature)
        if hook:
            hooks.append(hook)
        # Cap at 12 entries — the AI / picker only ever looks at the
        # most recent 6, so this gives comfortable headroom.
        sigs = sigs[-12:]
        hooks = hooks[-12:]
        p.write_text(json.dumps({"signatures": sigs, "hooks": hooks}), encoding="utf-8")
    except Exception:
        # History is a nice-to-have, not a hard requirement — never
        # surface persistence failures to the user.
        pass


def _v9_save_caption_history(run_id: str, swim_id: str, caption: str) -> None:
    if not caption or not caption.strip():
        return
    p = _v9_caption_history_path(run_id, swim_id)
    try:
        p.parent.mkdir(parents=True, exist_ok=True)
        existing = _v9_load_caption_history(run_id, swim_id)
        existing.append(caption.strip())
        # Dedupe (preserve order) and cap at 10.
        seen: set[str] = set()
        unique: list[str] = []
        for c in existing[-20:]:
            if c not in seen:
                seen.add(c)
                unique.append(c)
        unique = unique[-10:]
        p.write_text(json.dumps({"captions": unique}), encoding="utf-8")
    except Exception:
        pass


def _assistant_thread_reply(ctx, run_id: str, parent) -> None:
    """When @assistant is tagged in a comment, post the assistant's reply as a
    thread reply (1.18). Best-effort: never breaks posting the human comment."""
    try:
        from mediahub.collab import mentions as _m
        from mediahub.collab import threads as _th

        if not _m.mentions_assistant(parent.body):
            return
        text = _assistant_thread_answer(run_id, parent.card_id, parent.body, ctx.get("run_data"))
        _th.add_comment(
            run_id,
            parent.card_id,
            text,
            author_name="MediaHub Assistant",
            author_email="assistant@mediahub.local",
            parent_id=parent.thread_id,
            kind="comment",
        )
    except Exception:
        pass


def _nl_render_html(pid, newsletter_id, spec, *, preview=False, published_token="", embed=False):
    """Render a newsletter to email-safe HTML, resolving card images for the
    right context: authenticated preview route, public token route, or (for a
    downloaded unpublished draft) inline ``data:`` URIs (D-18)."""
    from mediahub.email_design.render import render_email_html

    prof = load_profile(pid)
    if preview:

        def _preview_resolver(r, c):
            from mediahub.web import public_wall as _pw

            # Explain unavailability in the editor instead of a silent blank.
            if str(c) not in _pw._approved_card_ids(r):
                return _nl_unavailable_src("card not approved yet")
            if not _pw.rendered_card_png(pid, r, c):
                return _nl_unavailable_src("consent-blocked, wrong org or not rendered")
            return url_for(
                "newsletter_preview_card", newsletter_id=newsletter_id, run_id=r, card_id=c
            )

        spec = _nl_resolve_images(spec, _preview_resolver)
    elif published_token:
        spec = _nl_resolve_images(
            spec,
            lambda r, c: url_for(
                "newsletter_public_card",
                token=published_token,
                run_id=r,
                card_id=c,
                _external=True,
            ),
        )
    elif embed:
        spec = _nl_resolve_images(spec, lambda r, c: _nl_embed_card_src(pid, r, c))
    return render_email_html(spec, profile=prof)


# ---------------------------------------------------------------------------
# Request-context spine constants (refactor-15, finding #15 stage 2)
#
# Moved out of ``create_app`` so the tenant-resolution helpers below can
# live at module level. All are pure constants or per-call env reads —
# no per-app state.
# ---------------------------------------------------------------------------
# Video footage is far larger than a meet export — a short phone clip easily
# exceeds 50 MB. The footage-upload route gets a raised per-request cap, applied
# in the CSRF guard below *before* the multipart body is parsed (parsing it is
# what enforces the limit). The clip is streamed to disk, not read into RAM, so
# the cap bounds disk per upload. Operator-tunable via MEDIAHUB_VIDEO_UPLOAD_MB.
try:
    _video_upload_max = max(50, min(1024, int(os.environ.get("MEDIAHUB_VIDEO_UPLOAD_MB", "512"))))
except (TypeError, ValueError):
    _video_upload_max = 512
_video_upload_max *= 1024 * 1024

