class _PhotoRejectedError(Exception):
    """An uploaded photo can't be accepted — disallowed file type,
    undecodable bytes, or a HEIC/HEIF this deployment can't convert.

    Carries a stable ``code`` plus the honest user-facing ``message``;
    the caller decides whether to surface a 415 (the upload form) or
    quietly skip the file (the bulk share-target receiver)."""

    def __init__(self, code: str, message: str) -> None:
        super().__init__(message)
        self.code = code
        self.message = message


# ---------------------------------------------------------------------------
# Hoisted closure-free helpers (refactor-15, finding #15 stage 1)
#
# Lifted out of the ``create_app`` closure by the fixpoint hoist engine:
# each function here was verified (symtable) to capture nothing from
# ``create_app``, to have a single binding, constant-only defaults, no
# decorators, and to reference only module-level/builtin names. Behaviour
# is identical; they are now importable and unit-testable in isolation.
# ---------------------------------------------------------------------------


def _complaints_throttled(remote: str) -> bool:
    # Tiny per-IP throttle so the public form can't be flooded:
    # 5 submissions per hour per address.
    import time as _time

    now = _time.time()
    _complaint_recent_posts = _app_state("complaint_recent_posts", dict)
    window = [t for t in _complaint_recent_posts.get(remote, []) if now - t < 3600]
    if window:
        _complaint_recent_posts[remote] = window
    else:
        # Drop empty-window keys so a header-rotating flood can't grow the
        # dict without bound; opportunistically trim if it still balloons.
        _complaint_recent_posts.pop(remote, None)
        if len(_complaint_recent_posts) > 256:
            for k in list(_complaint_recent_posts)[:128]:
                _complaint_recent_posts.pop(k, None)
    if len(window) >= 5:
        return True
    window.append(now)
    _complaint_recent_posts[remote] = window
    return False


def _health_payload():
    checks = {}
    # backend
    checks["backend"] = {"ok": True, "version": APP_VERSION}
    # db
    try:
        c = _db()
        c.execute("SELECT 1").fetchone()
        c.close()
        try:
            _db_display = str(DB_PATH.relative_to(DATA_DIR))
        except ValueError:
            _db_display = str(DB_PATH)
        checks["database"] = {"ok": True, "path": _db_display}
    except Exception as e:
        checks["database"] = {"ok": False, "error": str(e)}
    # writable dirs
    for label, p in [
        ("uploads", UPLOADS_DIR),
        ("runs", RUNS_DIR),
        ("pb_cache", DATA_DIR / ".cache" / "pb_lookup"),
    ]:
        try:
            p.mkdir(parents=True, exist_ok=True)
            test = p / ".write_test"
            test.write_text("ok")
            test.unlink()
            # Display path relative to DATA_DIR when possible (production layout);
            # fall back to absolute path when RUNS_DIR / UPLOADS_DIR live outside
            # DATA_DIR (a valid configuration in local dev and tests).
            try:
                display_path = str(p.relative_to(DATA_DIR))
            except ValueError:
                display_path = str(p)
            checks[label] = {"ok": True, "path": display_path}
        except Exception as e:
            checks[label] = {"ok": False, "error": str(e)}
    # V8.2: profiles UI removed; health check no longer requires any profiles.
    try:
        profs = list_profiles()
        checks["profiles"] = {
            "ok": True,
            "count": len(profs),
            "ids": [p.profile_id for p in profs],
        }
    except Exception as e:
        checks["profiles"] = {"ok": True, "count": 0, "error": str(e)}
    ok_all = all(v.get("ok") for v in checks.values())
    return {
        "ok": ok_all,
        "version": APP_VERSION,
        "ts": datetime.now(timezone.utc).isoformat(),
        "checks": checks,
    }


def _app_icon_png(size: int) -> bytes:
    """Render the MediaHub podium mark as a maskable PNG home-screen icon
    (roadmap 1.22). SVG favicons don't install as a home-screen icon on
    every platform, so a real raster icon makes the installed PWA polished.
    The podium is drawn into the central ~72% safe zone over a full-bleed
    dark background, so a maskable crop (circle / squircle) never clips it.
    Cached per size — the geometry is deterministic."""
    _APP_ICON_CACHE = _app_state("app_icon_cache", dict)
    if size in _APP_ICON_CACHE:
        return _APP_ICON_CACHE[size]
    from PIL import Image, ImageDraw
    import io as _io

    img = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    d = ImageDraw.Draw(img)
    d.rounded_rectangle([0, 0, size - 1, size - 1], radius=int(size * 0.22), fill=(10, 11, 17, 255))
    # The favicon is drawn on a 32-unit grid; scale it into a centred 72% box.
    inner = size * 0.72
    pad = (size - inner) / 2.0
    u = inner / 32.0

    def _bar(x, y, w, h, color):
        d.rounded_rectangle(
            [pad + x * u, pad + y * u, pad + (x + w) * u, pad + (y + h) * u],
            radius=max(1, int(u)),
            fill=color,
        )

    _bar(6, 20, 5, 7, (182, 178, 166, 255))  # third place (silver-grey)
    _bar(13.5, 9, 5, 18, (212, 255, 58, 255))  # winner (lane yellow)
    _bar(21, 14, 5, 13, (244, 213, 141, 255))  # runner-up (medal gold)
    d.line(
        [pad + 4 * u, pad + 28.5 * u, pad + 28 * u, pad + 28.5 * u],
        fill=(212, 255, 58, 255),
        width=max(1, int(1.5 * u)),
    )
    buf = _io.BytesIO()
    img.save(buf, format="PNG")
    out = buf.getvalue()
    _APP_ICON_CACHE[size] = out
    return out


def _render_settings_page() -> str:
    """Render the Settings landing — four headed clusters of heading cards
    (C-19), with the two "Coming soon" placeholders collapsed into a muted
    compact strip at the very bottom (J-10 badges kept)."""
    is_dev = _auth.is_dev_operator()
    grouped: dict[str, str] = {}
    for title, desc, icon_key, href, group in _settings_card_specs(is_dev):
        icon = _SETTINGS_ICONS.get(icon_key, "")
        soon = group == "soon"
        # J-10: the two placeholder tiles carry a visible badge (and, in
        # the strip, no "Open" CTA) so the state reads before the click.
        badge = '<span class="mh-template-soon-badge">Coming soon</span>' if soon else ""
        cta = "" if soon else '<span class="mh-template-cta">Open</span>'
        grouped[group] = grouped.get(group, "") + (
            f'<a href="{href}" class="mh-template mh-glow-border{" mh-template-soon" if soon else ""}">'
            f'<div class="mh-template-icon">{icon}</div>'
            '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:var(--sp-1)">'
            f'<h3 style="margin:0">{_h(title)}</h3>'
            f"{badge}"
            "</div>"
            f"<p>{_h(desc)}</p>"
            f"{cta}"
            "</a>"
        )
    sections = ""
    for key, heading in (
        ("club", "Your club"),
        ("content", "Content & brand"),
        ("account", "Account & billing"),
        ("system", "System"),
    ):
        tiles = grouped.pop(key, "")
        if not tiles:
            continue
        sections += (
            f'<section class="mh-settings-cluster" aria-labelledby="mh-settings-{key}">'
            f'<h2 class="mh-settings-cluster-head" id="mh-settings-{key}">{_h(heading)}</h2>'
            f'<div class="mh-template-grid mh-reveal-group">{tiles}</div>'
            "</section>"
        )
    soon_tiles = grouped.pop("soon", "")
    if soon_tiles:
        sections += (
            '<section class="mh-settings-cluster" aria-labelledby="mh-settings-soon">'
            '<h2 class="mh-settings-cluster-head" id="mh-settings-soon">Coming soon</h2>'
            f'<div class="mh-settings-soon-strip">{soon_tiles}</div>'
            "</section>"
        )
    body = (
        '<section class="mh-hero" data-lane="" style="padding-top:var(--sp-7);padding-bottom:var(--sp-5);margin-bottom:var(--sp-5)">'
        '<span class="mh-hero-eyebrow">Settings</span>'
        "<h1>Settings</h1>"
        '<p class="lede">Your club, content, account and system controls '
        "&mdash; grouped so each one is easy to find.</p>"
        "</section>"
        f"{sections}"
    )
    # C-16 — a deliberate interface-language control (distinct from the org's
    # caption-output language), shown only when more than English ships.
    lang_switcher = _interface_language_switcher_html(compact=False)
    if lang_switcher:
        body += (
            '<div class="card" style="margin-top:var(--sp-5);max-width:420px">'
            '<div class="strap" style="margin-bottom:var(--sp-2)">Interface language</div>'
            '<p class="dim" style="margin-bottom:var(--sp-3);font-size:13px">Changes the '
            "app&rsquo;s own menus and buttons. Your caption-output language is set "
            "separately under Organisation &amp; brand.</p>"
            f"{lang_switcher}"
            "</div>"
        )
    return _layout("Settings", body, active="settings")


