def _render_settings_audio_section(prof: Optional[ClubProfile]) -> str:
    """Audio engine settings — library, voices, lexicon, uploads, consent."""
    from mediahub.audio import list_voices, load_library
    from mediahub.audio.consent import FEATURES, ConsentStore
    from mediahub.audio.voice import OrgLexicon

    pid = _active_profile_id()
    lib = load_library()

    # --- Music & SFX library (with inline preview players) ---
    track_rows = ""
    for t in lib.all():
        mood = ", ".join(t.mood) if t.mood else "—"
        badge = "CC0" if t.licence.spdx == "CC0-1.0" else _h(t.licence.name)
        src = url_for("api_audio_track", track_id=t.id)
        track_rows += (
            '<div class="card" style="padding:12px 14px;display:flex;align-items:center;'
            'gap:12px;flex-wrap:wrap">'
            f'<div style="flex:1;min-width:180px"><strong>{_h(t.title)}</strong>'
            f'<div class="dim" style="font-size:12px">{_h(t.kind)} · {_h(mood)} · '
            f'energy {t.energy} · <span class="tag">{badge}</span></div></div>'
            f'<audio controls preload="none" src="{src}" style="height:34px"></audio>'
            "</div>"
        )
    library_html = (
        '<h2 style="font-size:18px;margin:24px 0 6px">Music &amp; sound effects</h2>'
        # F-3: customer copy, no env-var names — uploading their own tracks is
        # the customer action; the reel-bed default is an operator setting.
        '<p class="dim" style="margin:0 0 12px">MediaHub ships its own licence-clean '
        "(CC0) pool so reels have sound out of the box. Prefer your own music? "
        "Upload your licensed tracks under &ldquo;Upload your own audio&rdquo; below.</p>"
        f'<div style="display:grid;gap:8px">{track_rows}</div>'
    )

    # --- Voice catalogue ---
    voice_rows = ""
    for v in list_voices():
        # F-3: "built-in"/"premium" reads for a customer; "local"/"online" is
        # deployment jargon (and the on-server backend is never "local" in
        # customer copy, per the fonts/cutout naming rule).
        tag = "built-in" if v.local else "premium"
        voice_rows += (
            '<li style="margin-bottom:4px">'
            f"<strong>{_h(v.name or v.id)}</strong> "
            f'<span class="dim">· {_h(v.language)} · {_h(v.provider)} ({tag})'
            f"{(' · ' + _h(v.description)) if v.description else ''}</span></li>"
        )
    voices_html = (
        '<h2 style="font-size:18px;margin:28px 0 6px">Voices</h2>'
        '<p class="dim" style="margin:0 0 8px">Voiceover speaks the approved caption '
        "verbatim — no AI script. The built-in voice is the zero-cost default; Welsh and "
        "other premium voices are available too.</p>"
        f'<ul style="margin:0 0 4px;padding-left:18px">{voice_rows}</ul>'
    )

    # --- Per-org pronunciation lexicon ---
    if pid:
        entries = OrgLexicon(pid).entries()
        rows = ""
        for written, spoken in sorted(entries.items()):
            rows += (
                '<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">'
                f'<code style="flex:1">{_h(written)} → {_h(spoken)}</code>'
                f'<form method="post" action="{url_for("api_audio_lexicon")}" '
                'style="margin:0">'
                '<input type="hidden" name="op" value="remove">'
                f'<input type="hidden" name="written" value="{_h(written)}">'
                '<button class="btn btn-ghost" style="padding:4px 10px">Remove</button>'
                "</form></div>"
            )
        if not rows:
            rows = '<p class="dim" style="margin:0 0 8px">No name overrides yet.</p>'
        lexicon_html = (
            '<h2 style="font-size:18px;margin:28px 0 6px">Name pronunciation</h2>'
            '<p class="dim" style="margin:0 0 12px">Teach MediaHub how your swimmers\' '
            "names are said — once. Every voiceover then gets them right (no AI guessing).</p>"
            f"{rows}"
            f'<form method="post" action="{url_for("api_audio_lexicon")}" '
            'style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px">'
            '<input type="hidden" name="op" value="set">'
            '<input name="written" placeholder="Written (e.g. Saoirse)" required '
            'style="flex:1;min-width:160px;padding:8px">'
            '<input name="spoken" placeholder="Say it (e.g. Seer-sha)" required '
            'style="flex:1;min-width:160px;padding:8px">'
            '<button class="btn btn-primary">Add</button></form>'
        )
    else:
        lexicon_html = (
            '<h2 style="font-size:18px;margin:28px 0 6px">Name pronunciation</h2>'
            '<p class="dim">Choose an organisation to manage its pronunciation lexicon.</p>'
        )

    # --- Upload own audio + browser recorder ---
    if pid:
        _types_hint = ", ".join(sorted(s.lstrip(".").upper() for s in _AUDIO_UPLOAD_SUFFIXES))
        upload_html = (
            '<h2 style="font-size:18px;margin:28px 0 6px">Upload your own audio</h2>'
            '<p class="dim" style="margin:0 0 12px">Add a track you hold the licence for. '
            "We fingerprint it and record your licence attestation in the rights ledger.</p>"
            f'<form method="post" action="{url_for("api_audio_upload")}" '
            'enctype="multipart/form-data" style="display:grid;gap:8px;max-width:560px">'
            '<input type="file" id="mh-audio-file" name="file" accept="audio/*" required>'
            f'<span class="dim" style="font-size:12px">{_types_hint} · up to 25 MB.</span>'
            '<input name="licence_name" placeholder="Licence (e.g. Licensed, CC-BY)" '
            'style="padding:8px">'
            '<input name="attribution" placeholder="Attribution (if required)" '
            'style="padding:8px">'
            '<label style="font-size:13px"><input type="checkbox" name="commercial_ok" '
            'value="1" checked> I confirm this is cleared for commercial club use</label>'
            '<label style="font-size:13px"><input type="checkbox" name="enhance" value="1"> '
            "Clean up (denoise + level) — recommended for recordings</label>"
            '<div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">'
            '<button class="btn btn-primary" type="submit">Upload</button>'
            '<button class="btn btn-ghost" type="button" id="mh-rec-btn">● Record</button>'
            '<span id="mh-rec-status" class="dim" style="font-size:12px"></span>'
            "</div></form>"
        )
    else:
        upload_html = ""

    # --- Your uploaded audio (D-7: list + preview + remove) ---
    uploads_html = ""
    if pid:
        from mediahub.audio import rights as _rights

        up_rows = ""
        for rec in _rights.RightsLedger().list_for_profile(pid):
            fpath = DATA_DIR / "audio_uploads" / pid / Path(rec.filename).name
            if not fpath.is_file():
                continue  # a ledger row whose file is gone (cleaned/removed) — skip
            src = url_for("api_audio_upload_file", asset_id=rec.asset_id)
            lic = _h(rec.licence.name or "operator-supplied")
            when = _h((rec.attested_at or "")[:10])
            del_url = url_for("api_audio_upload_delete", asset_id=rec.asset_id)
            up_rows += (
                '<div class="card" style="padding:12px 14px;display:flex;align-items:center;'
                'gap:12px;flex-wrap:wrap">'
                f'<div style="flex:1;min-width:180px"><strong>{_h(rec.filename)}</strong>'
                f'<div class="dim" style="font-size:12px">{lic}'
                f"{(' · ' + when) if when else ''}</div></div>"
                f'<audio controls preload="none" src="{src}" style="height:34px"></audio>'
                f'<form method="post" action="{del_url}" style="margin:0" '
                "onsubmit=\"return confirm('Remove this uploaded track?')\">"
                '<button class="btn btn-ghost" style="padding:4px 10px">Remove</button>'
                "</form></div>"
            )
        if up_rows:
            uploads_html = (
                '<h2 style="font-size:18px;margin:28px 0 6px">Your uploaded audio</h2>'
                '<p class="dim" style="margin:0 0 12px">Tracks you\'ve added for this '
                "organisation — preview or remove them here.</p>"
                f'<div style="display:grid;gap:8px">{up_rows}</div>'
            )
        else:
            uploads_html = (
                '<h2 style="font-size:18px;margin:28px 0 6px">Your uploaded audio</h2>'
                '<p class="dim" style="margin:0 0 12px">No uploads yet — add a track above '
                "and it'll appear here to preview or remove.</p>"
            )

    # D-7 / D-14 / H-15: confirm or explain the action a form POST just
    # performed. Every code maps to plain-English copy in _AUDIO_STATUS —
    # the volunteer always sees a styled banner (success confirmation or
    # error explanation), never raw exception text or a silent redirect.
    _audio_flash = (request.args.get("status") or "").strip()
    banner_html = ""
    _spec = _AUDIO_STATUS.get(_audio_flash)
    if _spec:
        _ok, _text = _spec
        _colour = "var(--good)" if _ok else "var(--bad)"
        banner_html = (
            f'<div class="card" style="border-left:2px solid {_colour};margin-bottom:14px">'
            f'<p style="margin:0">{_h(_text)}</p></div>'
        )

    # --- Voice consent (cloning / changer; off by default) ---
    if pid:
        store = ConsentStore()
        consent_rows = ""
        for feat in FEATURES:
            on = store.is_enabled(pid, feat)
            state = (
                '<span class="tag" style="background:var(--accent);color:#0b0f17">enabled</span>'
                if on
                else '<span class="tag">off</span>'
            )
            if on:
                btn = (
                    f'<form method="post" action="{url_for("api_audio_voice_consent")}" '
                    'style="margin:0"><input type="hidden" name="action" value="revoke">'
                    f'<input type="hidden" name="feature" value="{_h(feat)}">'
                    '<button class="btn btn-ghost" style="padding:4px 10px">Revoke</button>'
                    "</form>"
                )
            else:
                btn = (
                    f'<form method="post" action="{url_for("api_audio_voice_consent")}" '
                    'style="margin:0;display:flex;gap:6px;flex-wrap:wrap">'
                    '<input type="hidden" name="action" value="grant">'
                    f'<input type="hidden" name="feature" value="{_h(feat)}">'
                    '<input name="voice_owner" placeholder="Voice owner" '
                    'style="padding:4px 8px">'
                    '<input name="consent_ref" placeholder="Consent reference" '
                    'style="padding:4px 8px">'
                    '<button class="btn btn-ghost" style="padding:4px 10px">'
                    "Enable with consent</button></form>"
                )
            label = "Voice cloning" if feat == "clone" else "Voice changer"
            consent_rows += (
                '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;'
                'margin-bottom:8px"><div style="flex:1;min-width:160px">'
                f"<strong>{_h(label)}</strong> {state}</div>{btn}</div>"
            )
        consent_html = (
            '<h2 style="font-size:18px;margin:28px 0 6px">Voice cloning &amp; changer</h2>'
            '<p class="dim" style="margin:0 0 12px">Off by default. Enable only with the '
            "recorded consent of the voice's owner — every grant and revocation is "
            f"audited.</p>{consent_rows}"
        )
    else:
        consent_html = ""

    recorder_js = (
        "<script>(function(){var b=document.getElementById('mh-rec-btn');"
        "if(!b||!navigator.mediaDevices)return;var rec,chunks=[],on=false;"
        "var st=document.getElementById('mh-rec-status');"
        "b.addEventListener('click',function(){if(on){rec&&rec.stop();return;}"
        "navigator.mediaDevices.getUserMedia({audio:true}).then(function(s){"
        "rec=new MediaRecorder(s);chunks=[];rec.ondataavailable=function(e){chunks.push(e.data);};"
        "rec.onstop=function(){var blob=new Blob(chunks,{type:'audio/webm'});"
        "var f=new File([blob],'recording.webm',{type:'audio/webm'});"
        "var dt=new DataTransfer();dt.items.add(f);"
        "document.getElementById('mh-audio-file').files=dt.files;"
        "s.getTracks().forEach(function(t){t.stop();});on=false;b.textContent='● Record';"
        "st.textContent='Recorded — review and Upload.';};rec.start();on=true;"
        "b.textContent='■ Stop';st.textContent='Recording…';}).catch(function(){"
        "st.textContent='Microphone unavailable.';});});})();</script>"
    )

    return (
        '<div style="max-width:760px">'
        + banner_html
        + '<p class="lede" style="margin-top:0">Sound for your videos — music, effects and '
        "voiceover — all rights-clean and explainable.</p>"
        + library_html
        + voices_html
        + lexicon_html
        + upload_html
        + uploads_html
        + consent_html
        + (recorder_js if pid else "")
        + "</div>"
    )


def _card_export_assets(run_id: str, card_id: str, run_data: dict, *, caption_override: str = ""):
    """Resolve one card's postable assets — (slug, caption, png_bytes,
    png_name) — or ``None`` if the card isn't in this run.

    Shared by the per-card ``/download`` route and the F-5 bulk
    "Download content" route so the two never disagree about which caption
    or visual ships. Caption priority (E-3): explicit override → approved
    active-tone caption (same source as the run-level export.zip / public
    API export) → any persisted human edit → the internal headline last.
    """
    rr = (run_data or {}).get("recognition_report") or {}
    ranked = rr.get("ranked_achievements") or []
    # F11: ~n-aware (a duplicate twin exports its own occurrence); a bare
    # swim_id still resolves to the first (byte-identical to the old scan).
    target = _resolve_card_ra(ranked, card_id)
    if target is None:
        for c in (run_data or {}).get("cards") or []:
            # Persisted stub cards serialise their id as ``card_id``.
            if c.get("swim_id") == card_id or c.get("id") == card_id or c.get("card_id") == card_id:
                target = {"achievement": c}
                break
    if target is None:
        return None

    ach = target.get("achievement") or {}
    swimmer = (ach.get("swimmer_name") or "swimmer").strip()
    event = (ach.get("event") or "").strip()
    slug = re.sub(r"[^A-Za-z0-9]+", "-", f"{swimmer} {event}").strip("-").lower() or "card"

    caption = (caption_override or "").strip()
    if not caption:
        try:
            from mediahub.workflow.pack import build_content_pack as _bcp

            for _card in _bcp(run_id, _active_profile_id() or "default", RUNS_DIR):
                if str(_card.get("_card_id") or "") == str(card_id):
                    _active = _card.get("active_caption") or {}
                    if isinstance(_active, dict):
                        caption = " ".join(
                            str(v).strip()
                            for v in _active.values()
                            if isinstance(v, str) and v.strip()
                        ).strip()
                    break
        except Exception:
            caption = ""
    if not caption:
        try:
            _ws = _get_wf_store()
            _st = _ws.load(run_id).get(card_id) if _ws else None
            _edits = (getattr(_st, "edited_captions", None) or {}) if _st else {}
            _parts = [
                _edits[k]
                for k in sorted(_edits)
                if k
                and not str(k).startswith(("insp.", "prev."))
                and k != "alt_text"
                and _edits.get(k)
            ]
            caption = "\n".join(p for p in _parts if p).strip()
        except Exception:
            caption = ""
    if not caption:
        caption = (ach.get("headline") or f"{swimmer} — {event}").strip()

    # Try to locate the rendered PNG for this card. Best-effort:
    # not every card has a generated visual yet.
    png_bytes: Optional[bytes] = None
    png_name = ""
    try:
        visuals = (
            target.get("visuals") or (ach.get("visuals") if isinstance(ach, dict) else None) or []
        )
        for v in visuals:
            fp = v.get("file_path") or v.get("path") or ""
            if fp and Path(fp).exists():
                png_bytes = Path(fp).read_bytes()
                png_name = Path(fp).name
                break
    except Exception:
        png_bytes = None

    return slug, caption, png_bytes, png_name


def _render_library_picker_for_active_profile() -> str:
    """Server-render a multi-select widget showing the active profile's
    media-library assets. Returns "" when there's no active profile or
    no v8 media engine — callers should treat empty as "don't inject".
    """
    if not _v8_ok or _v8_get_media_store is None:
        return ""
    pid = _active_profile_id()
    if not pid:
        return ""
    try:
        store = _v8_get_media_store()
        assets = store.list(profile_id=pid, limit=60)
    except Exception:
        return ""
    if not assets:
        _ml_url = url_for("media_library_page")
        return (
            '<div style="margin:0 0 14px;padding:12px;background:rgba(255,255,255,0.02);'
            'border:1px dashed var(--border);border-radius:6px">'
            '<div style="font-weight:600;margin-bottom:4px">Pick from your library</div>'
            '<p class="muted" style="font-size:12px;margin:0">'
            f"No saved assets yet for this organisation. "
            f'<a href="{_h(_ml_url)}" style="text-decoration:underline">'
            "Open your media library &rarr;</a></p></div>"
        )
    tiles = []
    for a in assets[:60]:
        ad = a.to_dict() if hasattr(a, "to_dict") else dict(a)
        aid = ad.get("id", "")
        if not aid:
            continue
        file_url = url_for("api_media_library_file", asset_id=aid)
        label_bits = []
        for n in ad.get("linked_athlete_names") or []:
            if n:
                label_bits.append(str(n))
                break
        if ad.get("type"):
            label_bits.append(str(ad["type"]))
        label = _h(" · ".join(label_bits) or (ad.get("filename") or "")[:40])
        tiles.append(
            '<label class="lib-pick" style="position:relative;cursor:pointer;'
            "border:1px solid var(--border);border-radius:6px;overflow:hidden;"
            'background:#0a0a0a;display:block">'
            f'<input type="checkbox" name="library_asset_id" value="{_h(aid)}" '
            'style="position:absolute;top:6px;left:6px;z-index:2;cursor:pointer"/>'
            f'<img src="{_h(file_url)}" alt="" loading="lazy" '
            'style="display:block;width:100%;height:90px;object-fit:cover"/>'
            f'<div style="padding:6px 8px;font-size:11px;color:var(--ink-dim);'
            'white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'
            f"{label}</div></label>"
        )
    if not tiles:
        return ""
    _ml_url = url_for("media_library_page")
    grid = "".join(tiles)
    return (
        '<div style="margin:0 0 14px;padding:12px;background:rgba(34,211,238,0.03);'
        'border:1px dashed var(--border);border-radius:6px">'
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">'
        '<div style="font-weight:600">Pick from your library</div>'
        f'<a href="{_h(_ml_url)}" style="font-size:12px;text-decoration:underline;color:var(--ink-muted)">'
        "Manage library &rarr;</a></div>"
        '<p class="muted" style="font-size:11px;margin:0 0 10px 0">'
        "Tick photos already saved to this organisation's library. "
        "Selected photos flow into the visual generator without re-upload.</p>"
        '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(110px,1fr));gap:8px">'
        f"{grid}</div></div>"
    )


def _load_accessible_chat(chat_id):
    """Load a chat only if the active organisation may access it.

    Returns None both when the chat is missing AND when it belongs to a
    different organisation — a foreign chat is indistinguishable from a
    nonexistent one, the same anti-enumeration posture as the run/pack
    guards (_can_access_run / _can_access_pack). Legacy ownerless chats
    stay accessible so historical conversations aren't orphaned.
    """
    from mediahub.free_text_chat.session import load_session, can_access_session

    s = load_session(chat_id)
    if s is None or not can_access_session(s, _active_profile_id()):
        return None
    return s


def _chat_brief_to_pack(s, chat_id, selected_ids):
    """Turn a session's accepted brief into a saved stub-pack.

    Shared by "Accept & generate" (B-6) and the standalone "Generate content
    from this brief" step so both build the pack identically. Returns the
    pack URL with ?autographic=1 so the draft renders its graphic on arrival,
    matching the quick path; None when there's no accepted brief to build.
    """
    from mediahub.club_platform.stub_pack_store import save_pack

    brief = s.accepted_brief
    if not brief:
        return None
    # The chat brief is the propose_brief tool input verbatim (unconstrained
    # schema), so hashtags may arrive as a list, a string, or nothing. Reuse
    # the quick path's normaliser so a stray string isn't iterated
    # character-by-character into per-letter chips at render/export.
    from mediahub.free_text_chat.agent import normalise_hashtags

    hashtags = normalise_hashtags(brief.get("hashtags"))
    # The chat brief is the propose_brief tool input verbatim (unconstrained
    # schema), so headline/body/visual_concept may arrive as a non-string
    # (a list of lines, a nested object, a number). Coerce to str before the
    # caption join — a raw list headline used to raise a TypeError that 500'd
    # accept/generate *and* bricked the chat (the brief was already frozen,
    # so every retry hit the same crash).
    _headline = str(brief.get("headline") or "").strip()
    _body = str(brief.get("body") or "").strip()
    card = {
        "platform": str(brief.get("platform") or "Instagram").strip() or "Instagram",
        "caption": "\n\n".join([p for p in [_headline, _body] if p]).strip(),
        "hashtags": hashtags,
        # D-25: prompt-led chat draft — no fabricated confidence badge.
        "confidence": None,
        "notes": str(brief.get("visual_concept") or "").strip(),
        "status": "queue",
    }
    pack_form_data = {
        "free_text": s.title or "Chat brief",
        "source": "chat",
        "chat_id": chat_id,
    }
    # Resolve library picks the same way _render_stub does — strictly
    # scoped to the active organisation; foreign ids are silently dropped.
    active_pid_for_pack = _active_profile_id() or ""
    # Stamp the active profile id on the pack regardless of whether
    # a library asset was picked. Without this, the renderer can't
    # resolve the BrandKit later (no profile_id → no theme JSON →
    # falls back to MediaHub defaults), which is exactly the
    # "brand colours don't carry through" bug for chat briefs.
    if active_pid_for_pack:
        pack_form_data["profile_id"] = active_pid_for_pack
    if selected_ids and _v8_get_media_store is not None:
        try:
            _ml = _v8_get_media_store()
            resolved = []
            for aid in selected_ids:
                a = _ml.get(aid)
                if not a or a.profile_id != active_pid_for_pack:
                    continue
                resolved.append({"id": a.id, "path": a.path, "filename": a.filename})
            if resolved:
                pack_form_data["library_asset_ids"] = ",".join(r["id"] for r in resolved)
                pack_form_data["library_asset_paths"] = ",".join(r["path"] for r in resolved)
                pack_form_data["attached_photo_path"] = resolved[0]["path"]
                pack_form_data["attached_photo_filename"] = resolved[0]["filename"]
                pack_form_data["profile_id"] = active_pid_for_pack
        except Exception:
            current_app.logger.exception("free-text chat library picker resolve failed")
    saved = save_pack("free_text", pack_form_data, [card], profile_id=_active_profile_id())
    return url_for("stub_pack_view", pack_id=saved["pack_id"]) + "?autographic=1"


def _render_pack_attached_media(rec: dict) -> str:
    """Render thumbnails for the library assets attached to a saved pack.

    Reads ``library_asset_ids`` (comma-separated) from the pack's
    form_data, drops any id that no longer belongs to the active
    organisation, and renders the survivors as a small thumbnail row.
    Returns "" when there's nothing safely visible.
    """
    if not _v8_ok or _v8_get_media_store is None:
        return ""
    form_data = rec.get("form_data") or {}
    raw_ids = form_data.get("library_asset_ids") or ""
    if not raw_ids:
        return ""
    ids = [s.strip() for s in raw_ids.split(",") if s.strip()]
    if not ids:
        return ""
    active_pid = _active_profile_id() or ""
    try:
        store = _v8_get_media_store()
    except Exception:
        return ""
    tiles = []
    for aid in ids:
        try:
            a = store.get(aid)
        except Exception:
            continue
        if not a:
            continue
        if a.profile_id != active_pid and not (a.profile_id or "").startswith("_run_"):
            continue
        file_url = url_for("api_media_library_file", asset_id=a.id)
        label = _h((a.linked_athlete_names[0] if a.linked_athlete_names else a.type) or a.filename)
        tiles.append(
            f'<div style="display:inline-flex;flex-direction:column;align-items:center;'
            f'gap:4px;width:90px">'
            f'<img src="{_h(file_url)}" alt="" loading="lazy" '
            f'style="width:90px;height:90px;object-fit:cover;border-radius:6px;'
            f'border:1px solid var(--border);background:var(--bg)"/>'
            f'<div style="font-size:10px;color:var(--ink-muted);text-align:center;'
            f'width:100%;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'
            f"{label}</div></div>"
        )
    if not tiles:
        return ""
    _ml_url = url_for("media_library_page")
    return (
        '<div class="card" style="margin-bottom:14px;background:rgba(34,211,238,0.03)">'
        '<div style="display:flex;justify-content:space-between;align-items:center;'
        'margin-bottom:10px">'
        '<div style="font-weight:600;font-size:13px">Library assets attached</div>'
        f'<a href="{_h(_ml_url)}" style="font-size:12px;color:var(--ink-muted);'
        'text-decoration:underline">Manage library &rarr;</a></div>'
        f'<div style="display:flex;flex-wrap:wrap;gap:10px">{"".join(tiles)}</div></div>'
    )


def _run_id_for_upload_stamp(raw_run_id) -> Optional[str]:
    """Validate an upload's optional run-context id.

    Only a run the *current session* can access may be stamped onto an
    asset's ``linked_meet_ids`` — otherwise a crafted form post could
    associate photos with another organisation's meet. Invalid or foreign
    ids are dropped (the upload itself still succeeds, just unstamped).
    """
    rid = str(raw_run_id or "").strip()
    if not rid or not re.fullmatch(r"[A-Za-z0-9_.-]+", rid):
        return None
    try:
        run_data = _load_run(rid)
        if run_data is None:
            return None
        if not _can_access_run(rid, run_data, _active_profile_id()):
            return None
    except Exception:
        return None
    return rid


def _session_can_access_profile(asset_profile_id: Optional[str]) -> bool:
    """Profile-scoped access guard for media-library files.

    Run-scoped synthetic profiles (``_run_<id>``) are tied to a single run,
    so they inherit that run's privacy semantics by actually resolving the
    run and applying the same guard the run routes use — NOT a blanket
    allow, which would let a signed-in stranger read a run's photos from a
    guessed/leaked asset id (the IDOR class fixed on /api/visual/<vid>).
    Otherwise the asset's profile must match the session's active org pin.
    """
    if not asset_profile_id:
        return False
    if asset_profile_id.startswith("_run_"):
        rid = asset_profile_id[len("_run_") :]
        return _can_access_run(rid, _load_run(rid), _active_profile_id())
    return asset_profile_id == _active_profile_id()


def _assemble_card_motion_inputs(run_id: str, card_id: str):
    """Shared validation + payload assembly for the per-card motion routes.

    Returns ``(inputs_dict, None)`` on success or ``(None, (response,
    status))`` — the same contract as ``_assemble_reel_inputs`` — so the
    sync route and the M32 async job route stay behaviourally identical.
    """
    from mediahub.visual import motion as _motion

    fmt = (request.args.get("format") or _motion.DEFAULT_MOTION_FORMAT).strip().lower()
    if fmt not in _motion.MOTION_FORMATS:
        return None, (
            jsonify(
                {
                    "error": "bad_format",
                    "detail": f"unknown motion format {fmt!r}",
                    "valid_formats": sorted(_motion.MOTION_FORMATS),
                }
            ),
            400,
        )

    run_data = _load_run(run_id)
    if run_data is None:
        run_dir = RUNS_DIR / run_id
        run_json = run_dir / "run.json"
        if run_json.exists():
            try:
                run_data = json.loads(run_json.read_text())
            except Exception as e:
                # A corrupt run file must not leak its existence (or the raw
                # exception text) to a caller that has not passed the tenant
                # gate below: answer exactly like a missing run. The operator
                # still gets the detail in the server log.
                log.warning("run_load_failed run=%s: %s", run_id, e)
                return None, (jsonify({"error": "run_not_found"}), 404)
        else:
            return None, (jsonify({"error": "run_not_found"}), 404)
    if not _can_access_run(run_id, run_data, _active_profile_id()):
        return None, (jsonify({"error": "run_not_found"}), 404)

    rr = run_data.get("recognition_report") or {}
    ranked = rr.get("ranked_achievements") or []
    # F11: ~n-aware (a duplicate twin resolves to its own occurrence); a bare
    # swim_id still resolves to the first (byte-identical to the old scan).
    target = _resolve_card_ra(ranked, card_id)
    if target is None:
        for c in run_data.get("cards") or []:
            # Persisted stub cards serialise their id as ``card_id``.
            if c.get("swim_id") == card_id or c.get("id") == card_id or c.get("card_id") == card_id:
                target = {"achievement": c}
                break
    if target is None:
        return None, (jsonify({"error": "card_not_found"}), 404)

    # R1.19 — optional per-card audio-mix profile (?mix=voice_lead|balanced|
    # music_forward), a deterministic operator knob folded into the card
    # payload so _card_mix_profile reads it; absent keeps the env/default
    # mix (byte-identical). Junk is an honest 400.
    from mediahub.visual import audio_mux as _audio_mux

    mix_profile = (request.args.get("mix") or "").strip().lower()
    if mix_profile and mix_profile not in _audio_mux.AUDIO_MIX_PROFILES:
        return None, (
            jsonify(
                {
                    "error": "bad_mix",
                    "detail": f"unknown audio mix profile {mix_profile!r}",
                    "valid_mix": sorted(_audio_mux.AUDIO_MIX_PROFILES),
                }
            ),
            400,
        )

    ach = target.get("achievement") or {}
    meet_name = (run_data.get("meet") or {}).get("name") or run_data.get("meet_name", "")
    card_payload = {
        "id": ach.get("swim_id") or card_id,
        "swim_id": ach.get("swim_id") or card_id,
        "achievement": ach,
        "meet_name": meet_name,
    }
    if mix_profile:
        card_payload["audio_mix_profile"] = mix_profile

    profile_id = run_data.get("profile_id") or run_data.get("club_filter") or "_run_" + run_id
    profile_id = re.sub(r"[^a-z0-9_-]", "-", profile_id.lower()).strip("-") or ("_run_" + run_id)
    try:
        brand_kit = _resolve_run_brand_kit(profile_id, run_id) if _v8_ok else None
    except Exception:
        brand_kit = None

    # Honour the same per-card variation seed as the static graphic, so
    # the motion render visually aligns with the still card.
    try:
        from mediahub.creative_brief.generator import auto_variation_seed_for

        variation_seed = auto_variation_seed_for(ach.get("swim_id") or card_id)
    except Exception:
        variation_seed = 1

    out_dir = RUNS_DIR / run_id / "motion"
    out_dir.mkdir(parents=True, exist_ok=True)
    # The story format keeps its historic filename so existing links and
    # cached artifacts stay valid; other cuts get a format suffix.
    out_name = f"{card_id}.mp4" if fmt == "story" else f"{card_id}_{fmt}.mp4"
    out_path = out_dir / out_name

    # Load the most recent Gemini-directed brief for this card so the
    # motion render picks up the layout / typography / background /
    # accent / mood axes the AI director chose for the static card.
    # Falls back silently to variationSeed-only variation when no
    # brief exists (e.g. legacy runs from before the director landed).
    brief_dict = _latest_brief_for_card(run_id, card_id)

    # M36 (UX-7) — the user's persisted Inspector tweaks follow the card
    # into motion exactly as the still create-graphic route honours them:
    # accent via the BrandKit-copy mechanism (+ brief palette, so the
    # APCA-gated roleAccent matches the tweaked still), no-photo via the
    # brief's photo treatment. Untouched cards pass through unchanged, so
    # their motion cache keys stay byte-identical.
    overrides = _inspector_overrides_for_card(run_id, card_id)
    card_payload, brief_dict, brand_kit = _apply_inspector_overrides_to_motion(
        overrides, card_payload, brief_dict, brand_kit
    )

    return (
        {
            "format": fmt,
            "card": card_payload,
            "brand_kit": brand_kit,
            "out_path": out_path,
            "out_name": out_name,
            "variation_seed": variation_seed,
            "brief": brief_dict,
        },
        None,
    )


def _assemble_reel_inputs(run_id: str):
    """Shared validation + payload assembly for the reel routes.

    Returns ``(inputs_dict, None)`` on success or ``(None, (response,
    status))`` so the sync route and the async job route stay
    behaviourally identical.
    """
    from mediahub.visual import motion as _motion

    run_data = _load_run(run_id)
    if run_data is None:
        run_dir = RUNS_DIR / run_id
        run_json = run_dir / "run.json"
        if run_json.exists():
            try:
                run_data = json.loads(run_json.read_text())
            except Exception as e:
                # A corrupt run file must not leak its existence (or the raw
                # exception text) to a caller that has not passed the tenant
                # gate below: answer exactly like a missing run. The operator
                # still gets the detail in the server log.
                log.warning("run_load_failed run=%s: %s", run_id, e)
                return None, (jsonify({"error": "run_not_found"}), 404)
        else:
            return None, (jsonify({"error": "run_not_found"}), 404)
    if not _can_access_run(run_id, run_data, _active_profile_id()):
        return None, (jsonify({"error": "run_not_found"}), 404)

    # M31 (UX-3) — explicit moment selection: ?cards=<id1>,<id2>,… names
    # the exact cards for this reel (validated below; assembled in RANK
    # order regardless of request order; max 5). Absent keeps the classic
    # top-N behaviour byte-identical.
    _cards_arg = (request.args.get("cards") or "").strip()
    selected_ids: list[str] = []
    if _cards_arg:
        seen_sel: set[str] = set()
        for part in _cards_arg.split(","):
            cid = part.strip()
            if cid and cid not in seen_sel:
                seen_sel.add(cid)
                selected_ids.append(cid)
        if not selected_ids or len(selected_ids) > 5:
            return None, (
                jsonify(
                    {
                        "error": "bad_cards",
                        "detail": "pick between 1 and 5 card ids",
                    }
                ),
                400,
            )

    try:
        n = int(request.args.get("n", "3"))
    except (TypeError, ValueError):
        n = 3
    n = max(1, min(5, n))
    if selected_ids:
        n = len(selected_ids)

    fmt = (request.args.get("format") or _motion.DEFAULT_MOTION_FORMAT).strip().lower()
    if fmt not in _motion.MOTION_FORMATS:
        return None, (
            jsonify(
                {
                    "error": "bad_format",
                    "detail": f"unknown motion format {fmt!r}",
                    "valid_formats": sorted(_motion.MOTION_FORMATS),
                }
            ),
            400,
        )

    # R1.19 — optional per-reel audio-mix profile (?mix=voice_lead|balanced|
    # music_forward), a deterministic operator knob like ?format/?n. Folded
    # into every card payload below so _card_mix_profile reads it; absent
    # keeps the env/default mix (byte-identical). Junk is an honest 400.
    from mediahub.visual import audio_mux as _audio_mux

    mix_profile = (request.args.get("mix") or "").strip().lower()
    if mix_profile and mix_profile not in _audio_mux.AUDIO_MIX_PROFILES:
        return None, (
            jsonify(
                {
                    "error": "bad_mix",
                    "detail": f"unknown audio mix profile {mix_profile!r}",
                    "valid_mix": sorted(_audio_mux.AUDIO_MIX_PROFILES),
                }
            ),
            400,
        )

    # R1.13 — optional cover stat-chip config from the POST body. Validated
    # via normalise_reel_stat_config (ValueError on junk ids → honest 400);
    # absent leaves the reel byte-identical.
    _reel_body = request.get_json(silent=True) or {}
    reel_stat_config = _reel_body.get("reel_stat_config")
    if reel_stat_config is not None:
        try:
            _motion.normalise_reel_stat_config(reel_stat_config)
        except (ValueError, TypeError) as e:
            return None, (
                jsonify({"error": "bad_stat_config", "detail": str(e)}),
                400,
            )

    # R1.12 — optional beat-rhythm & duration customisation. Bad numbers are
    # an honest 400 rather than a silently-ignored param; absent params keep
    # the default skeleton (normalise_reel_rhythm returns None).
    rhythm_raw: dict = {}

    def _arg_float(key: str):
        raw = request.args.get(key)
        if raw is None or not str(raw).strip():
            return None
        return float(raw)  # ValueError caught below

    try:
        for key in ("cover", "outro", "beat"):
            val = _arg_float(key)
            if val is not None:
                rhythm_raw[key] = val
        weights_arg = (request.args.get("weights") or "").strip()
        if weights_arg:
            rhythm_raw["weights"] = [float(w) for w in weights_arg.split(",") if w.strip()]
    except (TypeError, ValueError):
        return None, (
            jsonify(
                {
                    "error": "bad_rhythm",
                    "detail": (
                        "cover/outro/beat must be numbers and weights a "
                        "comma-separated list of numbers"
                    ),
                }
            ),
            400,
        )
    rhythm = _motion.normalise_reel_rhythm(rhythm_raw, n)

    rr = run_data.get("recognition_report") or {}
    ranked = rr.get("ranked_achievements") or []
    # ranked_achievements is generally already sorted; sort defensively.
    ranked_sorted = sorted(
        ranked,
        key=lambda r: float(r.get("priority", 0.0) or 0.0),
        reverse=True,
    )

    def _ra_ids(ra: dict) -> set[str]:
        ach = ra.get("achievement") or {}
        return {str(v) for v in (ach.get("swim_id"), ra.get("id")) if v}

    sel_suffix = ""
    if selected_ids:
        known: set[str] = set()
        for ra in ranked_sorted:
            known |= _ra_ids(ra)
        for c in run_data.get("cards") or []:
            known |= {str(v) for v in (c.get("swim_id"), c.get("id")) if v}
        unknown = [cid for cid in selected_ids if cid not in known]
        if unknown:
            return None, (
                jsonify(
                    {
                        "error": "bad_cards",
                        "detail": f"unknown card id(s): {', '.join(unknown[:5])}",
                    }
                ),
                400,
            )
        sel_set = set(selected_ids)
        top = [ra for ra in ranked_sorted if _ra_ids(ra) & sel_set][:5]
        if not top:
            top = [
                {"achievement": c}
                for c in (run_data.get("cards") or [])
                if str(c.get("swim_id") or c.get("id") or "") in sel_set
            ][:5]
        if not top:
            return None, (jsonify({"error": "no_cards_for_reel"}), 404)
        n = len(top)
        # An explicit selection that IS the top-n default keeps the
        # default naming (and therefore the default reel file + cache
        # reuse) — only a genuinely custom pick earns a selection suffix.
        if top == ranked_sorted[:n]:
            sel_suffix = ""
        else:
            ordered_ids: list[str] = []
            for ra in top:
                ids = _ra_ids(ra)
                pick = next((cid for cid in selected_ids if cid in ids), "")
                ordered_ids.append(pick or (sorted(ids)[0] if ids else ""))
            sel_suffix = (
                "_sel"
                + hashlib.sha1(
                    ",".join(ordered_ids).encode("utf-8"), usedforsecurity=False
                ).hexdigest()[:8]
            )
    else:
        top = ranked_sorted[:n]
        if not top:
            # Fall back to the cards array if no recognition report.
            top = [{"achievement": c} for c in (run_data.get("cards") or [])[:n]]
    if not top:
        return None, (jsonify({"error": "no_cards_for_reel"}), 404)

    meet_name = (run_data.get("meet") or {}).get("name") or run_data.get("meet_name", "")
    cards: list[dict] = []
    for ra in top:
        ach = ra.get("achievement") or {}
        card = {
            "id": ach.get("swim_id") or ra.get("id") or "",
            "swim_id": ach.get("swim_id") or "",
            "achievement": ach,
            "meet_name": meet_name,
        }
        # R1.19 — thread the operator's chosen mix into the card payload so
        # _card_mix_profile picks it up; absent leaves the env/default mix.
        if mix_profile:
            card["audio_mix_profile"] = mix_profile
        cards.append(card)

    profile_id = run_data.get("profile_id") or run_data.get("club_filter") or "_run_" + run_id
    profile_id = re.sub(r"[^a-z0-9_-]", "-", profile_id.lower()).strip("-") or ("_run_" + run_id)
    try:
        brand_kit = _resolve_run_brand_kit(profile_id, run_id) if _v8_ok else None
    except Exception:
        brand_kit = None

    # R1.30 — honest sponsor for the reel's outro close: the club's active
    # sponsor (registry first, then the legacy single sponsor_name field),
    # or "" when none is configured. Never fabricated — a club with no
    # sponsor simply gets the follow-the-club close.
    sponsor_name = ""
    next_meet_label = ""
    try:
        prof = load_profile(profile_id)
        if prof is not None:
            from mediahub.club_platform.sponsors import active_sponsors

            actives = active_sponsors(prof)
            if actives:
                sponsor_name = str(actives[0].get("name") or "").strip()
            if not sponsor_name:
                sponsor_name = str(getattr(prof, "sponsor_name", "") or "").strip()
            # R1.30 — honest next-meet label for the outro's "Next up"
            # close, read from the profile the same way Turn-Into does
            # (explicit next_meet dict or a "Next meet:" notes line).
            # "" when none is configured — never fabricated. Sponsor still
            # wins in the outro when both are set (outroCtaFor precedence).
            try:
                from mediahub.turn_into.templates import _next_meet_from_profile

                nm = _next_meet_from_profile(prof)
            except Exception:
                nm = None
            if nm and nm.get("name"):
                next_meet_label = " · ".join(
                    part
                    for part in (
                        str(nm.get("name") or "").strip(),
                        str(nm.get("date") or "").strip(),
                    )
                    if part
                )
    except Exception:
        sponsor_name = ""
        next_meet_label = ""

    out_dir = RUNS_DIR / run_id / "motion"
    out_dir.mkdir(parents=True, exist_ok=True)
    # 1.24 AI-dub: ?lang= re-voices the reel's verified narration in another
    # language. Only a dubbable, non-English language is honoured; the cut's
    # filename is language-suffixed so a dubbed reel never overwrites the
    # original-language one (and each language caches separately).
    from mediahub.visual import dub as _dub

    _lang = (request.args.get("lang") or "").strip()
    dub_language = ""
    if _lang:
        _lang_base = _lang.split("-", 1)[0].lower()
        if _lang_base == "en":
            # English IS the reel's original narration language — a no-op,
            # not a dub, so it is honoured as the plain English cut.
            dub_language = ""
        elif _dub.is_dubbable(_lang):
            dub_language = _lang
        else:
            # Honest-error rule: an undubbable ?lang= must not silently ship
            # the English cut (mirrors api_card_translate's bad_language).
            return None, (
                jsonify(
                    {
                        "error": "bad_language",
                        "message": "That language can't be dubbed on this deployment.",
                    }
                ),
                400,
            )
    _lang_suffix = f"_{dub_language.split('-', 1)[0]}" if dub_language else ""
    # One canonical naming shared by the single, job and batch routes (and
    # matched by the reel-file route): a custom M31 selection earns a
    # deterministic ``_sel<hash8>`` marker so it never clobbers the
    # default reel's published file, then the language suffix rides on
    # the base stem (reel_<n>[_sel…][_<lang>]); story keeps the bare stem
    # and other cuts append the format — exactly reel_format_out_path's
    # shape.
    base_name = f"reel_{n}{sel_suffix}{_lang_suffix}"
    _stem = base_name if fmt == "story" else f"{base_name}_{fmt}"
    out_path = out_dir / f"{_stem}.mp4"

    # Look up the latest brief per card so every beat of the reel
    # carries its own AI-directed variation. Cards without a brief
    # produce a None entry — render_meet_reel handles that.
    # M36 (UX-7) — each card's persisted Inspector overrides ride into
    # the reel exactly as into single-card motion: accent via the
    # brief-palette half of the still's translation (the reel's brand kit
    # is shared across all cards, so the per-card BrandKit copy is
    # deliberately not applied), no-photo via the brief's photo
    # treatment. Untouched cards pass through unchanged, keeping the
    # default reel byte-identical.
    brief_list: list = []
    for idx, c in enumerate(cards):
        cid = c.get("id") or c.get("swim_id") or ""
        brief = _latest_brief_for_card(run_id, cid) if cid else None
        overrides = _inspector_overrides_for_card(run_id, cid) if cid else {}
        card_payload, brief, _ = _apply_inspector_overrides_to_motion(
            overrides, c, brief, None, brand_copy=False
        )
        cards[idx] = card_payload
        brief_list.append(brief)

    return (
        {
            "n": n,
            "format": fmt,
            "cards": cards,
            "brand_kit": brand_kit,
            "out_path": out_path,
            "base_name": base_name,
            "meet_name": meet_name,
            "briefs": brief_list,
            "rhythm": rhythm,
            "sponsor": sponsor_name,
            "next_meet": next_meet_label,
            "dub_language": dub_language,
            "reel_stat_config": reel_stat_config,
            # "" for the default top-n pick; the final rank-ordered id list
            # for a custom M31 selection (threaded into the file URL so the
            # reel-file route re-derives the same _sel suffix).
            "cards_param": ",".join(ordered_ids) if sel_suffix else "",
        },
        None,
    )


def _charts_run_context(run_id: str):
    """Load a run + resolve its brand kit for the charts surface.

    Returns ``(ctx, None)`` or ``(None, (response, status))`` so callers stay
    behaviourally identical (mirrors ``_assemble_reel_inputs``).
    """
    run_data = _load_run(run_id)
    if run_data is None:
        return None, (jsonify({"error": "run_not_found"}), 404)
    if not _can_access_run(run_id, run_data, _active_profile_id()):
        return None, (jsonify({"error": "run_not_found"}), 404)
    raw_pid = run_data.get("profile_id") or run_data.get("club_filter") or ("_run_" + run_id)
    profile_id = re.sub(r"[^a-z0-9_-]", "-", str(raw_pid).lower()).strip("-") or ("_run_" + run_id)
    try:
        brand_kit = _resolve_run_brand_kit(profile_id, run_id) if _v8_ok else None
    except Exception:
        brand_kit = None
    return {"run_data": run_data, "brand_kit": brand_kit, "profile_id": profile_id}, None


def _reel_comments_run(run_id: str):
    """Resolve+access-gate a run for the comment routes.

    Returns ``(run_data, None)`` when the caller may touch this run's
    comments, or ``(None, (response, status))`` to short-circuit. The run
    must exist on disk — we never pin a marker to a phantom run id.
    """
    run_data = _load_run(run_id)
    if run_data is None:
        alt = RUNS_DIR / run_id / "run.json"
        if alt.exists():
            try:
                run_data = json.loads(alt.read_text())
            except Exception:
                run_data = None
    if run_data is None or not _can_access_run(run_id, run_data, _active_profile_id()):
        return None, (jsonify({"error": "run_not_found"}), 404)
    return run_data, None


def _collab_run_ctx(run_id: str):
    """Resolve+access-gate a run for the collab routes.

    Returns ``(ctx, None)`` where ctx carries the run, its owning org, the
    member roster (for @mention resolution) and the current user — or
    ``(None, (response, status))`` to short-circuit.
    """
    run_data = _load_run(run_id)
    if run_data is None or not _can_access_run(run_id, run_data, _active_profile_id()):
        return None, (jsonify({"error": "run_not_found"}), 404)
    owner_pid = _run_owner_id(run_id, run_data) or _active_profile_id() or ""
    members: list[tuple[str, str]] = []
    if owner_pid:
        try:
            members = [
                (m.email, "")
                for m in _tenancy.MembershipStore().list_for_profile(owner_pid)
                if m.status == _tenancy.STATUS_ACTIVE
            ]
        except Exception:
            members = []
    ctx = {
        "run_data": run_data,
        "owner_pid": owner_pid,
        "members": members,
        "me": _auth.current_user_email() or "",
    }
    return ctx, None


def _video_can_access_project(project) -> bool:
    """Per-profile guard for a video project (ADR-0003 isolation)."""
    if project is None:
        return False
    pid = getattr(project, "profile_id", None)
    if pid and isinstance(pid, str) and pid.startswith("_run_"):
        return True
    return pid == _active_profile_id()


def _video_brand_kit():
    """The active profile's BrandKit for the footage path, or None."""
    pid = _active_profile_id()
    if not pid or not _v8_ok:
        return None
    try:
        return _v8_brand_kit_for(pid)
    except Exception:
        return None


def _phase_w_org():
    """Active workspace id, or None (pages render a sign-in prompt)."""
    return _active_profile_id() or None


def _doc_load_owned(doc_id):
    """(pid, spec) for a document owned by the active org, else (pid, None)."""
    pid = _active_profile_id()
    if not pid:
        return None, None
    from mediahub.documents import store as _docstore

    return pid, _docstore.load_document(pid, doc_id)


def _nl_load_owned(newsletter_id):
    """(pid, spec) for a newsletter owned by the active org, else (pid, None)."""
    pid = _active_profile_id()
    if not pid:
        return None, None
    from mediahub.email_design import store as _ns

    return pid, _ns.load_newsletter(pid, newsletter_id)


def _gate_until_org_ready():
    # Tests bypass the gate by default — they assert specific
    # behaviour of downstream routes and shouldn't have to seed a
    # profile. Tests that exercise the gate set TESTING=False on
    # the app explicitly (see test_org_setup_gate.py).
    if current_app.config.get("TESTING") and not current_app.config.get("ENFORCE_ORG_GATE"):
        return None
    ep = request.endpoint or ""
    # Always allow static, the home page, settings, health, and the
    # organisation routes themselves.
    if ep in _SETUP_EXEMPT_ENDPOINTS:
        return None
    # The operator-only "Developer" settings section is a deployment
    # surface (health, deployment status, site-wide cache purge, links to
    # the operator dashboards), org-independent exactly like the operator
    # console and mobile-parity tool exempted above — an operator on a
    # fresh deployment has no organisation yet. Its endpoint (settings_section)
    # also serves the org-scoped sections, so it can't be a flat exemption;
    # carve out only the developer section for a signed-in operator (the
    # handler re-checks is_dev_operator, so this is not an auth grant).
    if (
        ep == "settings_section"
        and (request.view_args or {}).get("section") == "developer"
        and _auth.is_dev_operator()
    ):
        return None
    path = request.path or ""
    # Any /static/ asset (fonts.css, woff2, theme CSS, …) must load for
    # everyone, even before an org is set up. The endpoint-name exemption
    # ("static") above misses CUSTOM routes registered under /static/
    # (e.g. static_fonts_css), which would otherwise be redirected to
    # /sign-in and silently break the first-party fonts site-wide. Guard
    # by path so that class of break can't recur.
    if path.startswith("/static/"):
        return None
    # JSON-style callers get a 409 instead of a redirect so the browser
    # fetch() call can show a friendly inline error. This is keyed on the
    # /api/ prefix AND on a JSON Accept header, so fetch endpoints that
    # live outside /api/ (e.g. /upload/from-url, /runs/<id>/refetch) get
    # JSON too — never an HTML sign-in page dumped into a fetch().
    is_api = path.startswith("/api/")
    if is_api and any(path.startswith(p) for p in _SETUP_EXEMPT_API_PREFIXES):
        return None
    wants_json = is_api or "application/json" in (request.headers.get("Accept") or "")
    prof = _active_profile()
    if prof is not None and prof.is_ready():
        return None
    if wants_json:
        return (
            jsonify(
                {
                    "ok": False,
                    "error": "organisation_not_ready",
                    "message": (
                        "Set up your organisation before producing content. "
                        "MediaHub needs to know who you are first."
                    ),
                    "setup_url": url_for("organisation_setup"),
                }
            ),
            409,
        )
    # Browser request. If the visitor simply isn't signed in but
    # organisations already exist on this deployment, send them to
    # the sign-in picker so they can choose one — not into the
    # create-new flow. Only fall through to organisation setup when
    # there is genuinely nothing to sign into (fresh deployment), or
    # when a not-yet-ready org is already pinned (so they can finish
    # its setup).
    if prof is None and list_profiles():
        # Preserve the page the user was heading to (A-6): when an idle
        # timeout drops the org pin, re-entry through the picker should
        # land back on that deep link, not home. Only GET navigations
        # carry a replayable destination.
        _dest = _safe_next(request.full_path.rstrip("?")) if request.method == "GET" else ""
        if _dest and _dest != url_for("sign_in_page"):
            return redirect(url_for("sign_in_page", next=_dest))
        return redirect(url_for("sign_in_page"))
    # Hardening: never discard a browser POST in silence. The setup
    # POSTs themselves are exempt above, so reaching here on a POST
    # means an unexpected case (an expired session mid-setup, or a
    # content POST attempted before setup finished). Stash a one-shot
    # notice the setup page surfaces so the user learns their submit
    # was not saved instead of watching it vanish.
    if request.method == "POST":
        session["_setup_gate_notice"] = (
            "Your changes weren't saved yet — finish setting up your "
            "organisation below, then try that again."
        )
    return redirect(url_for("organisation_setup"))


def _render_configure(
    run_id: str,
    meta: dict,
    *,
    error: str = "",
    selected_club: str = "",
    duplicate: Optional[dict] = None,
) -> str:
    clubs = meta.get("clubs") or []
    meet_name = meta.get("meet_name") or ""
    parse_err = meta.get("parse_error") or ""

    # Re-run warning banner (warn, never block). Rendered into the body
    # below; empty when this meet/file hasn't been processed before.
    dup_banner_html = ""
    if duplicate:
        _dup_when = (duplicate.get("created_at") or "")[:10]
        _dup_name = duplicate.get("meet_name") or "this meet"
        _review_dup = url_for("review", run_id=duplicate["run_id"])
        _dup_lead = (
            "You&rsquo;ve already run this exact file."
            if duplicate.get("exact")
            else "Looks like you&rsquo;ve already run this meet."
        )
        dup_banner_html = (
            '<div class="card" role="alert" style="margin-bottom:var(--sp-4);'
            'border-left:3px solid var(--warn);background:rgba(255,200,90,0.06)">'
            f"<b>{_dup_lead}</b> "
            f'<span class="dim">{_h(_dup_name)}'
            + (f" &middot; {_h(_dup_when)}" if _dup_when else "")
            + "</span>"
            '<p class="dim" style="margin:6px 0 10px;font-size:var(--fs-sm)">'
            "You can still run it again &mdash; we never block a re-run &mdash; "
            "but if this is a duplicate you may want to open the existing pack "
            "instead of generating it twice.</p>"
            '<div style="display:flex;gap:10px;flex-wrap:wrap">'
            f'<a class="btn secondary" href="{_review_dup}">View existing run &rarr;</a>'
            "</div></div>"
        )

    # No clubs detected. Only render an error state when the file is
    # genuinely unusable:
    #   1. file is too small / unreadable (likely a broken download)
    #   2. file parsed OK but contains no events (entry list / meet preview)
    # When events DID parse but no club names survived (e.g. a distance-event
    # splits page that lists only swimmers, times and splits), fall through
    # to the form \u2014 its club field degrades to a free-text input so the run
    # is never dead-ended on a format quirk.
    byte_size = int(meta.get("file_byte_size") or 0)
    n_events = int(meta.get("n_events") or 0)
    if not clubs and (byte_size < 2048 or n_events == 0):
        upload_url = url_for("upload")

        _fname = _h(meta.get("filename") or "(unknown)")
        if parse_err:
            # D-22: the parser actually CRASHED — don't tell the volunteer
            # the file "parsed OK" and to wait for the meet to finish. Say we
            # couldn't read it, with plain-language causes.
            headline = "We couldn't read that file"
            explain = (
                f"<p>The file <code>{_fname}</code> couldn't be read as a meet "
                "results file. It may be corrupted, an unusual export, or "
                "password-protected.</p>"
                '<p class="dim" style="font-size:13px;margin-top:8px">'
                "Try re-exporting or re-downloading it from the source, then "
                "upload again.</p>"
            )
        elif byte_size < 2048:
            headline = "That file doesn't look like a meet results file"
            explain = (
                f"<p>The file <code>{_fname}</code> "
                f"is only {byte_size} bytes &mdash; far too small to be a real "
                "meet results file. The most common cause is a broken download "
                '(an HTML "404 Not Found" page saved as a PDF, or a partial save).</p>'
                '<p class="dim" style="font-size:13px;margin-top:8px">'
                "Try downloading the file again from the source and re-uploading. "
                "A real Hytek PDF or HY3 is usually 100 KB or larger.</p>"
            )
        else:
            headline = "That file looks like a meet preview, not results"
            explain = (
                f"<p>The file <code>{_fname}</code> "
                "parsed OK but doesn't contain any events with results.</p>"
                '<p class="dim" style="font-size:13px;margin-top:8px">'
                "This usually means you uploaded an entry list, a heat sheet, or "
                "meet conditions document. Wait until the meet finishes and the "
                "organisers publish the actual results file.</p>"
            )
        # D-22: the raw parser exception is operator-only — never shown to a
        # customer alongside friendly copy (it read as a contradiction).
        err_explain = (
            f'<p class="dim" style="margin-bottom:12px;font-size:13px">'
            f"Parser error: <code>{_h(parse_err)}</code></p>"
            if parse_err and _auth.is_dev_operator()
            else ""
        )
        body = f"""
<h1>{_h(headline)}</h1>
<div class="card">
  {explain}
  {err_explain}
  <p class="dim" style="font-size:13px;margin-top:14px">Supported formats: Hytek (<code>.hy3</code>, <code>.hyv</code>), SDIF (<code>.sd3</code>, <code>.sdif</code>, <code>.cl2</code>), a <code>.zip</code> of results, a results PDF, HTML, CSV, TXT or Excel (<code>.xlsx</code>).</p>
  <div style="margin-top:18px;display:flex;gap:10px;flex-wrap:wrap">
    <a class="btn" href="{upload_url}">\u2190 Try another file</a>
    <a class="btn secondary" href="{url_for("make_page")}">Pick a different input type</a>
  </div>
</div>
"""
        return _layout("Couldn't read file", body, active="create")

    # MR-8: pre-select the club that best matches the signed-in
    # organisation instead of defaulting to the alphabetical first club.
    # One shared fuzzy matcher (_best_club_match: containment + token-subset
    # + difflib, 0.6 floor) so this pre-select and upload_configure never
    # disagree; "" means nothing cleared the floor, so no wrong auto-pick.
    active_prof = _active_profile()
    org_name = (getattr(active_prof, "display_name", "") or "").strip()
    club_match_warning_html = ""
    if not selected_club and clubs and org_name:
        best_club = _best_club_match([str(c) for c in clubs], org_name)
        if best_club:
            selected_club = best_club
        else:
            club_match_warning_html = (
                '<p class="dim" style="margin-top:4px;font-size:var(--fs-sm);'
                'color:var(--warn)">Heads up &mdash; none of the clubs in this '
                f"meet match {_h(org_name)}. Captions will speak as "
                f"{_h(org_name)} about the selected club's swimmers.</p>"
            )

    # V8.2 issue 4: ONLY clubs from this file are listed.
    opts = "".join(
        f'<option value="{_h(c)}"{" selected" if c == selected_club else ""}>{_h(c)}</option>'
        for c in clubs
    )
    # Club field degrades gracefully: when no real club names were detected
    # (e.g. a distance-event page that lists only swimmers, times and splits),
    # offer a free-text input so the run is never blocked on a picker with
    # nothing valid to pick.
    if clubs:
        club_field_html = (
            '<label for="run-config-club">Club to feature</label>'
            f'<select name="club_filter" id="run-config-club" required>{opts}</select>'
            '<p class="dim" style="margin-top:4px;font-size:var(--fs-sm)">'
            "Only clubs that actually appear in this meet are listed.</p>"
            f"{club_match_warning_html}"
        )
    else:
        club_field_html = (
            '<label for="run-config-club">Club to feature</label>'
            '<input type="text" name="club_filter" id="run-config-club" required '
            f'value="{_h(selected_club or "")}" autocomplete="off" '
            'placeholder="e.g. City of Sheffield" />'
            '<p class="dim" style="margin-top:4px;font-size:var(--fs-sm);color:var(--warn)">'
            "We couldn&rsquo;t read club names from this file &mdash; some results "
            "pages list only swimmers, times and splits. Type the club you want to "
            "feature and we&rsquo;ll match its swimmers.</p>"
        )
    err_html = f'<p class="tag bad" style="margin-bottom:14px">{_h(error)}</p>' if error else ""

    # Pre-fill the brand fields from the active organisation so the
    # user never re-enters logo / colours they already gave us at
    # /organisation/setup. Phase 1.5 consolidation: logos live on the
    # profile, not on individual runs. Colour pickers stay because
    # they're cheap per-run overrides for the rare case someone wants
    # a different palette for a sponsor-themed post.
    # (active_prof already resolved above for the MR-8 club pre-select.)
    prof_primary = "#0A2540"
    prof_secondary = "#101820"
    prof_accent = "#FFD86E"
    prof_logo_html = ""
    if active_prof is not None:
        # Seed the run's palette the same way the site chrome resolves it,
        # so the colours a run starts from match what the user confirmed at
        # /organisation/setup. The manual override wins per-slot, falling
        # back to the AI's extracted pick. Reading the raw
        # ``brand_primary``/``brand_secondary`` fields directly is unsafe:
        # for an org whose colours came purely from the AI pick (the user
        # never did a manual "Save brand colours"), those legacy fields
        # stay at the ``#A30D2D`` class default, so runs were seeded red
        # while the chrome correctly showed the brand. Resolve all three
        # slots through ``effective_palette`` and only fall back to the
        # legacy fields, then the literal default, when the resolver is
        # empty for that slot.
        from mediahub.brand.palette import effective_palette as _effective_palette

        _resolved_palette = _effective_palette(
            manual=getattr(active_prof, "brand_palette_manual", {}) or {},
            extracted=getattr(active_prof, "brand_palette_extracted", {}) or {},
        )
        prof_primary = (
            _resolved_palette.get("primary")
            or (getattr(active_prof, "brand_primary", "") or "").strip()
            or prof_primary
        )
        prof_secondary = (
            _resolved_palette.get("secondary")
            or (getattr(active_prof, "brand_secondary", "") or "").strip()
            or prof_secondary
        )
        if _resolved_palette.get("accent"):
            prof_accent = _resolved_palette["accent"]
        logo_url = (getattr(active_prof, "brand_logo_url", "") or "").strip()
        # Uploaded logos live on ``brand_logos`` (local files), distinct
        # from the auto-detected website ``brand_logo_url``. Either one
        # counts as "the org has a logo" — without this, a user who
        # uploaded a crest at /organisation/setup was still told "No
        # logo on your organisation profile" here and the run never
        # received it.
        _uploaded_logo_label = ""
        for _lg in getattr(active_prof, "brand_logos", None) or []:
            if str(_lg.get("mime", "")).startswith("image/"):
                _uploaded_logo_label = (
                    _lg.get("label") or _lg.get("original_filename") or "uploaded logo"
                )
                break
        # Uploads win the display too \u2014 they're an explicit brand
        # decision, and the run seeding below follows the same order.
        if _uploaded_logo_label:
            prof_logo_html = (
                f'<p class="dim" style="margin:6px 0 0;font-size:12px">'
                f'Logo: <code style="font-size:11px">{_h(_uploaded_logo_label[:80])}</code> '
                f"&mdash; flows through to every graphic.</p>"
            )
        elif logo_url:
            _logo_disp = logo_url[:80] + ("\u2026" if len(logo_url) > 80 else "")
            prof_logo_html = (
                f'<p class="dim" style="margin:6px 0 0;font-size:12px">'
                f'Logo: <code style="font-size:11px">'
                f"{_h(_logo_disp)}</code></p>"
            )
        else:
            prof_logo_html = (
                '<p class="dim" style="margin:6px 0 0;font-size:12px;color:var(--warn)">'
                "No logo on your organisation profile. "
                f'<a href="{url_for("organisation_setup")}" '
                'style="color:var(--warn);text-decoration:underline">Add one</a> '
                "so it flows through to every graphic.</p>"
            )

    # H-13: brand-kit chooser. Only rendered when the org actually has two
    # or more kits — a single-kit org has nothing to choose, so the control
    # is hidden entirely. Defaults to the org's current default kit; the
    # choice applies to this run only (the org-wide default is untouched).
    # Swatch colours come from each kit's own palette data (inheriting the
    # org palette where a kit slot is blank) — never hardcoded here.
    kit_select_html = ""
    if active_prof is not None:
        try:
            from mediahub.brand import kits as _bkits

            _org_kits = _bkits.list_kits(active_prof)
            if len(_org_kits) >= 2:
                _default_kid = _bkits.default_kit_id(active_prof)
                _opts = ""
                _sel_name, _sel_cols = "", (prof_primary, prof_secondary, prof_accent)
                for _k in _org_kits:
                    _kp = _k.palette or {}
                    _o_cols = (
                        _kp.get("primary") or prof_primary,
                        _kp.get("secondary") or prof_secondary,
                        _kp.get("accent") or prof_accent,
                    )
                    _is_def = _k.kit_id == _default_kid
                    if _is_def or not _sel_name:
                        _sel_name, _sel_cols = _k.name, _o_cols
                    _opts += (
                        f'<option value="{_h(_k.kit_id)}"{" selected" if _is_def else ""} '
                        f'data-name="{_h(_k.name)}" data-primary="{_h(_o_cols[0])}" '
                        f'data-secondary="{_h(_o_cols[1])}" data-accent="{_h(_o_cols[2])}">'
                        f"{_h(_k.name)}{' (default)' if _is_def else ''}</option>"
                    )
                _sw_spans = "".join(
                    '<span style="width:14px;height:14px;border-radius:4px;'
                    f'border:1px solid var(--border);background-color:{_h(_c)}"></span>'
                    for _c in _sel_cols
                )
                kit_select_html = (
                    '<div style="margin-top:14px">'
                    '<label for="run-config-kit">Brand kit for these results</label>'
                    f'<select name="brand_kit_id" id="run-config-kit">{_opts}</select>'
                    '<div style="display:flex;align-items:center;gap:8px;margin-top:6px">'
                    f'<span id="mh-kit-choice-sw" style="display:inline-flex;gap:4px" aria-hidden="true">{_sw_spans}</span>'
                    f'<span id="mh-kit-choice-name" class="dim" style="font-size:var(--fs-sm)">{_h(_sel_name)}</span>'
                    "</div>"
                    '<p class="dim" style="margin-top:4px;font-size:var(--fs-sm)">'
                    "Applies to these results only &mdash; your organisation&rsquo;s "
                    "default kit stays unchanged for future meets.</p>"
                    "</div>"
                )
        except Exception:
            kit_select_html = ""

    body = f"""
<section class="mh-hero" data-lane="02" style="padding-top:var(--sp-7);padding-bottom:var(--sp-5);margin-bottom:var(--sp-4)">
  <span class="mh-hero-eyebrow">Configure this run</span>
  <h1>One more look,<br><em class="editorial">then we run it.</em></h1>
  <p class="lede">{_h(meet_name) or "Meet uploaded."} &mdash; {len(clubs)} club{"s" if len(clubs) != 1 else ""} detected. Pick yours and tune the palette for this one-off. Photos are added later, per graphic, so each one lands on the right athlete&rsquo;s card.</p>
</section>
{dup_banner_html}
<nav class="mh-stepper" aria-label="Upload progress">
  <span class="mh-stepper-item is-done"><span class="num">1</span>Upload</span>
  <span class="mh-stepper-arrow"></span>
  <span class="mh-stepper-item is-active"><span class="num">2</span>Configure</span>
  <span class="mh-stepper-arrow"></span>
  <span class="mh-stepper-item"><span class="num">3</span>Run</span>
  <span class="mh-stepper-arrow"></span>
  <span class="mh-stepper-item"><span class="num">4</span>Review</span>
</nav>

<div class="mh-form-grid">
<div>
{err_html}
<div class="card" style="margin-bottom:0">
  <form id="mh-cfg-form" method="post" enctype="multipart/form-data" data-loader-text="Setting up your run" data-loader-sub="Saving config and starting the pipeline\u2026">
    <input type="hidden" name="run_id" value="{_h(run_id)}" />

    {club_field_html}

    <fieldset class="mh-fieldset">
      <legend>Brand &mdash; loaded from your organisation</legend>
      <p class="mh-fieldset-lede">
        Defaults come from your <a href="{url_for("organisation_setup")}" style="text-decoration:underline">organisation profile</a>.
        Tweak below for a one-off override; the preview on the right updates as you move the picker.
      </p>
      {prof_logo_html}
      {kit_select_html}

      <div style="display:flex;gap:14px;align-items:flex-end;margin-top:12px;flex-wrap:wrap">
        <div style="flex:1;min-width:120px"><label for="run-config-primary">Primary</label><input id="run-config-primary" type="color" name="primary_colour" value="{_h(prof_primary)}" /></div>
        <div style="flex:1;min-width:120px"><label for="run-config-secondary">Secondary</label><input id="run-config-secondary" type="color" name="secondary_colour" value="{_h(prof_secondary)}" /></div>
        <div style="flex:1;min-width:120px"><label for="run-config-accent">Accent</label><input id="run-config-accent" type="color" name="accent_colour" value="{_h(prof_accent)}" /></div>
      </div>
      <div style="display:flex;gap:10px;align-items:center;margin-top:12px;flex-wrap:wrap"
           data-org-primary="{_h(prof_primary)}" data-org-secondary="{_h(prof_secondary)}" data-org-accent="{_h(prof_accent)}" id="mh-palette-tools">
        <button type="button" class="btn secondary" style="font-size:12px;padding:7px 12px"
                onclick="mhCyclePalette()" title="Rotate primary &rarr; secondary &rarr; accent">&#8635; Swap colour order</button>
        <button type="button" class="btn ghost" style="font-size:12px;padding:7px 10px"
                onclick="mhResetPalette()" title="Restore the organisation's official palette">Reset to organisation colours</button>
        <span class="muted" style="font-size:11.5px">Reordering here is a one-off for this meet &mdash; your organisation&rsquo;s official palette is untouched.</span>
      </div>
    </fieldset>

    <div style="margin-top:var(--sp-5)"><button class="btn large" type="submit">Run pipeline \u2192</button></div>
  </form>
</div>
</div>

<aside class="mh-form-side">
  <div class="mh-kit-preview">
    <h4>Live preview</h4>
    <div id="mh-kit-mock" class="mh-kit-mock" aria-hidden="true">
      <span class="mh-kit-mock-eyebrow">Story \u00b7 1080\u00d71920</span>
      <h3 class="mh-kit-mock-headline">Tom Davies<br><em>PB</em> 100m free</h3>
      <div>
        <div class="mh-kit-mock-time">52.41</div>
        <div class="mh-kit-mock-meta"><b>&minus;0.74s</b> &middot; LANE 4 &middot; HEAT 2</div>
      </div>
    </div>
    <div class="mh-kit-swatches" aria-hidden="true">
      <div id="mh-kit-sw-pri" title="Primary"></div>
      <div id="mh-kit-sw-sec" title="Secondary"></div>
      <div id="mh-kit-sw-acc" title="Accent"></div>
    </div>
    <p class="dim" style="margin-top:var(--sp-3);font-size:var(--fs-sm)">
      Story-card layout shown. Feed graphics and motion reels honour the same palette.
    </p>
  </div>
</aside>
</div>

<script>
(function(){{
  // Live update: every time a colour picker changes, repaint the
  // mock card's CSS custom properties.
  var mock = document.getElementById('mh-kit-mock');
  var swP  = document.getElementById('mh-kit-sw-pri');
  var swS  = document.getElementById('mh-kit-sw-sec');
  var swA  = document.getElementById('mh-kit-sw-acc');
  var pri  = document.getElementById('run-config-primary');
  var sec  = document.getElementById('run-config-secondary');
  var acc  = document.getElementById('run-config-accent');
  function paint() {{
    if (!mock) return;
    if (pri) {{ mock.style.setProperty('--kit-primary',   pri.value); if (swP) swP.style.background = pri.value; }}
    if (sec) {{ mock.style.setProperty('--kit-secondary', sec.value); if (swS) swS.style.background = sec.value; }}
    if (acc) {{ mock.style.setProperty('--kit-accent',    acc.value); if (swA) swA.style.background = acc.value; }}
  }}
  ['input','change'].forEach(function(evt){{
    if (pri) pri.addEventListener(evt, paint);
    if (sec) sec.addEventListener(evt, paint);
    if (acc) acc.addEventListener(evt, paint);
  }});
  paint();

  // H-13: brand-kit chooser — mirror the selected kit's name + palette
  // swatches beside the select so the volunteer sees what the kit means
  // before running. Colours ride on each <option>'s data attributes.
  var kitSel  = document.getElementById('run-config-kit');
  var kitName = document.getElementById('mh-kit-choice-name');
  var kitSw   = document.getElementById('mh-kit-choice-sw');
  function kitPaint(fromUser) {{
    if (!kitSel || !kitSel.options.length) return;
    var o = kitSel.options[kitSel.selectedIndex];
    if (!o) return;
    if (kitName) kitName.textContent = o.getAttribute('data-name') || o.textContent;
    var cols = [o.getAttribute('data-primary'), o.getAttribute('data-secondary'), o.getAttribute('data-accent')];
    if (kitSw) {{
      for (var i = 0; i < kitSw.children.length && i < 3; i++) {{
        if (cols[i]) kitSw.children[i].style.backgroundColor = cols[i];
      }}
    }}
    // SRV-3: picking a kit must drive what the form actually SUBMITS — the
    // run renders from these three colour inputs, while the kit id feeds
    // the governance gates. Without this, "Away kit" rendered in the
    // default kit's colours and the brand-lock then judged every card
    // against the away kit's tokens. Only on a user change (never the
    // initial paint, which would clobber a re-configured run's stored
    // colours); the volunteer can still override the pickers afterwards.
    if (fromUser) {{
      if (pri && cols[0]) pri.value = cols[0];
      if (sec && cols[1]) sec.value = cols[1];
      if (acc && cols[2]) acc.value = cols[2];
      paint();
    }}
  }}
  if (kitSel) {{ kitSel.addEventListener('change', function(){{ kitPaint(true); }}); kitPaint(); }}

  // Colour-order tools — same idea as "Cycle colours" on organisation
  // setup, but scoped to this one run. Reset restores the official
  // organisation palette the pickers were seeded from.
  window.mhCyclePalette = function() {{
    if (!pri || !sec || !acc) return;
    var p = pri.value, s = sec.value, a = acc.value;
    pri.value = s; sec.value = a; acc.value = p;
    paint();
  }};
  window.mhResetPalette = function() {{
    var tools = document.getElementById('mh-palette-tools');
    if (!tools) return;
    if (pri && tools.dataset.orgPrimary)   pri.value = tools.dataset.orgPrimary;
    if (sec && tools.dataset.orgSecondary) sec.value = tools.dataset.orgSecondary;
    if (acc && tools.dataset.orgAccent)    acc.value = tools.dataset.orgAccent;
    paint();
  }};

}})();
</script>
"""
    return _layout("Configure run", body, active="create")


def _render_settings_governance_section(prof: Optional[ClubProfile]) -> str:
    """AI governance for the active org (1.23): usage + quota headroom per
    feature, the role→feature permission matrix, and a provenance note."""
    if prof is None:
        return (
            '<div class="card"><p style="margin-top:0">No club yet &mdash; set one up to '
            "see its AI usage and permissions.</p>"
            f'<a class="btn" href="{url_for("organisation_setup")}">'
            "Create your organisation &rarr;</a></div>"
        )
    from mediahub import governance
    from mediahub.governance import features as _gf
    from mediahub.collab import permissions as _cperms

    pid = prof.profile_id
    plan = _auth.current_plan()

    # Features whose routes don't yet record usage: their per-request
    # governance context is bound but nothing meters them, so their limits
    # would never enforce. Label them honestly rather than imply a live
    # count (caption / imagine / translate DO record and are metered).
    _unmetered_features = {
        _gf.FEATURE_BRAND,
        _gf.FEATURE_PALETTE,
        _gf.FEATURE_DESCRIBE,
        _gf.FEATURE_DNA,
        _gf.FEATURE_RESEARCH,
    }

    # --- Usage + quota per feature ---
    usage_rows = ""
    for spec in _gf.all_features():
        if spec.key in _unmetered_features:
            usage_rows += (
                '<tr><td style="padding:8px 10px">'
                f"<strong>{_h(spec.label)}</strong>"
                f'<div style="font-size:12px;color:var(--ink-muted)">{_h(spec.description)}</div>'
                "</td>"
                '<td style="padding:8px 10px;text-align:right;color:var(--ink-muted)">&mdash;</td>'
                '<td style="padding:8px 10px;color:var(--ink-muted)">Not yet metered</td></tr>'
            )
            continue
        if spec.key == _gf.FEATURE_IMAGINE:
            try:
                q = _imagine.check_quota(pid)
                used, limit = int(q.used), int(q.limit)
                unlimited = bool(getattr(q, "unlimited", limit < 0))
            except Exception:
                st = governance.check(pid, spec.key, plan=plan)
                used, limit, unlimited = st.used, st.limit, not st.enforced
        else:
            st = governance.check(pid, spec.key, plan=plan)
            used, limit, unlimited = st.used, st.limit, not st.enforced

        if unlimited or limit < 0:
            limit_cell = "No limit &mdash; metered"
        else:
            pct = min(100, int(used * 100 / limit)) if limit else 0
            colour = (
                "var(--mh-prim-error-500)"
                if used >= limit
                else ("var(--mh-prim-warning-500)" if pct >= 80 else "var(--accent)")
            )
            limit_cell = (
                f"{used} / {limit}"
                '<div style="height:8px;background:rgba(255,255,255,0.08);'
                'border-radius:6px;margin-top:6px">'
                f'<div style="height:8px;width:{pct}%;background:{colour};'
                'border-radius:6px"></div></div>'
            )
        usage_rows += (
            '<tr><td style="padding:8px 10px">'
            f"<strong>{_h(spec.label)}</strong>"
            f'<div style="font-size:12px;color:var(--ink-muted)">{_h(spec.description)}</div>'
            "</td>"
            f'<td style="padding:8px 10px;text-align:right">{used}</td>'
            f'<td style="padding:8px 10px">{limit_cell}</td></tr>'
        )
    usage_card = (
        '<div class="card"><h2 style="margin-top:0;font-size:18px">AI usage this month</h2>'
        '<p style="color:var(--ink-muted);font-size:13px">A rolling 30-day window. Metered '
        "features (captions, imagery, translation) count every use and block only once a "
        "specific limit is set; features marked <em>not yet metered</em> run but aren&rsquo;t "
        "counted yet.</p>"
        '<table style="width:100%;border-collapse:collapse">'
        '<thead><tr style="text-align:left;color:var(--ink-muted);font-size:12px">'
        '<th style="padding:8px 10px">Feature</th>'
        '<th style="padding:8px 10px;text-align:right">Used</th>'
        '<th style="padding:8px 10px">Limit</th></tr></thead>'
        f"<tbody>{usage_rows}</tbody></table></div>"
    )

    # --- Role → feature permission matrix ---
    feats = _gf.all_features()
    head = "".join(f'<th style="padding:6px 8px;font-size:12px">{_h(s.label)}</th>' for s in feats)
    prows = ""
    for role in _cperms.assignable_roles():
        cells = ""
        for s in feats:
            ok = governance.can_use_feature(role, s.key, plan=plan)
            mark = (
                '<span style="color:var(--mh-prim-success-400)">&#10003;</span>'
                if ok
                else '<span style="color:var(--ink-muted)">&mdash;</span>'
            )
            cells += f'<td style="padding:6px 8px;text-align:center">{mark}</td>'
        prows += (
            f'<tr><td style="padding:6px 8px"><strong>{_h(_cperms.role_label(role))}</strong>'
            f"</td>{cells}</tr>"
        )
    your_role = _active_role(pid)
    perms_card = (
        '<div class="card"><h2 style="margin-top:0;font-size:18px">Who can use AI</h2>'
        '<p style="color:var(--ink-muted);font-size:13px">Your role here is '
        f"<strong>{_h(_cperms.role_label(your_role))}</strong>. Content generation needs "
        "Editor; brand-defining AI needs the Owner.</p>"
        '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse">'
        '<thead><tr style="text-align:left;color:var(--ink-muted)">'
        f'<th style="padding:6px 8px">Role</th>{head}</tr></thead>'
        f"<tbody>{prows}</tbody></table></div></div>"
    )

    prov_card = (
        '<div class="card"><h2 style="margin-top:0;font-size:18px">Provenance</h2>'
        '<p style="color:var(--ink-muted);font-size:13px;margin-bottom:0">Every result card, '
        "reel and generated image is stamped with an honest provenance manifest &mdash; what "
        "made it, from what, and when. Result cards are recorded as deterministic composites of "
        "real photography; AI-generated images are marked as such.</p></div>"
    )

    # D-17 — a visible AI-availability row. Previously the only signal that
    # AI was off lived in a hover tooltip on a tiny dot (useless on a phone),
    # and nothing in Settings said whether a provider was live.
    try:
        from mediahub.media_ai.llm import active_provider as _active_prov
        from mediahub.media_ai.llm import is_available as _llm_available

        _ai_live = bool(_llm_available())
        _prov_label = (
            {
                "gemini-api": "Google Gemini",
                "anthropic-api": "Anthropic (Claude)",
            }.get(_active_prov())
            if _ai_live
            else ""
        )
    except Exception:
        _ai_live, _prov_label = False, ""
    if _ai_live:
        status_card = (
            '<div class="card"><h2 style="margin-top:0;font-size:18px">AI status</h2>'
            '<p style="font-size:13px;margin-bottom:0">'
            '<span class="tag good">Live</span> AI captions, imagery and translation are '
            "enabled"
            + (f" via <strong>{_h(_prov_label)}</strong>" if _prov_label else "")
            + ".</p></div>"
        )
    else:
        status_card = (
            '<div class="card" style="border-color:var(--mh-prim-warning-500)">'
            '<h2 style="margin-top:0;font-size:18px">AI status</h2>'
            '<p style="font-size:13px;margin-bottom:0">'
            '<span class="tag warn">Disabled</span> No AI provider is live on this deployment, '
            "so captions, imagery and translation will show an honest error rather than a made-up "
            "result. You can still review, edit and approve cards by hand. Ask your operator to "
            "configure a provider key to turn AI back on.</p></div>"
        )

    return status_card + usage_card + perms_card + prov_card


def _preview_brand_kit():
    """The brand previews render in: the signed-in org's kit, else a neutral
    demo brand. Returns ``(brand_kit, signature)``."""
    prof = _active_profile()
    if prof is not None:
        try:
            bk = prof.get_brand_kit()
            return bk, _preview_brand_signature(bk)
        except Exception:
            pass
    from mediahub.brand.kit import BrandKit

    bk = BrandKit(
        profile_id="_preview",
        display_name="MediaHub",
        primary_colour="#0E2A47",
        secondary_colour="#C9A227",
        accent_colour="#FFFFFF",
        short_name="MH",
    )
    return bk, "demo-" + _preview_brand_signature(bk)


def _compose_spotlight_caption(run_id: str, swimmer_key: str, tone: str = ""):
    """Compose the single spotlight caption from APPROVED achievements.

    Shared by the initial build and the tone rewrite on the saved
    draft. Returns ``(result, None)`` with
    ``{caption, swimmer_name, meet_name, n_approved}`` on success, or
    ``(None, (response, status))`` carrying a rendered error page.
    Pure AI composition — no template stitching; an unavailable
    provider is an honest error page, never a fake caption.
    """
    from mediahub.club_platform.athlete_spotlight import build_spotlight_pack

    run_data = _load_run(run_id)
    if not _can_access_run(run_id, run_data, _active_profile_id()):
        run_data = None
    if not run_data:
        # _recovery_page already returns a (body, status) tuple.
        return None, _recovery_page(
            "Run not found",
            "This run isn't on disk. It may have been deleted from /privacy, "
            "or the URL might be from a different deployment.",
            eyebrow="Athlete spotlight",
            primary_cta=("Open activity", url_for("activity_page")),
            secondary_cta=("Back to home", url_for("home")),
        )
    try:
        pack = build_spotlight_pack(run_data, swimmer_key)
    except Exception as e:
        log.warning(
            "spotlight: build_spotlight_pack failed for %s/%s: %s",
            run_id,
            swimmer_key,
            e,
        )
        pack = None
    if not pack:
        return None, _recovery_page(
            "Swimmer not found",
            f'No achievements were recorded for "{swimmer_key}" in this meet. '
            "Pick another swimmer, or open the meet review to see who's in "
            "the recognition report.",
            eyebrow="Athlete spotlight",
            primary_cta=(
                "Choose another swimmer",
                url_for("spotlight_landing") + f"?run_id={run_id}",
            ),
            secondary_cta=("Open review", url_for("review", run_id=run_id)),
        )

    wf_states = {}
    try:
        ws = _get_wf_store()
        if ws:
            wf_states = ws.load(run_id)
    except Exception:
        wf_states = {}

    # Filter to approved/posted; treat absence as not-selected.
    # F11: key on the same unique ~n-deduped ids the spotlight review approves
    # under, so a duplicate swim_id's twin is read independently (keying on the
    # bare swim_id would read one twin's state for both). Non-duplicate runs
    # key exactly as before.
    _sp_post_ids = _unique_card_ids(pack["ranked_achievements"], base_fn=_card_base_id_for)
    approved: list[dict] = []
    for _i, ra in enumerate(pack["ranked_achievements"]):
        st = wf_states.get(_sp_post_ids[_i])
        if st and getattr(getattr(st, "status", None), "value", "") in ("approved", "posted"):
            approved.append(ra)

    if not approved:
        body = (
            "<h1>Build spotlight post</h1>"
            '<div class="card"><p class="muted">No achievements approved yet. '
            "Click <strong>Approve</strong> on the achievements you want in "
            "the post, then come back here.</p>"
            f'<p><a class="btn secondary" href="{url_for("spotlight_view", run_id=run_id, swimmer_key=swimmer_key)}">&larr; Back to spotlight</a></p></div>'
        )
        return None, (_layout("Build spotlight post", body, active="create"), 400)

    swimmer_name = pack["swimmer_name"]
    # The link-flow leaves an entry_url placeholder when it can't parse a
    # real meet title; never weave a URL into the caption.
    meet_name = _clean_meet_label(pack["meet_name"])
    # English brief — no JSON envelope. Each approved moment is a
    # natural-language line the model can weave into prose. Strip the
    # scraped crawl-URL suffix the headline template appends and drop
    # exact duplicates so the model isn't fed the same moment twice.
    moment_lines: list[str] = []
    for ra in approved[:8]:
        a = ra.get("achievement", {})
        hl = _strip_source_suffix(a.get("headline") or "")
        ev = _strip_source_suffix(a.get("event") or "")
        tm = (a.get("time") or "").strip()
        pl = a.get("place")
        pb = "PB" if a.get("pb") else ""
        bits = [b for b in [ev, tm, (f"{pl}" if pl else ""), pb] if b]
        line = "; ".join(bits)
        if hl:
            line = f"{hl} ({line})" if line else hl
        if line and line not in moment_lines:
            moment_lines.append(line)

    # Compact result lines for the spotlight GRAPHIC (event + time + PB
    # flag) — real parsed data, kept separate from the prose brief so
    # the renderer never has to re-mine the caption for facts.
    result_lines: list[str] = []
    for ra in approved[:4]:
        a = ra.get("achievement", {})
        ev = _strip_source_suffix(a.get("event") or "")
        tm = (a.get("time") or "").strip()
        pl = a.get("place")
        if not (ev or tm):
            continue
        bits = " ".join(b for b in [ev, "—" if ev and tm else "", tm] if b)
        if pl in (1, 2, 3, "1", "2", "3"):
            bits += f" · {['🥇', '🥈', '🥉'][int(pl) - 1]}"
        if a.get("pb"):
            bits += " · PB"
        if bits and bits not in result_lines:
            result_lines.append(bits)

    # Celebratory aggregates for the spotlight GRAPHIC's stat chips: tally
    # the real, verified achievements behind the approved moments so the
    # card can lead with medals / PBs / swims, never an internal "N
    # approved" count. Counted over every approved moment, not just the
    # four the graphic lists.
    n_pbs = 0
    n_medals = 0
    for ra in approved:
        a = ra.get("achievement", {})
        if a.get("pb"):
            n_pbs += 1
        if a.get("place") in (1, 2, 3, "1", "2", "3"):
            n_medals += 1

    tone_line = ""
    if tone:
        from mediahub.brand.tone import TONE_META, tone_from_str

        meta = TONE_META.get(tone_from_str(tone)) or {}
        if meta:
            tone_line = (
                f"\n\nTone: {meta.get('label', tone)} — {meta.get('description', '')} "
                f"Example of the register: {meta.get('example', '')}"
            )
    _where = f" at {meet_name}" if meet_name else ""
    brief = (
        f"{swimmer_name} just had a strong outing{_where}. The reviewer "
        f"has hand-approved these moments for the spotlight post:\n"
        + "\n".join(f"- {l}" for l in moment_lines)
        + "\n\nWrite ONE single Instagram-ready caption: a hooky "
        "opener, a tight body weaving the approved moments together, "
        "and a closing line. Use the swimmer's first name. Don't "
        "invent facts. ~700 characters max. Output the caption only." + tone_line
    )
    from mediahub.ai_core import (
        ask,
        ProviderNotConfigured,
        ProviderError,
    )

    # Ground the caption in the org's full brand context — the same
    # canonical helper single-card captions use — so the spotlight
    # composite speaks in the voice the rest of the product does.
    tool_system = (
        "You are MediaHub's spotlight-post writer. Output only the "
        "caption text, no preamble or markdown."
    )
    spotlight_system = tool_system
    try:
        spot_prof = _active_profile()
        from mediahub.brand.context import brand_context_for_llm

        brand_block = brand_context_for_llm(spot_prof) if spot_prof else ""
        if brand_block:
            spotlight_system = brand_block + "\n\n" + tool_system
    except Exception:
        pass
    try:
        composed_caption = (ask(spotlight_system, brief, max_tokens=600) or "").strip()
    except ProviderNotConfigured as e:
        err_html = (
            '<div class="card" style="border-color:rgba(255,107,107,0.40)">'
            '<h2 style="margin-top:0">AI features unavailable</h2>'
            f"<p>Spotlight posts require AI. {_h(str(e))}</p>"
            '<p class="muted">Contact your administrator to enable AI on '
            "this deployment.</p>"
            "</div>"
        )
        return None, (_layout("Build spotlight post", err_html, active="create"), 503)
    except ProviderError as e:
        err_html = (
            '<div class="card" style="border-color:rgba(255,107,107,0.40)">'
            '<h2 style="margin-top:0">AI provider error</h2>'
            f"<p>The AI provider couldn't finish the spotlight draft: "
            f"<code>{_h(str(e))}</code>.</p>"
            '<p class="muted">Try again in a moment (rate limits typically '
            "clear within seconds).</p>"
            "</div>"
        )
        return None, (_layout("Build spotlight post", err_html, active="create"), 502)
    if not composed_caption:
        err_html = (
            '<div class="card" style="border-color:rgba(255,107,107,0.40)">'
            '<h2 style="margin-top:0">AI returned no caption</h2>'
            "<p>The provider responded but produced an empty caption. "
            "Try regenerating.</p>"
            "</div>"
        )
        return None, (_layout("Build spotlight post", err_html, active="create"), 502)
    return (
        {
            "caption": composed_caption,
            "swimmer_name": swimmer_name,
            "meet_name": meet_name,
            "n_approved": len(approved),
            "n_pbs": n_pbs,
            "n_medals": n_medals,
            "results_lines": "\n".join(result_lines),
        },
        None,
    )


def _render_stub(
    stub_cls_name: str,
    route_endpoint: str,
    title: str,
    active_tab: str = "create",
    intro_ct: str = "",
):
    """Shared handler for stub routes. GET renders form, POST renders cards.

    ``intro_ct`` — the content-type slug of this flow's "how it works"
    slide (B-1): when set, the GET form keeps a small link back to the
    explainer, since the Create tile skips it after the first visit.
    """
    try:
        from mediahub.club_platform import stubs as _stubs_mod
    except Exception as exc:
        return _recovery_page(
            "Temporarily unavailable",
            f"The content engine failed to load: {exc}. The stub content type can't render until the underlying module is back. Try refreshing in a moment.",
            primary_cta=("Back to Create", url_for("make_page")),
            secondary_cta=("System status", url_for("status_page")),
            code=503,
        )

    StubCls = getattr(_stubs_mod, stub_cls_name, None)
    if StubCls is None:
        return _recovery_page(
            "Content type unavailable",
            f"The {title} stub class isn't registered on this deployment. The route still exists, but the generator wasn't loaded.",
            primary_cta=("Back to Create", url_for("make_page")),
        )

    stub = StubCls()
    if request.method == "POST":
        form_data = request.form.to_dict(flat=True)
        # Photo attachment (optional) — every stub form has this field.
        # Save to DATA_DIR/uploads/stub_attachments/<uuid>.<ext> and
        # record the relative path on form_data so the saved pack carries
        # the reference forward to downstream visual generators.
        photo = request.files.get("attached_photo")
        if photo and getattr(photo, "filename", ""):
            import uuid as _uuid

            ext = Path(photo.filename).suffix.lower() or ".jpg"
            if ext not in (".jpg", ".jpeg", ".png", ".webp", ".gif"):
                ext = ".jpg"
            # Validate the bytes decode as a real image before storing —
            # an extension whitelist alone would let arbitrary content land
            # on disk as a .jpg and reach the downstream visual generator.
            _photo_bytes = photo.read() or b""
            _photo_ok = False
            try:
                import io as _io_img

                from PIL import Image as _PILImg

                with _PILImg.open(_io_img.BytesIO(_photo_bytes)) as _im:
                    _im.verify()
                _photo_ok = True
            except Exception:
                current_app.logger.warning("stub photo upload rejected: not a decodable image")
            if _photo_ok:
                att_dir = UPLOADS_DIR / "stub_attachments"
                att_dir.mkdir(parents=True, exist_ok=True)
                dest = att_dir / f"{_uuid.uuid4().hex[:16]}{ext}"
                try:
                    dest.write_bytes(_photo_bytes)
                    form_data["attached_photo_path"] = str(dest)
                    form_data["attached_photo_filename"] = Path(photo.filename).name
                except Exception:
                    current_app.logger.exception("stub photo upload failed")

        # Media-library picks — strictly profile-scoped. Resolve each
        # selected asset id against the active profile only; foreign ids
        # are silently dropped so a tampered form can't pull another
        # org's photos into this pack.
        active_pid_for_pack = _active_profile_id() or ""
        # Stamp the active profile id on every saved pack so the
        # downstream renderer can resolve the BrandKit + theme
        # JSON. Previously this only happened when the user also
        # picked a library asset, which meant a sponsor / event
        # preview / session-update pack rendered without any
        # brand-driven colours when the user hadn't attached a
        # photo from their library.
        if active_pid_for_pack:
            form_data["profile_id"] = active_pid_for_pack
        selected_ids = request.form.getlist("library_asset_id")
        resolved_assets: list[dict] = []
        if selected_ids and _v8_get_media_store is not None:
            try:
                _ml = _v8_get_media_store()
                for aid in selected_ids:
                    a = _ml.get(aid)
                    if not a:
                        continue
                    if a.profile_id != active_pid_for_pack:
                        continue
                    resolved_assets.append(
                        {
                            "id": a.id,
                            "path": a.path,
                            "filename": a.filename,
                            "type": a.type,
                        }
                    )
            except Exception:
                current_app.logger.exception("stub library picker resolve failed")
        if resolved_assets:
            form_data["library_asset_ids"] = ",".join(r["id"] for r in resolved_assets)
            form_data["library_asset_paths"] = ",".join(r["path"] for r in resolved_assets)
            # Promote the first selected asset into attached_photo_path
            # when the user didn't also upload a one-off file. Downstream
            # visual generators read attached_photo_path as their primary
            # photo source — without this promotion, library picks would
            # show up in the pack metadata but never reach the renderer.
            if not form_data.get("attached_photo_path"):
                form_data["attached_photo_path"] = resolved_assets[0]["path"]
                form_data["attached_photo_filename"] = resolved_assets[0]["filename"]
            form_data["profile_id"] = active_pid_for_pack

        # Event-preview enrichment: read the event's website, the
        # uploaded meet pack, and the entries source so the AI can work
        # out what the event IS and pick ones-to-watch from REAL
        # entries. All best-effort — a dead link or unreadable file
        # is noted in _pv_unread so the results page can say so rather
        # than silently dropping it.
        _pv_unread: list[str] = []
        if stub_cls_name == "WeekendPreviewStub":
            # Resolve the active club up front so the LENEX path can order
            # THIS club's entries first — they must survive truncation on a
            # big multi-club meet.
            _pv_club = ""
            try:
                _pv_prof = _active_profile()
                if _pv_prof is not None:
                    _pv_club = (_pv_prof.display_name or "").strip()
                    form_data["club_name"] = _pv_prof.display_name
            except Exception:
                current_app.logger.exception("event preview: active profile lookup failed")
            try:
                from mediahub.brand.guidelines import extract_text as _doc_text

                def _pv_url_text(_u: str, _cap: int) -> str:
                    """Extract text from a URL, handling BOTH HTML pages and
                    document downloads (PDF / Word / RTF). A psych-sheet or
                    entries link is usually a PDF, which the plain HTML text
                    path reduces to noise — route those through the document
                    extractor instead. SSRF-safe (safe_fetch_bytes pins the
                    validated IP and re-checks every redirect hop)."""
                    from mediahub.web_research.safe_fetch import (
                        html_bytes_to_text as _h2t,
                        safe_fetch_bytes as _sfb,
                    )

                    _got = _sfb(_u, max_bytes=4 * 1024 * 1024, timeout=6.0, max_hops=2)
                    if not _got:
                        return ""
                    _ct, _body = _got
                    _is_pdf = _ct == "application/pdf" or _body[:5] == b"%PDF-"
                    _is_doc = (
                        _is_pdf
                        or "officedocument" in _ct
                        or _ct
                        in (
                            "application/msword",
                            "application/rtf",
                            "text/rtf",
                        )
                    )
                    if _is_doc:
                        from pathlib import Path as _P
                        from urllib.parse import urlparse as _urlp

                        _fn = _P(_urlp(_u).path).name or "download"
                        if _is_pdf and not _fn.lower().endswith(".pdf"):
                            _fn = (_fn or "download") + ".pdf"
                        try:
                            _r = _doc_text(_fn, _body)
                            if _r.get("status") == "ok" and (_r.get("text") or "").strip():
                                return _r["text"][:_cap]
                        except Exception:
                            current_app.logger.exception(
                                "event preview: URL document extract failed"
                            )
                        return ""  # a document we could not read
                    return _h2t(_body, _ct, _cap)

                _site_url = (form_data.get("event_website_url") or "").strip()
                if _site_url:
                    _t = _pv_url_text(_site_url, 8000)
                    if _t:
                        form_data["event_site_text"] = _t
                _entries_url = (form_data.get("entries_url") or "").strip()
                if _entries_url:
                    _t = _pv_url_text(_entries_url, 20000)
                    if _t:
                        form_data["entries_text"] = _t
                for _field, _key, _cap in (
                    ("event_pack", "event_pack_text", 8000),
                    ("entries_file", "entries_text", 20000),
                ):
                    _up = request.files.get(_field)
                    if _up and getattr(_up, "filename", ""):
                        _up_bytes = _up.read() or b""
                        # W.6: LENEX entry files (.lef/.lxf — what meet
                        # organisers actually send) parse structurally,
                        # not as raw text, so the AI sees clean
                        # name/event/entry-time rows.
                        _fn_lower = (_up.filename or "").lower()
                        if _field == "entries_file" and (
                            _fn_lower.endswith((".lef", ".lxf"))
                            or b"<LENEX" in _up_bytes[:2048].upper()
                        ):
                            try:
                                from mediahub.interpreter.lenex_parser import (
                                    parse_lenex_entries,
                                )

                                _rows = parse_lenex_entries(_up_bytes)
                                # Zero-typing goal (W.6): the entry file
                                # already names the meet — use it when
                                # the form field was left blank.
                                if not (form_data.get("meet_name") or "").strip():
                                    try:
                                        from mediahub.interpreter.lenex_parser import (
                                            parse_lenex as _parse_lenex_meet,
                                        )

                                        _ln_meet = _parse_lenex_meet(_up_bytes)
                                        if _ln_meet.meet_name:
                                            form_data["meet_name"] = _ln_meet.meet_name
                                    except Exception:
                                        pass
                                # F8: order the active club's entries first so
                                # the club we are previewing survives the
                                # brief's truncation on a big multi-club meet.
                                if _pv_club and _rows:
                                    _cl = _pv_club.lower()
                                    _rows = sorted(
                                        _rows,
                                        key=lambda _r: (
                                            0 if _cl in (_r.get("club") or "").lower() else 1
                                        ),
                                    )
                                _lines = []
                                for _r in _rows:
                                    _bits = [
                                        _r.get("swimmer_name") or "",
                                        (
                                            f"{_r.get('distance_m') or ''}"
                                            + (f" {_r['stroke']}" if _r.get("stroke") else "")
                                        ).strip(),
                                        _r.get("entry_time") or "",
                                        _r.get("club") or "",
                                    ]
                                    _lines.append(" — ".join(b for b in _bits if b))
                                if _lines:
                                    form_data[_key] = "\n".join(_lines)[:_cap]
                                    continue
                            except Exception:
                                current_app.logger.exception(
                                    "event preview: LENEX entries parse failed"
                                )
                        try:
                            _res = _doc_text(_up.filename, _up_bytes)
                        except Exception:
                            current_app.logger.exception(
                                "event preview: %s extraction failed", _field
                            )
                            continue
                        if _res.get("status") == "ok" and (_res.get("text") or "").strip():
                            form_data[_key] = _res["text"][:_cap]
            except Exception:
                current_app.logger.exception("event preview enrichment failed")
            # F9: note any source the user PROVIDED but we could not read,
            # so the results page can say so instead of silently dropping it.
            if (form_data.get("event_website_url") or "").strip() and not (
                form_data.get("event_site_text") or ""
            ).strip():
                _pv_unread.append("the event website link")
            _ef = request.files.get("entries_file")
            _entries_given = bool(
                (form_data.get("entries_url") or "").strip()
                or (_ef and getattr(_ef, "filename", ""))
            )
            if _entries_given and not (form_data.get("entries_text") or "").strip():
                _pv_unread.append("the entries source")
            _pf = request.files.get("event_pack")
            if (
                _pf
                and getattr(_pf, "filename", "")
                and not (form_data.get("event_pack_text") or "").strip()
            ):
                _pv_unread.append("the meet pack")
            # Reject an empty submission: with no event name, no readable
            # website/pack/entries text, and no typed ones-to-watch, the
            # model would have nothing to ground on and would guess. Ask
            # for a real source instead of generating an ungrounded preview.
            if not stub.has_meaningful_input(form_data):
                return _recovery_page(
                    "Add something to preview",
                    (
                        "Give us at least the event name, or upload the "
                        "entries file, or add the event's website or meet "
                        "pack, so the preview has real facts to work from. "
                        "It never guesses."
                    ),
                    primary_cta=("Back to Event Preview", url_for(route_endpoint)),
                    code=400,
                )
        try:
            cards_payload = stub.generate_cards(form_data)
        except Exception as e:
            current_app.logger.exception("stub generate_cards failed")
            # Show the actual error to the user — no silent fake card, and
            # do NOT fall through to persist an empty pack + a misleading
            # "success" shell with HTTP 200.
            from mediahub.ai_core import (
                ProviderNotConfigured,
                ProviderError,
            )

            if isinstance(e, ProviderNotConfigured):
                return _recovery_page(
                    "AI features unavailable",
                    (
                        "MediaHub needs a Gemini or Anthropic API key "
                        "to generate captions. Ask your deployment "
                        "operator to set GEMINI_API_KEY or "
                        "ANTHROPIC_API_KEY, then try again."
                    ),
                    primary_cta=("Back to Create", url_for("make_page")),
                    secondary_cta=("System status", url_for("status_page")),
                    code=503,
                )
            if isinstance(e, ProviderError):
                return _recovery_page(
                    "AI provider error",
                    (
                        f"The AI provider couldn't finish your draft: "
                        f"{str(e).rstrip('.')}. Rate limits usually clear "
                        "within seconds — try again, or simplify the input."
                    ),
                    primary_cta=("Try again", url_for(route_endpoint)),
                    secondary_cta=("Back to Create", url_for("make_page")),
                    code=502,
                )
            # Any other engine failure (e.g. malformed model JSON): honest
            # error, no empty pack persisted.
            return _recovery_page(
                "Couldn't generate your draft",
                (
                    "Something went wrong while writing the cards. This is "
                    "usually temporary — try again in a moment, or simplify "
                    "the input."
                ),
                primary_cta=("Try again", url_for(route_endpoint)),
                secondary_cta=("Back to Create", url_for("make_page")),
                code=502,
            )
        # Persist this pack so it survives refresh + is exportable.
        saved = None
        try:
            from mediahub.club_platform.stub_pack_store import save_pack

            saved = save_pack(
                _STUB_TYPE_BY_CLASS.get(stub_cls_name, "other"),
                form_data,
                cards_payload.get("cards") or [],
                profile_id=_active_profile_id(),
            )
        except Exception:
            current_app.logger.exception("stub save_pack failed")
        back = url_for(route_endpoint)
        actions_url = url_for("stub_pack_view", pack_id=saved["pack_id"]) if saved else None
        # Wire the per-card approval pill when we have a saved pack_id.
        # The status route is /api/drafts/<pid>/card/<idx>/status, so
        # we strip the trailing "/<idx>/status" (two segments) to give
        # render_cards_html a base it can append "/<idx>/status" to.
        _pack_id = saved["pack_id"] if saved else None
        _status_api_base = None
        _graphic_api_base = None
        if _pack_id:
            _full = url_for("api_stub_pack_card_status", pack_id=_pack_id, card_idx=0)
            _status_api_base = _full.rsplit("/", 2)[0]
            # Same strip trick for the create-graphic base: render_cards_html
            # appends "/<idx>/create-graphic" itself.
            _full_g = url_for("api_stub_pack_create_graphic", pack_id=_pack_id, card_idx=0)
            _graphic_api_base = _full_g.rsplit("/", 2)[0]
        body = _stubs_mod.render_cards_html(
            cards_payload,
            back,
            f"{title} — drafts",
            pack_id=_pack_id,
            status_api_base=_status_api_base,
            graphic_api_base=_graphic_api_base,
        )
        if saved:
            _packs_url = url_for("stub_packs_list")
            _new_body = body.replace(
                f'<a class="btn secondary" href="{_h(back)}">← Start over</a>',
                (
                    f'<a class="btn" href="{_h(actions_url)}">View &amp; export this pack →</a>'
                    f'<a class="btn secondary" href="{_h(back)}">← Start over</a>'
                    f'<a class="btn secondary" href="{_h(_packs_url)}">All saved drafts</a>'
                ),
                1,
            )
            if _new_body == body:
                # The anchor is render_cards_html's exact markup; if it
                # drifts this replace silently no-ops (PR-118 regression
                # class) — make the miss loud so it can't ship unnoticed.
                log.warning(
                    "stub POST: 'Start over' anchor not found — render_cards_html "
                    "markup drifted; View-&-export actions were not injected"
                )
            body = _new_body
        # F9: if the user provided a source we could not read, say so on
        # the results page rather than silently building the preview
        # without it. Only shown when cards were actually generated.
        if _pv_unread and (cards_payload.get("cards") or []):
            if len(_pv_unread) == 1:
                _srcs, _it = _pv_unread[0], "it"
            else:
                _srcs = ", ".join(_pv_unread[:-1]) + " and " + _pv_unread[-1]
                _it = "them"
            _notice = (
                '<div role="status" style="margin-bottom:16px;padding:12px 14px;'
                "border:1px solid rgba(255,180,84,0.45);border-radius:8px;"
                "background:rgba(255,180,84,0.08);font-size:13px;line-height:1.5;"
                'color:var(--ink)">'
                f"We couldn&rsquo;t read {_h(_srcs)}, so the preview was built without "
                f"{_it}. For entries, the organiser&rsquo;s LENEX (.lef / .lxf) export "
                "or a pasted list reads most reliably.</div>"
            )
            body = _notice + body
        if _graphic_api_base:
            body += _VISUAL_PANEL_JS
        return _layout(title, body, active=active_tab)
    # GET &mdash; render hero + form
    _how_html = ""
    if intro_ct:
        _how_html = (
            '<p style="margin:0 0 var(--sp-4)">'
            f'<a class="mh-how-pill" href="{url_for("content_type_intro", ct=intro_ct)}">'
            "How it works</a></p>"
        )
    body = _stub_hero(title) + _how_html + _llm_unavailable_banner() + stub.render_stub_html()
    # Inject the "Pick from your library" widget. The form-level photo
    # upload (stubs._PHOTO_INPUT_HTML) handles one-off uploads; this
    # picker pulls from the active organisation's library so the user
    # doesn't have to re-upload assets they already saved.
    picker_html = _render_library_picker_for_active_profile()
    if picker_html:
        body = body.replace(
            "Leave blank to use a library photo or no photo.</p></div>",
            "Or pick one from your library below.</p></div>" + picker_html,
            1,
        )
    try:
        _packs_url = url_for("stub_packs_list")
        body += (
            f'<p style="margin-top:var(--sp-5);display:flex;gap:var(--sp-4);flex-wrap:wrap">'
            f'<a href="{_packs_url}">View your saved drafts &rarr;</a>'
            f'<a href="{url_for("make_page")}">&larr; All input types</a>'
            f"</p>"
        )
    except Exception:
        body += f'<p style="margin-top:var(--sp-5)"><a href="{url_for("make_page")}">&larr; All input types</a></p>'
    return _layout(title, body, active=active_tab)


def _active_club_brand_for_llm() -> Optional[dict]:
    """Build the brand context the free-text agent + spotlight writer
    share. Returns None when there's no active org so callers can
    fall through to the unbranded system prompt cleanly. Includes
    the effective palette so the LLM can ground colour references
    ("wear the navy", "lean into the gold") in the actual brand."""
    prof = _active_profile()
    if prof is None:
        return None
    try:
        from mediahub.brand.palette import effective_palette as _eff

        eff = _eff(
            manual=prof.brand_palette_manual or {},
            extracted=prof.brand_palette_extracted or {},
        )
    except Exception:
        eff = {}
    return {
        "name": (prof.display_name or "").strip(),
        "short_name": (prof.short_name or "").strip(),
        "org_type": (prof.org_type or "").strip(),
        "tone": (prof.tone or "").strip(),
        "tone_notes": (prof.tone_notes or "").strip(),
        "exemplars": list(prof.exemplar_captions or [])[:6],
        "sponsor_name": (prof.sponsor_name or "").strip(),
        "sponsor_rules": (prof.sponsor_guidelines or "").strip(),
        "voice_summary": (prof.brand_voice_summary or "")[:600],
        "keywords": list(prof.brand_keywords or [])[:8],
        "phrases_to_use": list(prof.brand_phrases_to_use or [])[:6],
        "phrases_to_avoid": list(prof.brand_phrases_to_avoid or [])[:6],
        "palette": eff,
    }


def _assemble_spotlight_reel_inputs(pack_id: str, rec: dict):
    """Reel inputs for an athlete-spotlight composite: the swimmer's
    APPROVED moments (a subset of the real run), shaped exactly like
    ``_assemble_reel_inputs`` so ``render_meet_reel`` consumes them
    unchanged. Returns ``(inputs, None)`` or ``(None, (resp, status))``.
    Runs off the REAL run (the approved moments are real cards in it), so
    there is no synthetic-run access trap.
    """
    from mediahub.visual import motion as _motion
    from mediahub.club_platform.athlete_spotlight import build_spotlight_pack

    fd = (rec or {}).get("form_data") or {}
    # Type guard, mirroring api_stub_pack_caption / _caption_assist: only a
    # genuine athlete-spotlight pack drives this reel. A non-spotlight pack
    # that happened to carry run_id + swimmer_key would otherwise slip
    # through on presence alone.
    if fd.get("source") != "athlete_spotlight":
        return None, (jsonify({"error": "unsupported_type"}), 400)
    run_id = str(fd.get("run_id") or "")
    swimmer_key = str(fd.get("swimmer_key") or "")
    if not run_id or not swimmer_key:
        return None, (jsonify({"error": "spotlight_context_missing"}), 400)
    run_data = _load_run(run_id)
    if run_data is None:
        return None, (jsonify({"error": "run_not_found"}), 404)
    # Tenant isolation, mirroring _compose_spotlight_caption: the pack owns
    # the access check for its own row, but the run it names is a separate
    # object — never render another org's run just because the pack points
    # at it.
    if not _can_access_run(run_id, run_data, _active_profile_id()):
        return None, (jsonify({"error": "run_not_found"}), 404)
    try:
        pack = build_spotlight_pack(run_data, swimmer_key)
    except Exception as e:
        return None, (jsonify({"error": f"spotlight_pack_failed: {e}"}), 500)
    if not pack:
        return None, (jsonify({"error": "swimmer_not_found"}), 404)

    # Approved/posted moments only — the SAME selection the composite
    # caption uses (see `_compose_spotlight_caption`): the reviewer hand-
    # picks which moments go in the post by approving them.
    wf_states = {}
    try:
        ws = _get_wf_store()
        if ws:
            wf_states = ws.load(run_id)
    except Exception:
        wf_states = {}
    # F11: key on the same unique ~n-deduped ids the spotlight review approves
    # under (a duplicate swim_id's twin is read independently). Non-duplicate
    # runs key exactly as before.
    _sp_reel_ids = _unique_card_ids(
        pack.get("ranked_achievements") or [], base_fn=_card_base_id_for
    )
    approved = []
    for _i, ra in enumerate(pack.get("ranked_achievements") or []):
        st = wf_states.get(_sp_reel_ids[_i])
        if st and getattr(getattr(st, "status", None), "value", "") in ("approved", "posted"):
            approved.append(ra)
    if not approved:
        return None, (jsonify({"error": "no_approved_moments"}), 404)

    fmt = (request.args.get("format") or _motion.DEFAULT_MOTION_FORMAT).strip().lower()
    if fmt not in _motion.MOTION_FORMATS:
        return None, (
            jsonify({"error": "bad_format", "valid_formats": sorted(_motion.MOTION_FORMATS)}),
            400,
        )

    meet_name = pack.get("meet_name") or ""
    cards: list[dict] = []
    for ra in approved[:5]:
        ach = ra.get("achievement") or {}
        cards.append(
            {
                "id": ach.get("swim_id") or ra.get("id") or "",
                "swim_id": ach.get("swim_id") or "",
                "achievement": ach,
                "meet_name": meet_name,
            }
        )
    n = len(cards)
    rhythm = _motion.normalise_reel_rhythm({}, n)

    prof = _active_profile()
    try:
        brand_kit = (
            prof.get_brand_kit()
            if prof is not None
            else (_v8_brand_kit_for(f"_stub_{pack_id}") if _v8_ok else None)
        )
    except Exception:
        brand_kit = _v8_brand_kit_for(f"_stub_{pack_id}") if _v8_ok else None

    sponsor_name = ""
    try:
        if prof is not None:
            from mediahub.club_platform.sponsors import active_sponsors

            actives = active_sponsors(prof)
            if actives:
                sponsor_name = str(actives[0].get("name") or "").strip()
            if not sponsor_name:
                sponsor_name = str(getattr(prof, "sponsor_name", "") or "").strip()
    except Exception:
        sponsor_name = ""

    slug = re.sub(r"[^a-z0-9]+", "-", swimmer_key.lower()).strip("-") or "spotlight"
    out_dir = RUNS_DIR / run_id / "motion"
    out_dir.mkdir(parents=True, exist_ok=True)
    out_path = out_dir / (
        f"spotlight_{slug}_{n}.mp4" if fmt == "story" else f"spotlight_{slug}_{n}_{fmt}.mp4"
    )

    return (
        {
            "n": n,
            "format": fmt,
            "cards": cards,
            "brand_kit": brand_kit,
            "out_path": out_path,
            "meet_name": meet_name,
            "briefs": [None] * len(cards),
            "rhythm": rhythm,
            "sponsor": sponsor_name,
            "run_id": run_id,
            "slug": slug,
        },
        None,
    )


def _resolved_kit_for_run(run_id: str, run_data=None):
    """The brand kit the pipeline applies to this run.

    H-13: prefers the kit the user chose on the configure step
    (``brand_kit_id`` persisted with the run's brand-kit config in
    ``data/brand_kits/<run_id>.json``). An absent, empty, or since-deleted
    id falls back to the org's default kit via ``resolve_kit_for``, so
    runs recorded before the chooser existed behave exactly as before.

    Returns (profile, kit) or (None, None) when no profile resolves.
    """
    run_data = run_data if run_data is not None else (_load_run(run_id) or {})
    profile_id = run_data.get("profile_id", "")
    prof = load_profile(profile_id) if profile_id else _active_profile()
    if prof is None:
        return None, None
    from mediahub.brand import kits as _kits

    chosen_kit_id = ""
    try:
        _kit_path = DATA_DIR / "data" / "brand_kits" / f"{run_id}.json"
        if _kit_path.exists():
            chosen_kit_id = str(
                (json.loads(_kit_path.read_text()) or {}).get("brand_kit_id") or ""
            ).strip()
    except Exception:
        chosen_kit_id = ""

    return prof, _kits.resolve_kit_for(prof, kit_id=chosen_kit_id or None)


def _run_role(run_id: str, run_data=None) -> str:
    """The actor's collaboration role *in the run's owning org* (1.18).

    Run-scoped on purpose: a sign-off/edit is judged against who owns the
    run, not whatever org is pinned in the session. Ownerless/legacy runs
    and unbound (pilot) orgs resolve to the owner seat — the same permissive
    behaviour the run-access gate already grants those sessions, so nothing
    changes for pilots or pre-1.18 workspaces.
    """
    owner_pid = _run_owner_id(run_id, run_data)
    if not owner_pid:
        return _tenancy.ROLE_OWNER
    return _active_role(owner_pid)


def _imagine_role_ok(pid: str) -> bool:
    """Governance (1.23): may the actor's role use generative imagery?

    Editor+ on a bound org; pilot orgs and the operator keep the owner seat,
    so their flow is unchanged. Deterministic ops (subject-lift, grab-text)
    spend no AI budget and are not gated here.
    """
    from mediahub.governance import features as _gf, permissions as _gp

    return _gp.can_use_feature(_active_role(pid), _gf.FEATURE_IMAGINE, plan=_auth.current_plan())


def _imagine_forbidden(pid: str):
    from mediahub.governance import features as _gf, permissions as _gp

    return (
        jsonify(
            {
                "error": "forbidden",
                "user_message": _gp.denial_reason(
                    _active_role(pid), _gf.FEATURE_IMAGINE, plan=_auth.current_plan()
                ),
            }
        ),
        403,
    )


def _profile_accent_hex():
    """Best-effort brand accent for tinting mockup scenes (None if unknown).

    Goes through ``get_brand_kit()`` so the manual/extracted palette
    resolution applies — the raw ``brand_kit`` dict keys are
    ``*_colour``, and reading them directly missed every profile.
    """
    try:
        prof = _active_profile()
        if prof is None:
            return None
        kit = prof.get_brand_kit()
        val = getattr(kit, "accent_colour", None) or getattr(kit, "primary_colour", None)
        if isinstance(val, str) and val.strip():
            return val.strip()
    except Exception:
        pass
    return None


def _photo_editor_asset(asset_id: str):
    """Resolve + tenancy-check an asset for the editor. Returns (asset, store, error_response)."""
    if not _v8_ok:
        return None, None, (jsonify({"error": "v8_unavailable"}), 503)
    store = _v8_get_media_store()
    a = store.get(asset_id)
    if not a:
        return None, None, (jsonify({"error": "not_found"}), 404)
    if not _session_can_access_profile(a.profile_id):
        return None, None, (jsonify({"error": "forbidden"}), 403)
    return a, store, None


def _print_resolve(run_id: str):
    """Resolve + access-gate a run for the print routes.

    Returns ``(run_data, profile_id, None)`` on success, else
    ``(None, None, (response, status))`` to short-circuit.
    """
    run_data = _run_data_any(run_id)
    if run_data is None or not _can_access_run(run_id, run_data, _active_profile_id()):
        return None, None, (jsonify({"error": "run_not_found"}), 404)
    profile_id = _assistant_profile_id(run_id, run_data)
    if not _session_can_access_profile(profile_id):
        return None, None, (jsonify({"error": "forbidden"}), 403)
    return run_data, profile_id, None


def _charts_candidates_for(run_id: str):
    """``(ctx, candidates, None)`` or ``(None, None, error)``."""
    # Deliberate shadow: mediahub.charts (engine), NOT this package's .charts
    # (the module-level _charts alias, kept for the carved surfaces).
    from mediahub import charts as _charts  # noqa: F811

    ctx, err = _charts_run_context(run_id)
    if err is not None:
        return None, None, err
    records = None
    try:
        from mediahub.club_records import list_records

        records = list_records(ctx["profile_id"]) if ctx["profile_id"] else None
    except Exception:
        records = None
    cands = _charts.build_chart_candidates(ctx["run_data"], records=records)
    return ctx, cands, None


def _video_brand_colours():
    """Brand colours for caption/pad styling — the SAME resolved role set
    the motion path paints (M28).

    Runs the motion engine's APCA-gated bookend resolver
    (``motion._cover_brand_roles`` — the graphic_renderer's single role
    resolver over the brand palette: Tier A baseline, contrast-picked
    on-colours, no invented hex) so the Video Studio's captions and pad
    colour can never disagree with the club's approved cards. Falls back
    to the legacy accent-only pairing when no brand resolves — defaults
    stay legible either way.
    """
    from mediahub.video.clip_maker import BrandColours

    background = "#0A0A0A"
    brand_kit = _video_brand_kit()
    if brand_kit is not None:
        try:
            from mediahub.visual.motion import _brand_to_dict, _cover_brand_roles

            brand_dict = _brand_to_dict(brand_kit)
            roles = _cover_brand_roles(brand_dict, brand_kit)
            if roles.get("ground") and roles.get("onGround"):
                return BrandColours(
                    ground=roles["ground"],
                    onground=roles["onGround"],
                    accent=roles.get("accent") or "",
                    background=roles["ground"],
                )
        except Exception:
            pass
    prof = _active_profile()
    accent = ""
    for attr in ("accent_colour", "accent", "primary_colour", "primary"):
        val = getattr(prof, attr, "") if prof else ""
        if isinstance(val, str) and val.startswith("#"):
            accent = val
            break
    return BrandColours(ground="", onground="", accent=accent, background=background)


def _doc_club_name(pid, brand_kit) -> str:
    name = getattr(brand_kit, "display_name", "") or ""
    if name:
        return name
    try:
        prof = _active_profile()
    except Exception:
        prof = None
    return getattr(prof, "display_name", "") or getattr(prof, "name", "") or ""


def _editorial_ai_gate(pid: str):
    """1.23 governance for AI editorial drafting (newsletters/documents):
    the same permission + quota pattern as captions, under the caption
    feature key (editorial drafts are metered AI copy, like captions).
    Returns an error response to send, or None when allowed. The signed-in
    operator is exempt (no gate, no metering)."""
    from mediahub.governance import (
        features as _gov_features,
        permissions as _gov_perms,
        quota as _gov_quota,
    )

    org = "" if _auth.is_dev_operator() else (pid or "")
    if not org:
        return None
    plan = _auth.current_plan()
    if not _gov_perms.can_use_feature(_active_role(org), _gov_features.FEATURE_CAPTION, plan=plan):
        return jsonify(
            {
                "ok": False,
                "error": "forbidden",
                "message": _gov_perms.denial_reason(
                    _active_role(org), _gov_features.FEATURE_CAPTION, plan=plan
                ),
            }
        ), 403
    try:
        _gov_quota.enforce(org, _gov_features.FEATURE_CAPTION, plan=plan)
    except _gov_quota.QuotaExceeded as qe:
        return jsonify({"ok": False, "error": "quota_reached", "message": str(qe)}), 429
    return None


def _brand_lock_block_reason(run_id: str, card_id: str):
    """A locked-token brand violation that blocks approval, or None.

    Opt-in governance: only fires when the run's resolved kit has locked
    tokens (palette / fonts / logo) AND the card's brief fails one of those
    exact tokens. A kit with no locks → None, so every existing club's
    approval flow is byte-identical. Never raises — a check error never
    blocks a human approving their own content.
    """
    try:
        run_data = _load_run(run_id) or {}
        prof, kit = _resolved_kit_for_run(run_id, run_data)
        if prof is None or kit is None or not kit.locks:
            return None
        brief_dict = _latest_brief_for_card(run_id, card_id)
        if not brief_dict:
            return None
        from mediahub.brand.check import check_brief
        from mediahub.creative_brief.generator import CreativeBrief

        brand_kit = _resolve_run_brand_kit(run_data.get("profile_id", ""), run_id, run_data)
        report = check_brief(CreativeBrief.from_dict(brief_dict), kit, brand_kit=brand_kit)
        blocking = [f for f in report.findings if not f.passed and f.check in kit.locks]
        if not blocking:
            return None
        checks = ", ".join(f.check for f in blocking)
        return (
            f"This card is off-brand on the kit's locked token(s): {checks}. "
            "Use Brand Assist auto-fix or edit the design before approving."
        )
    except Exception:
        return None


def _group_approval_block(
    run_id: str, card_id: str, *, actor_email=None, is_operator=None, actor_kind="human"
):
    """Record the current user's approval vote and evaluate the kit's
    group-approver rule. Returns (blocked, info_dict).

    ``blocked`` is True when more approvals are still required — the card is
    held in QUEUE. Default-safe: no rule, an unbound (pilot) workspace, or
    the operator → never blocks. ``info_dict`` carries the pending detail
    for the response/UI (1.18 renders it richly).

    ``actor_email`` / ``is_operator`` default to the session identity (the
    web route's behaviour, byte-identical), but the public API passes the
    token's owner so an API approval is recorded as that person's vote and
    the same group rule is enforced — never bypassed. ``actor_kind``
    (finding #116) marks a public-API/MCP vote as ``"api_token"`` so the
    group-approval trail distinguishes an agent from a human; it does not
    change how votes are counted.
    """
    try:
        prof, kit = _resolved_kit_for_run(run_id)
        if prof is None or kit is None:
            return False, {}
        from mediahub.workflow import governance as _gov

        if not _gov.rule_is_active(kit.approver_rule):
            return False, {}
        pid = prof.profile_id
        store = _tenancy.MembershipStore()
        # Group rules only apply to bound (members-only) workspaces; a pilot
        # workspace is a single trust domain with no distinct approvers.
        if not store.is_bound(pid):
            return False, {}
        # The operator is the super-admin and can always finalise.
        if is_operator if is_operator is not None else _auth.is_dev_operator():
            return False, {}
        email = actor_email if actor_email is not None else (_auth.current_user_email() or "")
        ledger = _get_approval_ledger()
        if ledger is None:
            return False, {}
        approvers = ledger.record(run_id, card_id, email, actor_kind=actor_kind)
        owner_emails = [
            m.email
            for m in store.list_for_profile(pid)
            if m.role == _tenancy.ROLE_OWNER and m.status == _tenancy.STATUS_ACTIVE
        ]
        # 1.18 per-type rule: a sensitive card (safeguarding / sponsor) can
        # demand a stricter sign-off than the base rule; ordinary cards
        # inherit the base.
        content_type = _card_content_type(run_id, card_id)
        satisfied, still_needed, reason = _gov.evaluate_for_type(
            kit.approver_rule,
            content_type,
            approver_emails=approvers,
            owner_emails=owner_emails,
        )
        if satisfied:
            return False, {"approvals": approvers, "content_type": content_type}
        return True, {
            "pending_approval": True,
            "approvals": approvers,
            "approvals_needed": still_needed,
            "reason": reason,
            "content_type": content_type,
        }
    except Exception:
        return False, {}


def _run_actor_can(capability: str, run_id: str, run_data=None) -> bool:
    return _perms.can(_run_role(run_id, run_data), capability)


def _role_denied_json(capability: str, run_id: str, run_data=None):
    """A 403 JSON refusal when the actor's role in the run's owning org
    lacks ``capability``, else ``None`` (1.18). Default-safe: the operator,
    ownerless/legacy runs, and any unbound/pilot org resolve to the owner
    seat, so this never fires for them — it only bites a narrowed seat
    (Viewer/Reviewer/Editor/…) on a members-only workspace, matching the
    anti-enumeration JSON shape the consent/brand gates already use."""
    role = _run_role(run_id, run_data)
    if _perms.can(role, capability):
        return None
    verb = {
        _perms.CAP_EDIT: "edit content",
        _perms.CAP_APPROVE: "approve or reject content",
        _perms.CAP_COMMENT: "comment",
        _perms.CAP_MANAGE: "manage this workspace",
    }.get(capability, capability)
    return (
        jsonify(
            {
                "error": "forbidden",
                "reason": f"Your role ({_perms.role_label(role)}) can't {verb}.",
            }
        ),
        403,
    )


def _brand_check_context(run_id: str, card_id: str):
    """Resolve (brief, kit, brand_kit) for a card, or an error response."""
    # A run_id longer than the OS filename limit makes _load_run's p.exists()
    # raise OSError(ENAMETOOLONG) (it stats outside its own try/except), which
    # would 500 and log the internal RUNS_DIR path. Treat any such unusable
    # id as a missing run — the anti-IDOR 404 the rest of this gate returns.
    try:
        run_data = _load_run(run_id)
    except OSError:
        return None, (jsonify({"error": "run_not_found"}), 404)
    if run_data is None:
        return None, (jsonify({"error": "run_not_found"}), 404)
    if not _can_access_run(run_id, run_data, _active_profile_id()):
        # Anti-IDOR house norm: a foreign run answers exactly like a
        # missing one, so a probe can't confirm the run id exists.
        return None, (jsonify({"error": "run_not_found"}), 404)
    brief_dict = _latest_brief_for_card(run_id, card_id)
    if not brief_dict:
        return None, (jsonify({"error": "no_brief"}), 404)
    from mediahub.creative_brief.generator import CreativeBrief

    # H-13: one resolver — the check must judge the card against the same
    # kit the approval gate (_brand_lock_block_reason) enforces, i.e. the
    # kit chosen for this run, not unconditionally the org default.
    prof, kit = _resolved_kit_for_run(run_id, run_data)
    if prof is None:
        return None, (jsonify({"error": "no_profile"}), 404)
    brief = CreativeBrief.from_dict(brief_dict)
    brand_kit = _resolve_run_brand_kit(run_data.get("profile_id", ""), run_id, run_data)
    return (brief, kit, brand_kit, prof), None


def _doc_facts_for(pid, brand_kit, *, scope, run_id):
    from mediahub.documents.grounding import facts_from_run, facts_from_runs

    club = _doc_club_name(pid, brand_kit)
    if scope == "meet":
        run_data = _load_run(run_id)
        if run_data is None or not _can_access_run(run_id, run_data, pid):
            return None
        return facts_from_run(run_data, club_name=club, run_id=run_id)
    # season scope — every processed run for the org
    runs, ids = [], []
    for rid, _name, _n in _doc_recent_runs(pid):
        rd = _load_run(rid)
        if rd is not None and _can_access_run(rid, rd, pid):
            runs.append(rd)
            ids.append(rid)
    if not runs:
        return None
    return facts_from_runs(runs, club_name=club, period=time.strftime("%Y"), run_ids=ids)


def _api_card_action(profile_id, run_id, card_id, action, payload):
    """Apply a workflow action for the public API, mirroring the session
    route's gate sequence exactly (authorised upstream by token scope, not
    session role). Parity is guarded by tests/test_api_public_endpoints.py."""
    from mediahub.workflow.status import CardStatus

    run_data = _load_run(run_id)
    if not run_data or (run_data.get("profile_id") or "") != (profile_id or ""):
        return {"error": "not_found", "message": "No such run."}, 404
    ws = _get_wf_store()
    if ws is None:
        return {"error": "unavailable", "message": "Workflow not available."}, 503
    actor_email = payload.get("_actor_email") or ""
    # Finding #116: the machine-distinguishable audit label for this
    # public-API/MCP action (e.g. "api-token:<id>"), stamped onto the
    # durable workflow state and the approval telemetry.
    actor = payload.get("_actor") or ""

    if action == "set_status":
        status_str = payload.get("status", "queue")
        try:
            status = CardStatus(status_str)
        except (ValueError, NameError):
            return {"error": "bad_request", "message": f"invalid status: {status_str}"}, 400
        # F11: content-resolving gates key on the shared base id (a ~n twin is
        # the same athlete/swim/design), so a twin approved by its unique id
        # can't slip past consent. Non-duplicate cards: base == card_id.
        _content_card_id = _base_card_id(card_id)
        # Consent gate — the legal/safeguarding rule; identical to the route.
        if status in (CardStatus.APPROVED, CardStatus.POSTED):
            from mediahub.compliance.gate import (
                consent_block_reason_for_card,
                find_card_in_run,
            )

            card = find_card_in_run(run_data, _content_card_id)
            reason = consent_block_reason_for_card(run_data.get("profile_id", ""), card)
            if reason:
                return {"error": "consent_blocked", "message": reason}, 403
        # Brand-lock gate.
        if status in (CardStatus.APPROVED, CardStatus.POSTED):
            brand_reason = _brand_lock_block_reason(run_id, _content_card_id)
            if brand_reason:
                return {"error": "brand_locked", "message": brand_reason}, 403
        # Open-review-task gate.
        if status == CardStatus.APPROVED:
            task_reason = _open_tasks_block_reason(run_id, _content_card_id)
            if task_reason:
                return {"error": "tasks_open", "message": task_reason}, 403
        # Group-approval rule — recorded under the token owner's identity,
        # but marked api_token so the vote trail shows it came via an agent.
        if status == CardStatus.APPROVED:
            held, info = _group_approval_block(
                run_id,
                card_id,
                actor_email=actor_email,
                is_operator=False,
                actor_kind="api_token",
            )
            if held:
                return {"ok": True, "status": "queue", **info}, 200
        if status in (CardStatus.REJECTED, CardStatus.QUEUE):
            _led = _get_approval_ledger()
            if _led is not None:
                _led.clear(run_id, card_id)
        ws.set_status(run_id, card_id, status, notes=payload.get("notes"), actor=actor)
        if status in (CardStatus.APPROVED, CardStatus.REJECTED, CardStatus.QUEUE):
            _action = {
                CardStatus.APPROVED: "approved",
                CardStatus.REJECTED: "rejected",
                CardStatus.QUEUE: "requeued",
            }[status]
            _phase_w_after_status_change(
                profile_id, run_id, card_id, _action, via="api", actor=actor
            )
        return {"ok": True, "status": status_str, "summary": ws.summary(run_id)}, 200

    if action == "set_edits":
        edits = payload.get("edits", {})
        if isinstance(edits, dict) and edits:
            try:
                from mediahub.collab import locks as _locks

                _locked = _locks.locked_elements(run_id, card_id)
                if _locked:
                    _insp_element = {
                        "insp.hideSponsor": "sponsor",
                        "insp.noPhoto": "photo",
                        "insp.focus": "photo",
                        "insp.accent": "accent",
                    }
                    edits = {k: v for k, v in edits.items() if _insp_element.get(k) not in _locked}
            except Exception:
                pass
        ws.set_edits(run_id, card_id, edits, actor=actor)
        _phase_w_after_status_change(profile_id, run_id, card_id, "edited", via="api", actor=actor)
        try:
            cur_state = ws.load(run_id).get(card_id)
            cur_status = cur_state.status if cur_state else CardStatus.QUEUE
            if cur_status == CardStatus.QUEUE:
                ws.set_status(run_id, card_id, CardStatus.EDITED, actor=actor)
        except Exception:
            pass
        return {"ok": True, "status": "edited"}, 200

    return {"error": "bad_request", "message": "unknown action"}, 400


