def create_app() -> Flask:
    # Fail-fast env validation (security/secrets-and-config): production
    # refuses to boot with unsafe config (no DATA_DIR, weak operator key,
    # malformed provider keys) instead of running degraded.
    from mediahub.web.env_check import validate_environment

    _setup_app_logging()
    validate_environment()

    # One-time legacy-secrets cleanup at startup. This scrub used to run on
    # every load_profile / list_profiles call — an uncached secrets.json read
    # per call, on the hot active-profile path. The withdrawn token keys are
    # never written at runtime, so a single scrub per boot is sufficient.
    _scrub_legacy_secrets_file()

    # Python's mimetypes database omits font/woff2 on some Linux systems,
    # causing Flask to serve .woff2 as application/octet-stream and browsers
    # to treat it as a download rather than loading it as a font.
    mimetypes.add_type("font/woff2", ".woff2")

    app = Flask(__name__)
    app.config["MAX_CONTENT_LENGTH"] = 50 * 1024 * 1024  # 50 MB (meet exports, images, PDFs)
    # Let the browser hold static assets (self-hosted fonts, fonts.css, the UI
    # kit) instead of revalidating each with a conditional GET on every single
    # navigation. Every mutable, behaviour-bearing asset — ui-kit.js and the
    # other page JS (offline-queue / pwa-install / mobile-capture / print_center
    # / bulk_export) plus fonts.css — carries a per-file content-hash `?v=`
    # cache-buster (see _static_ver) so a deploy still lands instantly; the woff2
    # faces are effectively immutable. Routes that must stay fresh (sw.js,
    # generated previews) set their own Cache-Control, which overrides this.
    app.config["SEND_FILE_MAX_AGE_DEFAULT"] = 604800  # 7 days
    app.url_map.strict_slashes = False

    # Carved route surfaces (finding #15 stage 4): importable modules that
    # register with their ORIGINAL endpoint names (url_for targets,
    # request.endpoint keying and the gate exemption sets depend on them).
    from mediahub.web import (
        routes_api_misc,
        routes_api_runs,
        routes_auth,
        routes_creative,
        routes_media_library,
        routes_operator,
        routes_organisation,
        routes_planner,
        routes_review,
        routes_site,
        routes_video,
    )

    routes_api_runs.register(app)
    routes_media_library.register(app)
    routes_organisation.register(app)
    routes_video.register(app)
    routes_site.register(app)
    routes_auth.register(app)
    routes_operator.register(app)
    routes_creative.register(app)
    routes_planner.register(app)
    routes_api_misc.register(app)
    routes_review.register(app)

    # ---- Web hardening (security/web-hardening, THREAT_MODEL §6) --------
    # Security headers on every response + CSRF protection on state-changing
    # form posts. JSON POSTs are exempt by content-type (a cross-site form
    # cannot send application/json without a CORS preflight), webhooks are
    # exempt by signature verification, and the public wall embed keeps its
    # frame permissions. Enforcement follows the ENFORCE_LOGIN_IDLE pattern:
    # on in production, opt-in under TESTING via ENFORCE_CSRF so the large
    # form-posting test corpus doesn't need a token each.

    app.before_request(_csrf_protect)

    app.after_request(_security_headers)

    # Persistent SECRET_KEY &mdash; survives restarts and redeploys.
    # Priority: env var > persisted file > generated + saved.
    _secret = os.environ.get("SECRET_KEY", "")
    if not _secret:
        _persistent_path = DATA_DIR / ".secret_key"
        if _persistent_path.exists():
            try:
                _secret = _persistent_path.read_text().strip()
            except OSError:
                pass
        if not _secret:
            _secret = os.urandom(32).hex()
            try:
                _persistent_path.write_text(_secret)
                # SECRET_KEY signs session cookies — anyone who can
                # read this file can forge sessions. Restrict to the
                # owner so a co-tenant on a shared host can't trivially
                # impersonate the operator.
                try:
                    os.chmod(_persistent_path, 0o600)
                except OSError:
                    pass
            except OSError:
                pass  # writable fallback not available; sessions won't survive restart
        # Tighten perms on a pre-existing key file too — a previous
        # release wrote it with the umask default (0644).
        try:
            if _persistent_path.exists():
                os.chmod(_persistent_path, 0o600)
        except OSError:
            pass
    app.config["SECRET_KEY"] = _secret

    # ---- Session cookie hardening (PC.1) -------------------------------
    # The session cookie carries the signed-in user's identity (auth.py),
    # so lock it down. It is already cryptographically *signed* by the
    # SECRET_KEY above. Make it HttpOnly (JS can't read it → XSS can't
    # steal the session) and SameSite=Lax (CSRF defence-in-depth while
    # still allowing top-level navigation). Mark it Secure (HTTPS-only)
    # on real deployments — Render terminates TLS — but never under TESTING
    # or local HTTP dev, where a Secure cookie would simply be dropped and
    # break login. The operator can force it on/off with
    # MEDIAHUB_SESSION_COOKIE_SECURE=1/0.
    app.config["SESSION_COOKIE_HTTPONLY"] = True
    app.config["SESSION_COOKIE_SAMESITE"] = "Lax"
    _secure_env = os.environ.get("MEDIAHUB_SESSION_COOKIE_SECURE", "").strip().lower()
    if _secure_env in ("1", "true", "yes", "on"):
        _cookie_secure = True
    elif _secure_env in ("0", "false", "no", "off"):
        _cookie_secure = False
    else:
        # Default: Secure on when an HTTPS-fronted deployment is detected
        # (Render sets RENDER / a public URL), off otherwise so HTTP dev works.
        _cookie_secure = bool(
            os.environ.get("RENDER")
            or (os.environ.get("RENDER_EXTERNAL_URL", "").startswith("https://"))
        )
    app.config["SESSION_COOKIE_SECURE"] = _cookie_secure

    # Apply SCRIPT_NAME middleware so url_for generates prefixed URLs when
    # running behind a reverse-proxy that mounts the app at a sub-path
    # (e.g. the pplx.app dev environment serves us under /port/5000/...).
    # Default is empty so production deployments — including Render —
    # generate clean root-relative URLs. Set SCRIPT_NAME=/port/5000 in
    # dev to restore the old behaviour.
    _script_name = os.environ.get("SCRIPT_NAME", "").rstrip("/")
    if _script_name:
        _real_wsgi = app.wsgi_app

        def _script_name_middleware(environ, start_response):
            environ["SCRIPT_NAME"] = _script_name
            path_info = environ.get("PATH_INFO", "")
            if path_info.startswith(_script_name):
                environ["PATH_INFO"] = path_info[len(_script_name) :] or "/"
            return _real_wsgi(environ, start_response)

        app.wsgi_app = _script_name_middleware  # type: ignore[assignment]

    # ---- PC.3 workspace binding (ADR-0014) ------------------------------
    # An org with ≥1 ACTIVE membership is "bound" — members-only at every
    # pinning/editing surface. An org with zero active memberships behaves
    # exactly as it always has (standalone/pilot mode), so deployments with
    # no accounts are untouched. The env-gated operator bypasses all gates.

    # A profile persisted mid-request must drop its cached copy, or a later
    # read in the same request (tenant gating included) would see stale data.
    # Registering the hook here covers every save_profile() call automatically,
    # without threading invalidation through each caller. The few routes that
    # write a profile another way (save_brand, the delete routes) call
    # _invalidate_profile_cache explicitly at their call sites.
    set_profile_saved_hook(_invalidate_profile_cache)

    # Expose the helpers as app-level functions so other routes can reach
    # them without re-implementing the lookup. (Routes defined later in
    # create_app() close over these via the enclosing scope.)
    app.active_profile_id = _active_profile_id  # type: ignore[attr-defined]
    app.active_profile = _active_profile  # type: ignore[attr-defined]

    # Expose on the app (mirrors ``app.active_profile_id`` above) so the
    # follow-up migration batches and the tenant-isolation tests can reach the
    # one true guard without re-implementing it.
    app.require_run = require_run  # type: ignore[attr-defined]

    app.before_request(_bind_governance_context)

    app.teardown_request(_clear_governance_context)

    app.before_request(_gate_until_org_ready)

    # ---- Versioned ToS re-acceptance gate (UK legal baseline) -----------
    #

    app.before_request(_gate_until_terms_accepted)

    # Security headers live in the consolidated _security_headers hook in
    # create_app's web-hardening block (CSP + CSRF injection + nosniff +
    # embed-aware XFO + Referrer/Permissions-Policy + HSTS) — one hook,
    # one truth (Art. 32 / audit finding 1.10).

    # Expose the banner builder so content pages can include it.
    app._free_tier_banner_html = _free_tier_banner_html  # type: ignore[attr-defined]

    # ---- Global error handlers &mdash; keep tracebacks out of the UI ---------
    @app.errorhandler(404)
    def _not_found_page(e):
        accepts = request.headers.get("Accept", "") if request else ""
        if "application/json" in accepts or request.path.startswith("/api/"):
            return jsonify({"error": "not_found", "path": request.path}), 404
        body = (
            '<section class="mh-hero" data-lane="404" style="padding-top:var(--sp-9);padding-bottom:var(--sp-8)">'
            '<span class="mh-hero-eyebrow">Page not found</span>'
            "<h1>Off the lane.</h1>"
            f'<p class="lede">The page <code>{_h(request.path)}</code> doesn\'t exist on this deployment. '
            "It may have been moved, renamed, or never minted.</p>"
            '<div class="mh-hero-actions">'
            f'<a class="mh-cta-primary" href="{url_for("home")}">Back to home &rarr;</a>'
            f'<a class="mh-cta-secondary" href="{url_for("activity_page")}">Recent activity</a>'
            "</div>"
            "</section>"
        )
        return _layout("Not found", body, active=""), 404

    @app.errorhandler(500)
    def _server_error_page(e):
        try:
            app.logger.exception("Unhandled server error")
        except Exception:
            pass
        accepts = request.headers.get("Accept", "") if request else ""
        if "application/json" in accepts or request.path.startswith("/api/"):
            return jsonify({"error": "internal_error"}), 500
        body = (
            '<section class="mh-hero" data-lane="500" style="padding-top:var(--sp-9);padding-bottom:var(--sp-8)">'
            '<span class="mh-hero-eyebrow">Server error</span>'
            "<h1>The engine stalled.</h1>"
            '<p class="lede">'
            "Something failed on the server. Nothing you uploaded was lost — "
            "refresh, or try a different action. If it keeps happening, the "
            "deployment status page has the latest health signal."
            "</p>"
            '<div class="mh-hero-actions">'
            f'<a class="mh-cta-primary" href="{url_for("home")}">Back to home &rarr;</a>'
            '<a class="mh-cta-secondary" href="javascript:history.back()">Go back</a>'
            f'<a class="mh-cta-secondary" href="{url_for("status_page")}">Check status</a>'
            "</div>"
            "</section>"
        )
        return _layout("Error", body, active=""), 500

    @app.errorhandler(413)
    def _payload_too_large(e):
        # Report the cap that actually applied to THIS request — the footage route
        # raises it per-request, so a hardcoded "50 MB" would mislead there.
        limit = (getattr(request, "max_content_length", None) if request else None) or app.config[
            "MAX_CONTENT_LENGTH"
        ]
        max_mb = max(1, int(limit) // (1024 * 1024))
        accepts = request.headers.get("Accept", "") if request else ""
        if "application/json" in accepts or request.path.startswith("/api/"):
            return jsonify({"error": "file_too_large", "max_mb": max_mb}), 413
        body = (
            '<section class="mh-hero" data-lane="413" style="padding-top:var(--sp-9);padding-bottom:var(--sp-8)">'
            '<span class="mh-hero-eyebrow">413 / payload too large</span>'
            "<h1>File too big.</h1>"
            '<p class="lede">'
            f"The upload exceeded {max_mb}&nbsp;MB. Try compressing or trimming the file first."
            "</p>"
            '<div class="mh-hero-actions">'
            f'<a class="mh-cta-primary" href="{url_for("upload")}">Try a smaller file &rarr;</a>'
            f'<a class="mh-cta-secondary" href="{url_for("home")}">Back to home</a>'
            "</div>"
            "</section>"
        )
        return _layout("File too large", body, active=""), 413

    # Start the in-process scheduler once per worker. Idempotent and self-
    # guarded (no-ops under pytest and when MEDIAHUB_SCHEDULER=0). Safe under
    # 2 workers because each due (task, UTC-slot) is fired via a single atomic
    # SQLite claim — see mediahub.scheduler / mediahub.workflow.schedule.
    try:
        from mediahub.autonomy.app_env import register_autonomy_task
        from mediahub.scheduler import start_scheduler

        # Register the (off-by-default) autonomy task type before the tick loop
        # starts, so a scheduled "prepare my pack for review" run can fire.
        register_autonomy_task()
        # W.7: live-meet watch polling — cards queue for approval only;
        # the runner re-runs the pipeline into the watch's fixed run id.
        try:
            from mediahub.results_fetch.live_watch import register_live_watch_task

            register_live_watch_task(_live_watch_runner)
        except Exception:
            log.warning("live watch task not registered", exc_info=True)
        # W.8: monthly season-wrap drafts (per-org schedule rows are created
        # from the Wraps page; this just registers the handler).
        try:
            from mediahub.season_wrap import register_season_wrap_task

            register_season_wrap_task()
        except Exception:
            log.warning("season wrap task not registered", exc_info=True)
        # PC.7: the demo-run sweep — demo previews are self-cleaning. The
        # task type is registered unconditionally (cheap no-op when there
        # are no demo runs); the daily schedule row is ensured once.
        from mediahub.scheduler import register_task_type as _register_task_type
        from mediahub.web.demo_try import demo_enabled as _demo_enabled
        from mediahub.web.demo_try import sweep_demo_runs as _sweep_demo_runs

        def _demo_sweep_handler(params: dict) -> None:
            _sweep_demo_runs(_delete_run)
            # Abandoned pre-run staging dirs (upload made, club never picked)
            # are invisible to the DB-driven sweep above — clean them here.
            _sweep_demo_staging_dirs()

        _register_task_type("demo_sweep", _demo_sweep_handler)
        if _demo_enabled():
            from mediahub.workflow.schedule import create_task as _sched_create_task
            from mediahub.workflow.schedule import list_tasks as _sched_list_tasks

            if not any(t.task_type == "demo_sweep" for t in _sched_list_tasks()):
                _sched_create_task(
                    name="Demo run sweep (PC.7)",
                    task_type="demo_sweep",
                    schedule_kind="daily",
                    schedule_expr="03:30",
                )

        # Retention purge (Art 5(1)(e) storage limitation): ONE daily job.
        # compliance.retention is the engine — per-class windows
        # (runs/uploads/caches/security-log), tenant tightening, and it
        # honours the legacy global MEDIAHUB_RETENTION_DAYS window from the
        # UK-legal baseline as a ceiling for runs + raw uploads (so the
        # Privacy page's stated setting stays true). Disabling a class is
        # an explicit env setting (days=0), never an absent job.
        def _retention_handler(params: dict) -> None:
            from mediahub.compliance.retention import run_purge

            report = run_purge(_delete_run)
            log.info(
                "retention purge: %d runs, %d upload dirs, %d cache files removed",
                len(report["runs_deleted"]),
                len(report["upload_dirs_deleted"]),
                report["pb_cache_files_deleted"],
            )

        _register_task_type("retention_purge", _retention_handler)
        from mediahub.workflow.schedule import create_task as _ret_create_task
        from mediahub.workflow.schedule import list_tasks as _ret_list_tasks

        if not any(t.task_type == "retention_purge" for t in _ret_list_tasks()):
            _ret_create_task(
                name="Retention purge (storage limitation)",
                task_type="retention_purge",
                schedule_kind="daily",
                schedule_expr="04:10",
            )
        # PC.14: daily DATA_DIR backup. Handler always registered (honest
        # no-op when no backup target is configured); the schedule row is
        # ensured once when the operator opts in.
        from mediahub.backup import backup_enabled as _backup_enabled
        from mediahub.backup import sweep as _backup_sweep

        def _backup_handler(params: dict) -> None:
            _backup_sweep(params)

        _register_task_type("backup_sweep", _backup_handler)
        if _backup_enabled():
            from mediahub.workflow.schedule import create_task as _sched_create_task3
            from mediahub.workflow.schedule import list_tasks as _sched_list_tasks3

            if not any(t.task_type == "backup_sweep" for t in _sched_list_tasks3()):
                _sched_create_task3(
                    name="DATA_DIR backup (PC.14)",
                    task_type="backup_sweep",
                    schedule_kind="daily",
                    schedule_expr="04:20",
                )
        # 1.13: register the bulk-generation + connector-refresh task types so
        # large jobs / scheduled syncs can run on the in-process scheduler.
        if _data_hub_ok:
            try:
                _data_hub_bulk.register_task()
                from mediahub.data_hub.connectors import register_refresh_task

                register_refresh_task()
            except Exception:
                pass
        # 1.21: outbound-webhook retry sweep. emit() attempts each delivery
        # immediately; this durable backstop re-attempts any that are still
        # pending (with exponential backoff) and survives restarts.
        try:
            from mediahub.webhooks.delivery import deliver_pending as _wh_deliver_pending

            def _webhook_delivery_handler(params: dict) -> None:
                _wh_deliver_pending()

            _register_task_type("webhook_delivery", _webhook_delivery_handler)
            from mediahub.workflow.schedule import create_task as _wh_create_task
            from mediahub.workflow.schedule import list_tasks as _wh_list_tasks

            if not any(t.task_type == "webhook_delivery" for t in _wh_list_tasks()):
                _wh_create_task(
                    name="Webhook delivery retry (1.21)",
                    task_type="webhook_delivery",
                    schedule_kind="cron",
                    schedule_expr="*/5 * * * *",
                )
        except Exception:
            log.warning("webhook retry task not registered", exc_info=True)
        start_scheduler()
    except Exception:
        log.warning("scheduler did not start", exc_info=True)

    # Production log watchdog (log_sentinel): polls this service's own Render
    # logs, notifies on known failure patterns, and applies opt-in, rate-capped
    # auto-fixes. Inert without RENDER_API_KEY + RENDER_SERVICE_ID; a heartbeat
    # lockfile under DATA_DIR elects one polling worker. docs/LOG_SENTINEL.md.
    try:
        from mediahub.log_sentinel import start_sentinel

        start_sentinel()
    except Exception:
        log.warning("log sentinel did not start", exc_info=True)

    # ---- Public platform API (roadmap 1.21) ---------------------------------
    # Register the first-party /api/v1 blueprint and wire its write callbacks
    # back to the monolith's gated internals. Reads happen directly in the
    # service layer (strict per-token tenant check); writes (run-trigger, card
    # approval, pack export) run through these callbacks so the public API uses
    # the SAME consent / brand-lock / group-approval gates as the UI.

    try:
        from mediahub.api_public import build_api_v1_blueprint
        from mediahub.api_public import service as _api_service

        _api_service.register_run_starter(_api_run_starter)
        _api_service.register_card_action(_api_card_action)
        _api_service.register_pack_exporter(_api_pack_exporter)
        app.register_blueprint(build_api_v1_blueprint())
    except Exception:
        log.warning("public API blueprint did not register", exc_info=True)

    return app


app = create_app()


if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port, debug=False, threaded=True)
